		\draw[violet,samples=100,domain=-4.5:5.5] plot (\x,{g(\x)});
		\draw[violet,samples=100,domain=-4.5:1] plot (\x,{h(\x)});
		\path (4,{f(4)}) node[shift={(180:.3)},scale=1]{$d_1$};
