			\fill[opacity=0.4,pattern=vertical lines] plot[domain=12:-2](\x,{8-2*(\x)})--plot[domain=-2:12](\x,{10})--cycle;
			\fill[opacity=0.4,pattern=horizontal lines] plot[domain=12:-2](\x,{(10-(\x))/2})--plot[domain=-2:12](\x,{10})--cycle;
