	;
	\draw (A)--(B)--(C)--cycle;
	\draw (O) circle(2.5);
	\foreach \d/\g in {A/90,B/180,C/0} \fill (\d)node[shift={(\g:0.3)}]{$\d$} circle(1pt);
	\path
	(B)--(C) node[below, midway]{$5$ m};
	\draw pic[draw=black, angle eccentricity=2.2, angle radius=0.4cm]{angle=B--A--C};
