		\draw (3.2,0)--(2,0)--(A)--(C)--(B);
		\draw[dashed] (C)--(3.2,0) (A)--(A') (B)--(B');
		\foreach \d/\g in {A/180,B/180} \fill (\d)node[shift={(\g:0.3)}]{$\d$} circle(1pt);
		\pic[draw,angle radius=4mm,angle eccentricity=1.5] {angle = A'--A--C};
