		% Dây phải theo hướng T2(60,20) -> y = 1/3 x. Tại y=90 -> x = 270 (Rất xa)
		% Ta lấy điểm trên biên hình vẽ để vẽ dây phải
		\coordinate (WallRight) at (80, 26.66);
