%[1D1H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	Cho góc $\alpha=-\dfrac{\pi}{4}+(2k+1)\pi$ ($k\in\mathbb{Z}$).
	\choiceTF
	{\True $\sin\alpha=\dfrac{\sqrt{2}}{2}$}
	{$\cos\alpha=\dfrac{\sqrt{2}}{2}$}
	{\True $\tan \alpha=-1$}
	{\True $\cot\alpha=-1$}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có
		\begin{eqnarray*}
			\sin\left[-\dfrac{\pi}{4}+(2k+1)\pi\right]&=&\sin\left(-\dfrac{\pi}{4}+2k\pi+\pi\right)\\
			&=&\sin\left(-\dfrac{\pi}{4}+\pi\right)=-\sin\left(-\dfrac{\pi}{4}\right)=\sin\dfrac{\pi}{4}=\dfrac{\sqrt{2}}{2}.
		\end{eqnarray*}
		\itemch Ta có
		\begin{eqnarray*}
			\cos\left[-\dfrac{\pi}{4}+(2k+1)\pi\right]&=&\cos\left(-\dfrac{\pi}{4}+2k\pi+\pi\right)\\
			&=&\cos\left(-\dfrac{\pi}{4}+\pi\right)=-\cos\left(-\dfrac{\pi}{4}\right)=-\cos\dfrac{\pi}{4}=-\dfrac{\sqrt{2}}{2}.
		\end{eqnarray*}
		\itemch  Ta có
		\begin{eqnarray*}
			\tan\left[-\dfrac{\pi}{4}+(2k+1)\pi\right]=\tan\left(-\dfrac{\pi}{4}\right)=-\tan\dfrac{\pi}{4}=-1.
		\end{eqnarray*}
		\itemch Ta có
		\begin{eqnarray*}
			\cot\left[-\dfrac{\pi}{4}+(2k+1)\pi\right]=\cot\left(-\dfrac{\pi}{4}\right)=-\cot\dfrac{\pi}{4}=-1.
		\end{eqnarray*}
	\end{itemchoice}
	}

%[1D1H2-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	Cho $\dfrac{\pi}{2}<\alpha<\pi$.
	\choiceTF
	{\True $\sin \alpha>0$}
	{\True $\cos \alpha<0$}
	{$\cot\left(\dfrac{\pi}{2}+\alpha\right)<0$}
	{\True $\tan\left(\dfrac{\pi}{2}-\alpha\right)<0$}
\loigiai{
	\begin{itemchoice}
		\itemch Nếu $\dfrac{\pi}{2}<\alpha<\pi$ thì $\sin\alpha>0$.
		\itemch Nếu $\dfrac{\pi}{2}<\alpha<\pi$ thì $\cos\alpha <0$.
		\itemch Ta có $\cot\left(\dfrac{\pi}{2}+\alpha\right)=\tan(-\alpha)=-\tan\alpha$.\\
		Nếu $\dfrac{\pi}{2}<\alpha<\pi$ thì $\tan\alpha <0$, suy ra $-\tan\alpha>0$. Do đó $\cot\left(\dfrac{\pi}{2}+\alpha\right)>0$.
		\itemch Ta có $\tan\left(\dfrac{\pi}{2}-\alpha\right)=\cot\alpha$.\\
		Nếu $\dfrac{\pi}{2}<\alpha<\pi$ thì $\cot\alpha <0$. Do đó $\tan\left(\dfrac{\pi}{2}-\alpha\right)<0$.
	\end{itemchoice}
	}

%[1D1H1-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	Từ một vị trí ban đầu trong không gian, vệ tinh $X$ chuyển động theo quỹ đạo là một đường tròn quanh Trái Đất và luôn cách tâm Trái Đất một khoảng bằng $9200$ km. Sau $2$ giờ thì vệ tinh $X$ hoàn thành hết một vòng di chuyển.
	\choiceTF
	{\True Quãng đường vệ tinh $X$ chuyển động được sau $1$ giờ là $28902{,}65$ (km) (kết quả được làm tròn đến hàng phần trăm) (kết quả được làm tròn đến hàng phần trăm)}
	{\True Quãng đường vệ tinh $X$ chuyển động được sau $1{,}5$ giờ là $43353{,}98$ (km) (kết quả được làm tròn đến hàng phần trăm)}
	{Sau khoảng $5{,}3$ giờ thì $X$ di chuyển được quãng đường $240000$ km (kết quả được làm tròn đến hàng phần trăm)}
	{\True Giả sử vệ tinh di chuyển theo chiều dương của đường tròn, sau $4{,}5$ giờ thì vệ tinh vẽ nên một góc $\dfrac{9\pi}{2}$ rad}
\loigiai{
	\begin{itemchoice}
		\itemch Một vòng di chuyển của $X$ chính là chu vi đường tròn:
		\[
		C=2\pi R=2\pi\cdot 9200=18400\pi\,\text{km}.
		\]
		Sau $1$ giờ, vệ tinh di chuyển nửa đường tròn với quãng đường là $\dfrac{1}{2}C=9200\pi\approx 28902{,}65$ (km).
		\itemch Sau $1{,}5$ giờ, vệ tinh di chuyển được $\dfrac{1{,}5\cdot 1}{2}$ đường tròn (hay $\dfrac{3}{4}$ đường tròn), quãng đường là $\dfrac{3}{4}C=\dfrac{3}{4}\cdot 18400\pi=13800\pi\approx 43353{,}98$ (km).
		\itemch Sau $5{,}3$ giờ, vệ tinh di chuyển được $\dfrac{5,3\cdot 1}{2}$ đường tròn (hay $\dfrac{53}{20}$ đường tròn), quãng đường là $\dfrac{53}{20}C=\dfrac{53}{20}\cdot 18400\pi=48760\pi\approx 153184{,}05$ (km).
		\itemch Sau $4{,}5$ giờ thì số vòng tròn mà vệ tinh $X$ di chuyển được là $\dfrac{4{,}5}{2}=\dfrac{9}{2}$ (vòng).\\
		Số đo góc lượng giác thu được là $\dfrac{9}{4}\cdot 2\pi=\dfrac{9\pi}{2}$ (rad).
	\end{itemchoice}
	}

