%[1D1V2-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	Giá trị của biểu thức  $\cos (\alpha+\pi)+\sin \left(\alpha+\dfrac{5 \pi}{2}\right)-\tan \left(\alpha+\dfrac{\pi}{2}\right) \tan (\pi-\alpha)$ bằng bao nhiêu?
	\shortans{$-1$}
\loigiai{
	Ta có $A=\cos (\alpha+\pi)+\sin \left(\alpha+\dfrac{5 \pi}{2}\right)-\tan \left(\alpha+\dfrac{\pi}{2}\right) \tan (\pi-\alpha)=-\cos \alpha+\cos  \alpha-\cot \alpha \tan \alpha=-1$.
	}

questions.solution:
Ta có $\tan (-\alpha+11 \pi)=\tan (-\alpha)=-\tan \alpha$;
	$$
	\sin \left(\alpha-\dfrac{3 \pi}{2}\right)=\sin \left(\alpha+\dfrac{\pi}{2}-2 \pi\right)=\sin \left(\alpha+\dfrac{\pi}{2}\right)=\cos (-\alpha)=\cos \alpha.
	$$
	Suy ra
	\begin{eqnarray*}
		\left[1+\tan ^2(-\alpha+11 \pi)\right] \cdot \sin ^2\left(\alpha-\dfrac{3 \pi}{2}\right)&=&\left(1+\tan ^2 \alpha\right) \cdot \cos ^2 \alpha\\
		&=&\dfrac{1}{\cos ^2 \alpha} \cdot \cos ^2 \alpha=1.
	\end{eqnarray*}

