%[1D1V1-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	\immini{Trạm vũ trụ Quốc tế ISS (tên Tiếng Anh: International Space Station) nằm trong quỹ đạo tròn cách bề mặt Trái Đất khoảng $400$ km. Nếu trạm mặt đất theo dõi được trạm vũ trụ ISS khi nó nằm trong góc $45^\circ$ ở tâm của quỹ đạo tròn này phía trên ăng-ten theo dõi, thì trạm vũ trụ ISS đã di chuyển được bao nhiêu km trong khi nó đang được trạm mặt đất theo dõi? Giả sử rằng bán kính của Trái Đất là $6400$ km. Làm tròn kết quả đến hàng đơn vị.
	}
	{\begin{tikzpicture}[font=\footnotesize, line join=round, line cap=round, >=stealth,scale=0.8]
	\def\x{2}
	\def\y{3}
	\path
	(0,0) coordinate (O)
	(0:\y) coordinate (A)
	(70:\y) coordinate (B)
	(115:\y) coordinate (C)
	(70:2.5) node[right]{$400$ km}
	;
	\fill[gray!30] (O) circle(\x);
	\draw[dashed] (O) circle(\y);
	\draw[->] (O)--(A);
	\draw[->] (O)--(B);
	\draw[->] (O)--(C);
	\begin{scope}
		\clip (C)--(O)--(B);
		\draw[fill=yellow] (O) circle(.5);
		\path ($(O)+(90:0.8)$) node{$45^\circ$};
	\end{scope}
	\foreach \d in{O,A,B}
	\fill[black](\d) circle (1pt);
	%	($(\x)+(\g:5mm)$) node{$\x$};
	\end{tikzpicture}}
	\shortans{$5341$}
\loigiai{
	Bán kính quỹ đạo của trạm vũ trụ quốc tế là $R=6400+400=6800$ km.\\
	Đổi $45^\circ =45\cdot \dfrac{\pi}{180}=\dfrac{\pi}{4}$ rad.\\
	Vậy trong khi được trạm mặt đất theo dõi, trạm ISS đã di chuyển một quãng đường có độ dài\\ $\ell=R\cdot \alpha =6800\cdot \dfrac{\pi}{4}\approx 5341$ km.
	}

