%[1D1V2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Phú Thạch]
	Chứng minh các đẳng thức lượng giác sau:
	\begin{enumerate}
		\item $\dfrac{\sin ^3 \alpha+\cos ^3 \alpha}{\sin \alpha+\cos \alpha}=1-\sin \alpha \cos \alpha$;
		\item $\sin ^4 x+\cos ^4 x=1-2 \sin ^2 x \cos ^2 x$,
		\item $\dfrac{1+\cot x}{1-\cot x}=\dfrac{\tan x+1}{\tan x-1}$;
		\item $\dfrac{\sin \alpha+\cos \alpha}{\sin ^3 \alpha}=\dfrac{1-\cot ^4 \alpha}{1-\cot \alpha}$.
	\end{enumerate}
\loigiai{
	\begin{enumerate}
		\item $\begin{aligned}[t]\dfrac{\sin ^3 \alpha+\cos ^3 \alpha}{\sin \alpha+\cos \alpha} & =\dfrac{(\sin \alpha+\cos \alpha)\left(\sin ^2 \alpha-\sin \alpha \cos \alpha+\cos ^2 \alpha\right)}{\sin \alpha+\cos \alpha} \\
		& =\sin ^2 \alpha-\sin \alpha \cos \alpha+\cos ^2 \alpha \\
		& =1-\sin \alpha \cos \alpha .
		\end{aligned}$
		\item $\sin ^4 x+\cos ^4 x=\left(\sin ^2 x+\cos ^2 x\right)^2-2 \sin ^2 x \cos ^2 x=1-2 \sin ^2 x \cos ^2 x$;
		\item $\dfrac{1+\cot x}{1-\cot x}=\dfrac{1+\dfrac{1}{\tan x}}{1-\dfrac{1}{\tan x}}=\dfrac{\tan x+1}{\tan x-1}$;
		\item
		$\dfrac{\sin \alpha+\cos \alpha}{\sin ^3 \alpha}  =\dfrac{1}{\sin ^2 \alpha}+\dfrac{\cos \alpha}{\sin \alpha} \cdot \dfrac{1}{\sin ^2 \alpha}=\left(1+\cot ^2 \alpha\right)+\cot \alpha\left(1+\cot ^2 \alpha\right)
		=(1+\cot \alpha)\left(1+\cot ^2 \alpha\right) \\
		=\dfrac{\left(1-\cot ^2 \alpha\right)\left(1+\cot ^2 \alpha\right)}{1-\cot \alpha}=\dfrac{1-\cot ^4 \alpha}{1-\cot \alpha}.
		$
	\end{enumerate}
	}

