	{\True $\sin a-\sin b=2\cos\dfrac{a+b}
	{2}\sin\dfrac{a-b}
	{2}$}
	{$\sin a-\sin b=2\sin\dfrac{a+b}{2}\sin\dfrac{a-b}{2}$}
	{$\sin a-\sin b=2\sin\dfrac{a+b}{2}\cos\dfrac{a-b}{2}$}
	{$\sin a-\sin b=2\cos\dfrac{a+b}{2}\cos\dfrac{a-b}{2}$}
\loigiai{
