%[1D1V3-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Lê Phúc]
	Trong vật lý, phương trình tổng quát của một vật giao động điều hòa được cho bởi công thức $x(t)=A\cos (\omega t+\varphi)$ trong đó $t$ là thời điểm (tính bằng giây), $x(t)$ là li độ của vật tại thời điểm $t$, $A$ là biên độ dao động $(A>0)$.
	\choiceTF
	{Nếu một vật giao động theo phương trình $x(t)=5\cos\left(100\pi t+\dfrac{\pi}{4}\right)$ thì li độ của vật ở thời điểm ban đầu là $5\sqrt{2}$}
	{\True Một vật giao động điều hòa theo phương trình $x(t)=10\sin\left(50\pi t\right)\cos\left(50\pi t\right)$ thì biên độ của giao động là $5$}
	{Cho hai dao động điều hòa cùng phương có phương trình lần lượt là $x_1=5\cos\left(100\pi t+\pi\right)$ (cm) và $x_2=5\cos\left(100\pi t-\dfrac{\pi}{2}\right)$ (cm). Khi đó phương trình dao động tổng hợp của hai dao động trên là $x=5\sqrt{2}\cos\left(100\pi t+\dfrac{\pi}{4}\right)$ (cm)}
	{\True Một sợi cáp $R$ được gắn vào một cột thẳng đứng ở vị trí cách mặt đất $14$m. Một sợi cáp $S$ khác cũng được gắn vào cột đó ở vị trí cách mặt đất $12$m. Biết rằng hai sợi cáp trên cùng được gắn với mặt đất tại một vị trí cách chân cột $15$ m (Hình vẽ bên dưới). Gọi $\alpha $ là góc giữa hai sợi cáp trên khi đó $\tan\alpha=\dfrac{10}{131}$
	\centerline{
	\begin{tikzpicture}[scale=0.8, font=\footnotesize,>=stealth]
		\path
		(5,0) coordinate (O)
		(0,0) coordinate (H)
		(0,4) coordinate (B)
		(0,6) coordinate (A)
		(1.5,1) coordinate (H1)
		(1.5,5) coordinate (B1)
		(1.5,7) coordinate (A1)
		;
		\draw[line width=4pt,cyan] (H)--(A) (H1)--(A1);
		\draw[red!70!black,line width=0.7pt] (O)--(A)node[pos=.5,above right]{$R$} (O)--(B)node[pos=.5,below]{$S$};
		\draw
		(A)--(A1) (B)--(B1) (H)--(H1)
		pic[draw,double,angle radius=11mm]{angle=A--O--H}
		pic[draw,angle radius=9mm]{angle=A--O--B};
		\draw[<->] (O)--(H)node[pos=.5,below]{$15$ m};
		\draw[<-] ($(H)+(-0.5,0)$)--($(0,1.5)+(-0.5,0)$)node[above]{\scriptsize$12$ m};
		\draw[->] ($(0,2)+(-0.5,0)$)--($(B)+(-0.5,0)$);
		\draw[<-] ($(H)+(-1,0)$)--($(0,2.5)+(-1,0)$)node[above]{\scriptsize$14$ m};
		\draw[->] ($(0,3)+(-1,0)$)--($(A)+(-1,0)$);
		\foreach \x/\g in {	O/-90,H/-90,B/150,A/90}\draw[fill=black] (\x) circle (.05) +(\g:.35)node{\footnotesize$\x$};
		\draw[dashed] (0,0)--(-1.5,0);
		\draw[dashed] (0,6)--(-1.5,6);
		\draw[dashed] (0,4)--(-0.6,4);
		\node[left] at (3.7,0.6) {$\beta$};
		\node[left] at (5.1,1.4) {$\alpha$};
		\draw[->] (4.6,1.2)--(4.25,0.65);
	\end{tikzpicture}
	}
	}
\loigiai{
	\begin{itemchoice}
		\itemch
		Ta có $x(t)=5\sin\left(100\pi t+\dfrac{\pi}{4}\right)$ thì li độ của vật ở thời điểm ban đầu (ứng với $t=0$) là \[x=5\sin\left(\dfrac{\pi}{4}\right)=\dfrac{5\sqrt{2}}{2}.\]
		\itemch
		Ta có $x(t)=10\sin\left(50\pi t\right)\cos\left(50\pi t\right)=5\sin\left(100\pi t\right)=5\cos\left(100\pi t+\dfrac{3\pi}{2}\right)$.\\
		Khi đó biên độ của giao động là $5$.
		\itemch
		Ta có
		\begin{eqnarray*}
			x&=&x_1+x_2=5\cos\left(100\pi t+\pi\right)+5\cos\left(100\pi t-\dfrac{\pi}{2}\right)\\
			&=&5\left[\cos\left(100\pi t+\pi\right)+\cos\left(100\pi t-\dfrac{\pi}{2}\right)\right]\\
			&=& 5\cdot 2\cos\left(100\pi t+\dfrac{\pi}{4}\right)\cos\dfrac{3\pi}{4}=-5\sqrt{2}\cos\left(100\pi t+\dfrac{\pi}{4}\right)=5\sqrt{2}\cos\left(100\pi t-\dfrac{3\pi}{4}\right).
		\end{eqnarray*}
		\itemch
		Ta có $\tan\beta=\dfrac{AH}{HO}=\dfrac{14}{15};\quad\tan{\beta_1}=\dfrac{BH}{HO}=\dfrac{12}{15}$.
		\begin{center}
			\begin{tikzpicture}[scale=0.8, font=\footnotesize,>=stealth]
				\path
				(5,0) coordinate (O)
				(0,0) coordinate (H)
				(0,4) coordinate (B)
				(0,6) coordinate (A)
				(1.5,1) coordinate (H1)
				(1.5,5) coordinate (B1)
				(1.5,7) coordinate (A1)
				;
				\draw[line width=4pt,cyan] (H)--(A) (H1)--(A1);
				\draw[red!70!black,line width=0.7pt] (O)--(A)node[pos=.5,above right]{$R$} (O)--(B)node[pos=.5,below]{$S$};
				\draw
				(A)--(A1) (B)--(B1) (H)--(H1)
				pic[draw,double,angle radius=11mm]{angle=A--O--H}
				pic[draw,angle radius=9mm]{angle=A--O--B};
				\draw[<->] (O)--(H)node[pos=.5,below]{$15$ m};
				\draw[<-] ($(H)+(-0.5,0)$)--($(0,1.5)+(-0.5,0)$)node[above]{\scriptsize$12$ m};
				\draw[->] ($(0,2)+(-0.5,0)$)--($(B)+(-0.5,0)$);
				\draw[<-] ($(H)+(-1,0)$)--($(0,2.5)+(-1,0)$)node[above]{\scriptsize$14$ m};
				\draw[->] ($(0,3)+(-1,0)$)--($(A)+(-1,0)$);
				\foreach \x/\g in {	O/-90,H/-90,B/150,A/90}\draw[fill=black] (\x) circle (.05) +(\g:.35)node{\footnotesize$\x$};
				\draw[dashed] (0,0)--(-1.5,0);
				\draw[dashed] (0,6)--(-1.5,6);
				\draw[dashed] (0,4)--(-0.6,4);
				\node[left] at (3.7,0.6) {$\beta$};
				\node[left] at (5.1,1.4) {$\alpha$};
				\draw[->] (4.6,1.2)--(4.25,0.65);
			\end{tikzpicture}
		\end{center}
		Khi đó $\tan\alpha=\tan\left(\beta-\beta_1\right)=\dfrac{\tan\beta-\tan{\beta_1}}{1+\tan\beta\tan{\beta_1}}=\dfrac{10}{131}$.
	\end{itemchoice}
	}

%[1D1N3-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Lê Phúc]
	Cho góc $\alpha$ thỏa mãn $\cos \alpha = -\dfrac{1}{2}$. Giá trị của $\cos 2\alpha$ bằng bao nhiêu? (kết quả làm tròn đến chữ số thập phân thứ nhất).
	\par\shortans{-0{,}5}
\loigiai{
	Ta có
	$$\cos2\alpha=2\cos^2\alpha-1=2\cdot\left(-\dfrac{1}{2}\right)^2-1=-\dfrac{1}{2}.$$
	Vậy $\cos2\alpha=-\dfrac{1}{2}=-0{,}5$.
	}

%[1D1H3-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Lê Phúc]
	Cho hai góc nhọn $a$ và $b$. Biết $\cos a=\dfrac{1}{3}$; $\cos b=\dfrac{1}{4}$. Tính giá trị của biểu thức \\$ P=\cos (a+b)\cos (a-b)$ (kết quả làm tròn đến một chữ số thập phân).
	\shortans{-0{,}8}
\loigiai{
	Ta có $\sin^2a=1-\cos^2a=\dfrac{8}{9}$; ${\sin^2}b=1-\cos^2b=\dfrac{15}{16}$.\\
	Do đó
	\begin{eqnarray*}
		P &=& (\cos a\cos b-\sin a\sin b)(\cos a\cos b+\sin a\sin b)\\
		&=& (\cos a\cos b)^2-(\sin a\sin b)^2\\
		&=&\cos^2a{\cos^2}b-\sin^2a{\sin^2}b \\
		&=& \dfrac{1}{9}\cdot\dfrac{1}{16}-\dfrac{8}{9}\cdot\dfrac{15}{16}=-\dfrac{119}{144}\approx-0{,}8.
	\end{eqnarray*}
	}

%[1D1V3-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Lê Phúc]
	Từ một vị trí $A$, người ta buộc hai sợi cáp $AB$ và $AC$ đến một cái trụ cao $15$\,m, được dựng vuông góc với mặt đất, chân trụ ở vị trí $D$. Biết $CD=9$\,m và $AD=12$\,m. Tìm góc nhọn $\alpha=\widehat{BAC}$ tạo bởi hai sợi dây cáp đó, đồng thời tính gần đúng $\alpha$ (làm tròn kết quả đến hàng phần chục của độ).
	\begin{center}
