			\path
			(-0.9,0.35)pic[scale=0.7]{khomcay}
			(1.2,0.6)pic[scale=0.7]{khomcay}
			(0.5,0.6)pic[scale=0.7]{khomcay}
			(0,0)pic{khomcay}
			;
			\draw[fill=brown] (6.3,0.05) rectangle (6.6,6.4);
