	\par
	\shortans{$14{,}5$}
\loigiai{
	Ta có
	$
	\tan\alpha=\tan (\widehat{BAD}-\widehat{CAD})
	=\dfrac{\tan\widehat{BAD}-\tan\widehat{CAD}}{1+\tan\widehat{BAD}\tan\widehat{CAD}}=\dfrac{\dfrac{15}{12}-\dfrac{9}{12}}{1+\dfrac{15}{12}\cdot\dfrac{9}{12}}=\dfrac{8}{31}.
	$\\
	Vì vậy $\alpha\approx 14{,}5^\circ$.
	}

