%[1D1V3-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Lê Phúc]
	Hiệu điện thế và cường độ dòng điện trong một thiết bị điện lần lượt được cho bởi các biểu thức sau
	\begin{eqnarray*}
		&& u=40 \sin (120 \pi t)+10 \sin (360 \pi t)\quad \text{(V)} \\
		&& i=4 \sin (120 \pi t)+\sin (360 \pi t) \quad \text{(A).}
	\end{eqnarray*}
	\begin{flushright}
		(Nguồn: Ron Larson, Intermediate Algebra, Cengage)
	\end{flushright}
	Biết rằng công suất tiêu thụ tức thời của thiết bị đó được tính theo công thức: $P=u \cdot i$ (W). Hãy viết biểu thức biểu thị công suất tiêu thụ tức thời ở dạng không có lũy thừa và tích của các biểu thức lượng giác.
\loigiai{
	Ta có
	$$
	\begin{aligned}
		P & =u \cdot i=[40 \sin (120 \pi t)+10 \sin (360 \pi t)] \cdot[4 \sin (120 \pi t)+\sin (360 \pi t)] \\
		& =160 \sin ^{2}(120 \pi t)+10 \sin ^{2}(360 \pi t)+80 \sin (120 \pi t) \sin (360 \pi t) \\
		& =80[1-\cos (240 \pi t)]+5[1-\cos (720 \pi t)]+40[\cos (360 \pi t-120 \pi t)-\cos (360 \pi t+120 \pi t)] \\
		& =85-80 \cos (240 \pi t)-5 \cos (720 \pi t)+40 \cos (240 \pi t)-40 \cos (480 \pi t) \\
		& =85-40 \cos (240 \pi t)-5 \cos (720 \pi t)-40 \cos (480 \pi t)\,\,(\mathrm{W}).
	\end{aligned}
	$$
	}

%[1D1N4-2]
	Trong các khẳng định sau, khẳng định nào {\bf đúng}?
	\choice
	{Tập xác định của hàm số $y=\sin x$ là $\mathscr{D}=[-1;1]$}
	{Tập xác định của hàm số $y=\cos x$ là $\mathscr{D}=[-1;1]$}
	{Tập xác định của hàm số $y=\cos x$ là $\mathscr{D}=[-2;2]$}
	{\True Tập xác định của hàm số $y=\sin x$ là $\mathscr{D}=\mathbb{R}$}
\loigiai{
	Tập xác định của hàm số $y=\sin x$ là $\mathscr{D}=\mathbb{R}$.
	}

%[1D1H4-3]
	Trong các khẳng định sau, khẳng định nào {\bf sai}?
	\choice
	{Hàm số $y=\sin x$ đồng biến trên mỗi khoảng $\left(-\dfrac{\pi}
	{2}+k2\pi;\dfrac{\pi}
	{2}+k2\pi\right)$ và nghịch biến trên mỗi khoảng $\left(\dfrac{\pi}
	{2}+k2\pi ;\dfrac{3\pi}{2}+k2\pi\right)$, $k \in \mathbb{Z}$}
	{Hàm số $y=\cos x$ đồng biến trên mỗi khoảng $\left(-\pi+k2\pi ;k2\pi\right)$ và nghịch biến trên mỗi khoảng $\left(k2\pi ;\pi+k2\pi\right)$, $k \in \mathbb{Z}$}
	{\True Hàm số $y=\tan x$ đồng biến trên mỗi khoảng $\left(k\pi ;\pi+k\pi\right)$, $k \in \mathbb{Z}$}
	{Hàm số $y=\cot x$ nghịch biến trên mỗi khoảng $\left(k\pi ;\pi+k\pi\right)$, $k \in \mathbb{Z}$}
\loigiai{
	Xét hàm số $y=\tan x$ có tập xác định là $\mathscr{D}=\mathbb{R}\setminus \left\{\dfrac{\pi}{2}+k\pi\mid k\in\mathbb{Z}\right\}$.\\
	Trên các khoảng $\left(k\pi;\pi+k\pi\right)$, $k \in \mathbb{Z}$ có chứa các điểm mà hàm số $y=\tan x$ không xác định nên hàm số không đồng biến trên mỗi khoảng $\left(k\pi ;\pi+k\pi\right)$, $k \in \mathbb{Z}$.}

