	Trong các hàm số sau, hàm số nào là hàm số chẵn?
	\choice
	{$y=\sin x$}
	{\True $y=\cos x$}
	{$y=\tan x$}
	{$y=\cot x$}
\loigiai{
	Hàm số $y=\cos x$ là hàm số chẵn.\\
	Các hàm số $y=\sin x$; $y=\tan x$; $y=\cot x$ là các hàm số lẻ.
	}

%[1D1N4-5]
	Chu kì tuần hoàn của hàm số $y=\sin x$ là
	\choice
	{$T=\mathbb{R}$}
	{$T=[-1;1]$}
	{$T=\pi $}
	{\True $T=2\pi $}
\loigiai{
	Chu kì tuần hoàn của hàm số $y=\sin x$ là $T=2\pi $.
	}

%[1D1N4-6]
	Tập giá trị của hàm số $y=\cos x$ là
	\choice
	{$T=\mathbb{R}$}
	{\True $T=[-1;1]$}
	{$T=[0;1]$}
	{$T=2\pi $}
\loigiai{
	Ta có $-1\le \cos x\le 1$, $\forall x\in\mathbb{R}$ nên $-1\le y\le 1$.\\
	Vậy tập giá trị của hàm số $y=\cos x$ là $T=[-1;1]$.
	}

