	\end{center}
	\choice
	{$y=\sin x$}
	{$y=\cos x$}
	{$y=\tan x$}
	{\True $y=\cot x$}
\loigiai{
	Đồ thị hàm số trên là đồ thị hàm số $y=\cot x$.
	}

%[1D1H4-2]
	Tập xác định $\mathscr{D}$ của hàm số $y=\dfrac{1-\cos x}{\sin x}$ là
	\choice
	{$\mathscr{D}=\mathbb{R}$}
	{$\mathscr{D}=\mathbb{R}\setminus \{0\}$}
	{$\mathscr{D}=\mathbb{R}\setminus\left\{\dfrac{\pi}
	{2}+k\pi \mid k\in\mathbb{Z}\right\}$}
	{\True $\mathscr{D}=\mathbb{R}\setminus\left\{k\pi\mid  k\in\mathbb{Z}\right\}$}
\loigiai{
	Điều kiện xác định của hàm số là $\sin x\ne 0 \Leftrightarrow x\ne k\pi$ ($k\in\mathbb{Z}$).\\
	Vậy tập xác định của hàm số là $\mathscr{D}=\mathbb{R}\setminus\left\{k\pi\mid  k\in\mathbb{Z}\right\}$.
	}

%[1D1H4-3]
	Hàm số nào sau đây nghịch biến trên khoảng $\left(0;\dfrac{\pi}{2}\right)$?
	\choice
	{$y=\sin x$}
	{\True $y=\cos x$}
	{$y=\tan x$}
	{$y=-\cot x$}
\loigiai{
	Hàm số $y=\cos x$ nghịch biến trên khoảng $\left(0;\dfrac{\pi}{2}\right)$.
	}

%[1D1H4-4]
	Phát biểu nào sau đây {\bf đúng}?
	\choice
	{Hàm số $y=\sin ^2x+x$ là hàm số lẻ}
	{\True Hàm số $y=\sin x\cdot \cos x$ là hàm số lẻ}
	{Hàm số$y=\cos x+\sin x$ là hàm số chẵn}
	{Hàm số $y=\sin x+1$ là hàm số lẻ}
\loigiai{
	Xét hàm số $y=f(x)=\sin x\cdot \cos x$.\\
	Tập xác định $\mathscr{D}=\mathbb{R}$.\\
	Với mọi $x\in \mathscr{D}$ thì $-x\in\mathscr{D}$.\\
	Đồng thời $f(-x)=\sin(-x)\cdot \cos(-x)=-\sin x\cdot \cos x=-f(x)$.\\
	Vậy $f(x)$ là hàm số lẻ.
	}

%[1D1H4-5]
	Chu kì $T$ của hàm số $y=\cos\left(\dfrac{x}{2}-2\,024\right)$ là
	\choice
	{$T=\pi $}
	{$T=-2\pi $}
	{\True $T=4\pi $}
	{$T=2\pi $}
\loigiai{
	Hàm số $y=\cos(ax+b)$ tuần hoàn với chu kì $T=\dfrac{2\pi}{|a|}$.\\
	Vậy hàm số $y=\cos\left(\dfrac{x}{2}-2\,024\right)$ tuần hoàn với chu kì $T=\dfrac{2\pi}{\dfrac{1}{2}}=4\pi$.
	}

%[1D1H4-6]
	Tập giá trị của hàm số $y=2\sin x$ là
	\choice
	{$T=\mathbb{R}$}
	{\True $T=[-2;2]$}
	{$T=[0;1]$}
	{$T=[-1;1]$}
\loigiai{
	Với mọi $x\in\mathbb{R}$,
	ta có \[-1\le\sin x\le 1\Leftrightarrow -2\le 2\sin x\le 2\Leftrightarrow -2\le y\le 2.\]
	Vậy tập giá trị của hàm số $y=2\sin x$ là $T=[-2;2]$.
	}

