Ta có $\sin x+5=m^2 \Leftrightarrow \sin x=m^2-5$.\\ Vì $\sin x \in[-1; 1]$ nên phương trình đã cho có nghiệm
	\begin{eqnarray*}
		&\Leftrightarrow &-1\le m^2-5 \leq 1 \Leftrightarrow 4 \le m^2\le 6 \Leftrightarrow\hoac{&2\le m\le \sqrt{6} \\&-\sqrt{6}\le m \le -2.}\\
	\end{eqnarray*}
	Mà $m\in \mathbb{Z}\Rightarrow m\in\{-2;2\}$.

questions.rawBody:
%[1D1H5-2]
	Có bao nhiêu giá trị nguyên của tham số $m$ để phương trình $\sin x+5=m^2$ có nghiệm?
	\choice
	{$4$}
	{\True $2$}
	{$1$}
	{$0$}
\loigiai{
	Ta có $\sin x+5=m^2 \Leftrightarrow \sin x=m^2-5$.\\ Vì $\sin x \in[-1; 1]$ nên phương trình đã cho có nghiệm
	\allowdisplaybreaks
	\begin{eqnarray*}
		&\Leftrightarrow &-1\le m^2-5 \leq 1 \Leftrightarrow 4 \le m^2\le 6 \Leftrightarrow\hoac{&2\le m\le \sqrt{6} \\&-\sqrt{6}\le m \le -2.}\\
	\end{eqnarray*}
	Mà $m\in \mathbb{Z}\Rightarrow m\in\{-2;2\}$. }

%[1D1H5-3]
	Phương trình $\dfrac{\cos 2 x(2 \cos 2 x+1)}{\sin 3 x}=\cot x$ có bao nhiêu nghiệm thuộc khoảng $(-2 \pi; 2 \pi)$?
	\choice
	{\True$0$}
	{$12$}
	{$8$}
	{$6$}
\loigiai{
	Điều kiện $\heva{	&\sin 3 x \neq 0 \\
	&\sin x \neq 0}\Leftrightarrow \sin 3 x \neq 0 \Leftrightarrow x \neq \dfrac{k \pi}{3}, k \in \mathbb{Z}$.\\
	Ta có
	\allowdisplaybreaks
	\begin{eqnarray*}
		&	&\dfrac{\cos 2 x(2 \cos 2 x+1)}{\sin 3 x}=\cot x \\
		&\Leftrightarrow	& \dfrac{\cos 2 x\left[2\left(1-2 \sin^2 x\right)+1\right]}{3 \sin x-4 \sin^3 x}=\dfrac{\cos x}{\sin x}\\
		&\Leftrightarrow	& \dfrac{\cos 2 x\left(3-4 \sin^2 x\right)}{\sin x\left(3-4 \sin^2 x\right)}=\dfrac{\cos x}{\sin x} \\
		&\Rightarrow	& \cos 2 x=\cos x\\
		&\Leftrightarrow	&\hoac{	&2 x=x+k 2 \pi \\
		& 2 x=-x+k 2}\\
		&\Leftrightarrow	&\hoac{	&x=k 2 \pi \\
		& x=\dfrac{k 2 \pi}{3}}\\
		& \Leftrightarrow	& x=\dfrac{k 2 \pi}{3}, k \in \mathbb{Z} \text{ (loại vì không thỏa mãn điều kiện)}.
	\end{eqnarray*}
	Kết luận: Phương trình vô nghiệm.
	}

%Câu 3%[1D1H5-3]
	Phương trình $\cos 2 x=-\dfrac{1}{2}$ có nghiệm là
	\choice
	{$x= \pm \dfrac{\pi}
	{3}+k 2 \pi, k \in \mathbb{Z}$}
	{$x= \pm \dfrac{\pi}
	{6}+k \pi, k \in \mathbb{Z}$}
	{\True $x= \pm \dfrac{\pi}{3}+k \pi, k \in \mathbb{Z}$}
	{$x= \pm \dfrac{\pi}{6}+k 2 \pi, k \in \mathbb{Z}$}
\loigiai{
	Ta có $\cos 2 x=-\dfrac{1}{2}\Leftrightarrow 2 x= \pm \dfrac{2 \pi}{3}+k 2 \pi \Leftrightarrow x= \pm \dfrac{\pi}{3}+k \pi(k \in \mathbb{Z})$.}

%[1D1H5-3]%[Câu 8]
	Tất cả các nghiệm của phương trình $\sin x=-\dfrac{1}{2}$ là
	\choice
	{$x=\pi+k 2 \pi ; \quad x=\dfrac{\pi}
	{8}+k 2 \pi, k \in \mathbb{Z}$}
	{$x=\dfrac{\pi}
	{6}+k 2 \pi ; \quad x=\dfrac{7 \pi}{6}+k 2 \pi, k \in \mathbb{Z}$}
	{\True $x=-\dfrac{\pi}{6}+k 2 \pi ; \quad x=\dfrac{7 \pi}{6}+k 2 \pi, k \in \mathbb{Z}$}
	{$x=-\dfrac{\pi}{6}+k 2 \pi ; \quad x=\dfrac{5 \pi}{6}+k 2 \pi, k \in \mathbb{Z}$}
\loigiai{
	$\sin x=-\dfrac{1}{2}=\sin \left(-\dfrac{\pi}{6}\right) \Leftrightarrow \hoac{&x=-\dfrac{\pi}{6} +k2\pi \\&x=\dfrac{7\pi}{6} +k2\pi}, k\in \mathbb{Z}$.
	}

%[1D1H5-3]
	Cho phương trình lượng giác $2 \cos x=\sqrt{3}$.
	\choiceTF
	{\True Phương trình có nghiệm $x= \pm \dfrac{\pi}{6}+k 2 \pi, (k \in \mathbb{Z})$}
	{Trong đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ phương trình có $4$ nghiệm}
	{\True Tổng các nghiệm của phương trình trong đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ bằng $\dfrac{25 \pi}{6}$}
	{\True Trong đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ phương trình có nghiệm nhỏ nhất bằng $\dfrac{\pi}{6}$}
\loigiai{
	\begin{itemchoice}
		\itemch Phương trình tương đương với $\cos x=\dfrac{\sqrt{3}}{2}=\cos \dfrac{\pi}{6}\Leftrightarrow x=\pm \dfrac{\pi}{6}+k2\pi, k\in \mathbb{Z}$.
		\itemch Xét
		\begin{itemize}
			\item $0\le \dfrac{\pi}{6}+k2\pi\le \dfrac{5\pi}{2}\Leftrightarrow -\dfrac{1}{12}\le k\le \dfrac{7}{6}$ mà $k\in \mathbb{Z}$ nên $k\in \{0;1\}$.\\
			Suy ra $x=\dfrac{\pi}{6}$ và $x=\dfrac{13\pi}{6}$.
			\item $0\le -\dfrac{\pi}{6}+k2\pi\le \dfrac{5\pi}{2}\Leftrightarrow \dfrac{1}{12}\le k\le \dfrac{4}{3}$ mà $k\in \mathbb{Z}$ nên $k\in \{1\}$.\\
			Suy ra $x=\dfrac{11\pi}{6}$.
		\end{itemize}
		Vậy trong đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ phương trình có $3$ nghiệm.
		\itemch Tổng các nghiệm trên đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ bằng $\dfrac{\pi}{6}+\dfrac{13\pi}{6}+\dfrac{11\pi}{6}=\dfrac{25\pi}{6}$.
		\itemch Trong đoạn $\left[0 ; \dfrac{5 \pi}{2}\right]$ phương trình có nghiệm nhỏ nhất bằng $\dfrac{\pi}{6}$.
	\end{itemchoice}
	}

