	\itemch $u_7-u_8 = -\dfrac{1}{56}$.
	\itemch Ta có $u_{n+1}-u_n = \left(1-\dfrac{1}{n+1}\right) -\left(1-\dfrac{1}{n}\right) = \dfrac{1}{n}-\dfrac{1}{n+1} = \dfrac{1}{n(n+1) } > 0$, $\forall n \ge 1$.\\
