%[1D2H1-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Liên Phúc Quỳnh]
	Cho dãy số $\left(u_n\right)$ cho bởi công thức $u_n = \dfrac{3n-1}{n+1}$. Xét tính đúng sai của các khẳng định sau
	\choiceTF
	{Năm số hạng đầu là $1;\dfrac{5}{3};2;\dfrac{12}{5};\dfrac{7}{3}$}
	{\True Số hạng $u_{n+1} = \dfrac{3n+2}{n+2}$}
	{Dãy số $\left(u_n\right)$ là dãy giảm}
	{\True Dãy số $\left(u_n\right)$ bị chặn}
\loigiai{
	\begin{itemchoice}
		\itemch  Ta có $u_1 = \dfrac{3 \cdot 1 - 1}{1+1} = 1$, tương tự ta cũng có $u_2 = \dfrac{5}{3}$, $u_3 = 2$, $u_4 = \dfrac{11}{3} $, $u_5 = \dfrac{7}{3}$.
		\itemch  Từ $u_{n} = \dfrac{3n-1}{n+1}$ nên $u_{n+1} = \dfrac{3\left(n+1\right) -1}{\left(n+1\right)+1} = \dfrac{3n+2}{n+2}$.
		\itemch  Ta kiểm tra dấu của hiệu số $u_{n+1}-u_n$.\\
		\[u_{n+1}-u_n = \dfrac{3n+2}{n+2} - \dfrac{3n-1}{n+1} = \dfrac{4}{\left(n+1\right)\left(n+2\right)} >0.\]
		Nên $\left(u_n\right)$ là dãy tăng.
		\itemch  Theo lí thuyết, để chứng minh dãy số bị chặn ta chứng minh nó bị chặn trên và bị chặn dưới.
		Với $n \in \mathbb{N}^\ast$ ta có $u_n = \dfrac{3n-1}{n+1} >0$.\\
		Nên dãy $\left(u_n\right)$ bị chặn dưới bởi $0$.\\
		Mặt khác $u_n = \dfrac{3n-1}{n+1} = \dfrac{3n+3-4}{n+1} = 3 - \dfrac{4}{n+1} <3$, $\forall n \in \mathbb{N}^\ast$.\\
		Nên dãy $\left(u_n\right)$ bị chặn trên bởi $3$.\\
		Vậy dãy số $\left(u_n\right)$ bị chặn.
	\end{itemchoice}
	}

%[1D2V1-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Liên Phúc Quỳnh]
