 %[1D2H2-6]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Tính tổng $T=15+20+25+\cdots+7515$.
	\choice
	{\True $T=5651265$}
	{$T=5651256$}
	{$T=5651625$}
	{$T=5651526$}
\loigiai{
	Ta thấy các số hạng của tổng $T$ tạo thành một cấp số cộng với số hạng đầu $u_{1} =15$ và công sai $d=5$.\\
	Giả sử tổng trên có $n$ số hạng thì $u_{n} =7515$.
	\[\Leftrightarrow u_{1} +\left(n-1\right)d=7515\Leftrightarrow 15+\left(n-1\right)\cdot 5=7515\Leftrightarrow n=1501.\]
	Vậy $T=S_{1501} =\dfrac{\left(2u_{1} +1500d\right)\cdot 1501}{2} =\dfrac{\left(2\cdot 15+1500\cdot 5\right)\cdot 1501}{2} =5651265$.
	}

%[1D2N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
