%[1D2H2-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Cho dãy cấp số cộng $\left(u_n\right)$ có $u_1=4.$ Biết tổng $20$ số hạng đầu tiên bằng $460.$
	\choiceTF
	{\True Dãy số $\left(u_n\right)$ có $d=2$}
	{Dãy số $\left(u_n\right)$ có $u_4=8$}
	{\True Dãy số $\left(u_n\right)$ có $S_{10}=120$}
	{\True Dãy số $\left(u_n\right)$ có hiệu $S_8-S_4=60$}
\loigiai{
	\begin{itemchoice}
		\itemch
		$S_{20}=\dfrac{20\left(u_1+u_{20}\right)}{2}=10\left(4+4+19d\right)=460\Leftrightarrow d=2.$
		\itemch
		${u_4}=u_1+3d=4+3 \cdot 2=10$.
		\itemch  ${S_{10}}=\dfrac{10\left(u_1+u_9\right)}{2}=5\left(4+4+8\cdot2\right)=120$.
		\itemch  ${S_8}-S_4=\dfrac{8\left(u_1+u_8\right)}{2}-\dfrac{4\left(u_1+u_4\right)}{2}=4\left(2u_1+7d\right)-2\left(2u_1+3d\right)=4u_1+22d=60$.
	\end{itemchoice}
	}

%[1D2H2-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Cho cấp số cộng $\left(u_n\right)$ có $u_4=-12,\,\,u_{14}=18$.
	\choiceTF
	{\True Công sai của cấp số cộng là $ d=3$}
	{Số hạng đầu của cấp số cộng là $u_1=21$}
	{\True Số hạng thứ $ 9$ của cấp số cộng là $u_9=3$}
	{Tổng $ 5$ số hạng đầu của cấp số cộng là $S_5=-60$}
\loigiai{
	\begin{itemchoice}
		\itemch
		Gọi $u_1$ là số hạng đầu, $ d$ là công sai của cấp số cộng $\left(u_n\right)$.\\
		Ta có
		$\heva{&u_4=u_1+3d \\&u_{14}=u_1+13d}$
		$\Leftrightarrow \heva{&u_1+3d=-12 \\&u_1+13d=18} \Leftrightarrow\heva{& d=3\\&u_1=-21.}$
		\itemch
		$u_1=-21.$
		\itemch
		Số hạng thứ $ 9$ là $u_9=u_1+8d$$=-21+8\cdot 3$$=3$.
		\itemch
		Tổng $ 5$ số hạng đầu là $S_5=5u_1+\dfrac{5\left(5-1\right)}{2}d=-75$.
	\end{itemchoice}
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Giá của một chiếc xe ô tô lúc mới mua là $680$ triệu đồng. Cứ sau mỗi năm sử dụng, giá của chiếc xe ô tô giảm $50$ triệu đồng. Gọi $u_n$ (triệu đồng) là giá của chiếc ô tô trong năm thứ $n$ sử dụng.
	\choiceTF
	{\True $u_2=630$}
	{Dãy số $(u_n)$ là cấp số cộng với công sai $d=50$}
	{\True Giá của chiếc ô tô sau $3$ năm sử dụng lớn hơn $500$ triệu đồng}
	{Sau ít nhất $8$ năm sử dụng thì giá của chiếc ô tô nhỏ hơn một nửa giá trị ban đầu của nó}
\loigiai{
	\begin{itemchoice}
		\itemch Giá của chiếc ô tô trong năm thứ $2$ là $u_2=680-50=630$ triệu đồng.
		\itemch Dãy số $(u_n)$ là cấp số cộng với công sai $d=-50$.
		\itemch Giá của chiếc ô tô sau $3$ năm sử dụng $u_4=u_1+3d=680-3\cdot 50=530$ triệu đồng.
		\itemch Ta có
		\begin{eqnarray*}
			u_n<340&\Leftrightarrow& u_1+(n-1)\cdot d<340
			\Leftrightarrow 680+(n-1)\cdot (-50)<340 \\
			& \Leftrightarrow& -50n+730<340
			\Leftrightarrow n>7{,}8.
		\end{eqnarray*}
		Suy ra đến năm thứ $8$ thì giá trị của chiếc xe nhỏ hơn một nửa giá trị ban đầu của nó.
	\end{itemchoice}
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Người ta trồng $3240$ cây theo một hình tam giác như sau: hàng thứ nhất trồng $1$ cây, hàng thứ hai trồng $2$ cây, hàng thứ ba trồng $3$ cây, $\ldots$
	\choiceTF
	{\True Số cây mỗi hàng lập thành một cấp số cộng $\left(u_n\right)$ có số hạng đầu là $u_1=1$}
	{Số cây mỗi hàng lập thành một cấp số cộng $\left(u_n\right)$ có công sai là $ d=2$}
	{\True Có tất cả $80$ hàng cây}
	{Hàng thứ $20$ trồng được $ 40$ cây}
\loigiai{
	\begin{itemchoice}
		\itemch
		Số cây mỗi hàng (bắt đầu từ hàng thứ nhất) lập thành một cấp số cộng $\left(u_n\right)$ có $u_1=1,d=1$.
		\itemch
		Công sai $d=1$.
		\itemch
		Ta có $ 3240=S_n=n{u_1}+\dfrac{n(n-1)}{2}d\Leftrightarrow{n^2}+n-6480=0\Leftrightarrow n=80$.
		\itemch
		Số cây hàng thứ $ 20$ trồng được là $u_{20}=u_1+19d=20$.
	\end{itemchoice}
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Cho cấp số cộng $(u_{n})$ có $u_{1}=-2$; $u_{3}=6$. Hỏi $2022$ là số hạng thứ bao nhiêu của cấp số cộng đó?
	\shortans{$507$}
\loigiai{
	Ta có $u_{3}=u_{1}+2d \Rightarrow 6=-2+2d \Rightarrow d=4$. \\
	Số hạng tổng quát là $u_{n}=u_{1}+(n-1)d=-2+(n-1) \cdot 4=4n-6$. \\
	Ta có $4n-6=2022 \Leftrightarrow 4n=2028 \Leftrightarrow n=507$. \\
	Vậy $2022$ là số hạng thứ $507$ của cấp số cộng.
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Một chiếc đồng hồ đánh chuông, số tiếng chuông được đánh bằng số giờ mà đồng hồ chỉ tại thời điểm đánh chuông. Hỏi một ngày đồng hồ đó đánh bao nhiêu tiếng chuông báo giờ (mỗi ngày $24$ tiếng)?
	\shortans{$156$}
\loigiai{
	Gọi $u_{n}$ là số tiếng chuông ở giờ thứ $n$, trong đó $1 \leq n \leq 12$.\\
	Sau $12$ giờ đồng hồ đánh được
	$S_{12}=u_{1}+\ldots+u_{12}=1+2+\ldots+12=6 \cdot (1+12)=78$ tiếng. \\
	Một ngày đồng hồ đánh được $78 \cdot 2=156$ tiếng.
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Trên một bàn cờ có nhiều ô vuông, người ta đặt $7$ hạt dẻ vào ô đầu tiên, sau đó đặt tiếp vào ô thứ hai số hạt nhiều hơn ô thứ nhất là $5$, tiếp tục đặt vào ô thứ ba số hạt nhiều hơn ô thứ hai là $5$, và cứ thế tiếp tục đến ô thứ $n$. Biết rằng đặt hết số ô trên bàn cờ người ta phải sử dụng $25450$ hạt. Hỏi bàn cờ đó có bao nhiêu ô vuông?
	\shortans{$100$}
\loigiai{
	Số hạt dẻ trên mỗi ô (bắt đầu từ ô thứ nhất) theo thứ tự đó lập thành cấp số cộng $(u_{n})$ có $u_{1}=7,d=5$. \\
	Gọi $n$ là số ô trên bàn cờ thì $u_{1}+u_{2}+\ldots+u_{n}=25\,450=S_{n}$. \\
	Ta có
	\allowdisplaybreaks
	\begin{eqnarray*}
		&&25\,450=S_{n}=nu_{1}+\dfrac{n(n-1)}{2} \cdot d=7n+ \dfrac{n^2-n}{2} \cdot 5\\
		&\Leftrightarrow& 5n^2+9n-50\,900=0 \\
		&\Leftrightarrow& n=100.
	\end{eqnarray*}
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Hùng đang tiết kiệm để mua một cây guitar. Trong tuần đầu tiên, anh ta để dành $42$ đô la, và trong mỗi tuần tiếp theo anh ta đã thêm $8$ đô la vào tài khoản tiết kiệm của mình. Cây guitar Hùng cần mua có giá $400$ đô la. Hỏi vào tuần thứ bao nhiêu thì anh ấy có đủ tiền để mua cây guitar đó?
	\shortans{$46$}
\loigiai{
	Gọi $n$ là số tuần anh ta đã thêm $8$ đô la vào tài khoản tiết kiệm của mình. \\
	Số tiền anh ta tiết kiệm được sau $n$ tuần đó là $S=42+8n$.\\
	Theo bài ra $S=42+8n \geq 400 \Leftrightarrow n \geq 44\cdot 75 \Rightarrow n=45$.\\
	Vậy kể cả tuần đầu thì tuần thứ $46$ anh ta có đủ tiền để mua cây guitar đó.
	}

