%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Mặt cắt của một tổ ong có hình lưới tạo bởi các ô hình lục giác đều. Từ một ô đầu tiên, bước thứ nhất, các ong thợ tạo ra vòng $1$ gồm $6$ ô lục giác; bước thứ hai, các ong thợ sẽ tạo ra vòng $2$ có $12$ ô bao quanh vòng $1$; bước thứ ba, các ong thợ sẽ tạo ra $18$ ô bao quanh vòng $2$; cứ thế tiếp tục như hình vẽ bên dưới. Tính số ô trên vòng thứ $108$ mà ong thợ tạo ra?
	\begin{center}
		\begin{tikzpicture}[scale=0.4, font=\footnotesize, line join=round, line cap=round, >=stealth]
			\def\k{0.7}
			\node[draw,regular polygon, regular polygon sides=6, minimum size=\k cm,double,fill=orange] (hexagon) {};
			\def\r{1.33} % Bán kính tính từ tâm lục giác đến một đỉnh
			\foreach \angle in {-90,90, 30, -30, 150,-150} {
			\node[draw,regular polygon, regular polygon sides=6, minimum size=\k cm,fill=orange!20] at ({1.2*\r*cos(\angle)}, {1.2*\r*sin(\angle)}) {};
			}
			\foreach \angle in {-90,90, 30, -30, 150,-150} {
			\node[draw,regular polygon, regular polygon sides=6, minimum size=\k cm,fill= orange!50] at ({2.4*\r*cos(\angle)}, {2.4*\r*sin(\angle)}) {};
			}
			\foreach \angle in {0,180,60,-60,120,-120} {
			\node[draw,regular polygon, regular polygon sides=6, minimum size=\k cm,fill= orange!50] at ({2.1*\r*cos(\angle)}, {2.1*\r*sin(\angle)}) {};
			}
		\end{tikzpicture}
	\end{center}
	%hình vẽ
	\shortans{$648$}
\loigiai{
	Số ô lục giác ở từng vòng tạo thành cấp số cộng có công sai $d=6$. \\
	Với cấp số cộng có $u_{1}=6$; $u_{2}=12$; $u_{3}=18$. \\
	Vậy số ô trên vòng thứ $108$ mà ong thợ tạo ra là $u_{108}=u_{1}+(n-1)d=6+(108-1) \cdot 6=648$.
	}

%[2D1H3-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Cho cấp số cộng $\left(u_n\right)$ có số hạng đầu $u_1=-3$ và công sai $d=2$.
	\begin{enumerate}
		\item Tìm $u_{12}$.
		\item Số $195$ là số hạng thứ bao nhiêu của cấp số cộng đó?
	\end{enumerate}
\loigiai{\begin{enumerate}
	\item Tìm $u_{12}$.\\
	Ta có $u_{12}=u_1+11d=-3+11\cdot 2=19$.
	\item Số $195$ là số hạng thứ bao nhiêu của cấp số cộng đó?\\
	Ta có $u_n=u_1+(n-1)d=-3+(n-1)2=195$, suy ra $n=100$.\\
	Vậy $195$ là số hạng thứ $100$ của cấp số cộng $\left(u_n\right)$ đã cho.
	\end{enumerate}
	}

%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	Giá của một chiếc xe ô tô lúc mới mua là $680$ triệu đồng. Cứ sau mỗi năm sử dụng, giá của chiếc ô tô đó giảm $55$ triệu đồng. Tính giá còn lại của chiếc xe sau $5$ năm sử dụng.
\loigiai{
	Sau mỗi năm giá của chiếc ô tô giảm $55$ triệu đồng, do đó ta có thể xem giá của chiếc ô tô đó là một cấp số cộng với $u_1=680$ và công sai $d=-55$. \\
	Vậy giá của chiếc ô tô sau $5$ năm sử dụng là $ u_5=680+4\cdot (-55)=460$ triệu đồng.
	}

questions.solution:
Số hộp sữa của mỗi hàng lập thành một cấp số cộng với $u_1=1$ và $d=2$.\\
	Theo đề ta có \begin{eqnarray*}
	&&S_n=\dfrac{n[2u_1+(n-1)d]}{2}=900\\&\Leftrightarrow & \dfrac{n[2\cdot 1+(n-1)\cdot 2]}{2}=900\\&\Leftrightarrow & 2n^2=1800\\ &\Leftrightarrow & n^2=900 \\ &\Leftrightarrow &n=30\ (do n>0).
	\end{eqnarray*}
	Số hộp sữa ở hàng dưới cùng là $u_{30}=1+29\cdot 2=59$.

questions.rawBody:
%[1D2V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Khổng Xuân Thạnh]
	\immini{	Trong hội chợ tết Mậu Tuất $2018$, một công ty sữa muốn xếp $900$ hộp sữa theo số lượng $1$, $3$, $5$,$\ldots$ từ trên xuống dưới (số hộp sữa trên mỗi hàng xếp từ trên xuống là các số lẻ liên tiếp). Hàng dưới cùng có bao nhiêu hộp sữa?}{
	\begin{tikzpicture}
		\draw (0,0)--(7,0);
		\draw (0,1)--(7,1);
		\draw (1,2)--(6,2);
		\draw (2,3)--(5,3);
		\draw (3,4)--(4,4);
		\foreach \i in {0,...,7}
		\draw (\i,0)--(\i,1);
		\foreach \i in {1,...,6}
		\draw (\i,1)--(\i,2);
		\foreach \i in {2,...,5}
		\draw (\i,2)--(\i,3);
		\foreach \i in {3,...,4}
		\draw (\i,3)--(\i,4);
	\end{tikzpicture}
	}
\loigiai{
	Số hộp sữa của mỗi hàng lập thành một cấp số cộng với $u_1=1$ và $d=2$.\\
	Theo đề ta có \begin{eqnarray*}
	&&S_n=\dfrac{n[2u_1+(n-1)d]}{2}=900\\&\Leftrightarrow & \dfrac{n[2\cdot 1+(n-1)\cdot 2]}{2}=900\\&\Leftrightarrow & 2n^2=1800\\ &\Leftrightarrow & n^2=900 \\ &\Leftrightarrow &n=30\ (\text{do }n>0).
	\end{eqnarray*}
	Số hộp sữa ở hàng dưới cùng là $u_{30}=1+29\cdot 2=59$.
	}

%[1D2H3-5]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Dương Công Tạo]
	Ba số $-\sqrt{3}$; $x$; $-3\sqrt{3}$ theo thứ tự là ba số hạng liên tiếp của một cấp số nhân. Tìm công bội $q$ của cấp số nhân đó.
	\choice
	{$q=\pm 3$}
	{$q=-\sqrt{3}$}
	{$q=3$}
	{\True $q=\pm \sqrt{3}$}
\loigiai{
	Do $-\sqrt{3}$; $x$; $-3\sqrt{3}$ là một cấp số nhân. Suy ra $ x^2=9\Leftrightarrow x=\pm 3$.\\
	Vậy công bội của cấp số nhân là $q=\dfrac{x}{-\sqrt{3}}=\mp \sqrt{3}$.
	}

%[1D2H3-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Dương Công Tạo]
	Trong các dãy số $\left(u_n \right)$ với số hạng tổng quát sau, dãy số nào là cấp số nhân?
	\choice
	{\True $u_n=5^n$}
	{$u_n=1+5n$}
	{$u_n=5^n+1$}
	{$u_n=5+n^2$}
\loigiai{
	Dãy số $u_n=5^n$ là cấp số nhân vì $\dfrac{u_{n+1}}{u_n}=\dfrac{5^{n+1}}{5^n}=5$, $\forall n\in\mathbb{N}^*$.
	}

%[1D2H3-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Dương Công Tạo]
	Cho cấp số nhân $\left(u_n \right)$, biết $u_2 \cdot u_6=64$. Giá trị của $u_3 \cdot u_5$ là
	\choice
	{$-8$}
	{$-64$}
	{\True $64$}
	{$8$}
\loigiai{
	Ta có $u_3 \cdot u_5=\left(u_2\cdot q\right) \cdot u_5=u_2\left(u_5\cdot q\right)=u_2 \cdot u_6=64$.
	}

%[1D2N3-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Dương Công Tạo]
	Cho cấp số nhân $\left(u_n \right)$ với $u_1=-2$ và $q=-5$. Viết bốn số hạng đầu tiên của cấp số nhân.
	\choice
	{$-2$; $10$; $50$; $-250$}
	{\True $-2$; $10$; $-50$; $250$}
	{$-2$; $-10$; $-50$; $-250$}
	{$-2$; $10$; $50$; $250$}
\loigiai{
	Ta có $u_1=-2$, $q=-5$. Khi đó, bốn số hạng đầu tiên của cấp số nhân $\left(u_n \right)$ là
	\begin{itemize}
		\item $u_1=-2$.
		\item $u_2=u_1\cdot q=10$.
		\item $u_3=u_2\cdot q=-50$.
		\item $u_4=u_3\cdot q=250$.
	\end{itemize}
	}

questions.solution:
Ta có
	<ul class="kntt-list"><li>Dãy số $-2$; $2$; $-2$; $2$; {\dots}; $-2$; $2$; $-2$; $2$; {\dots} là cấp số nhân với số hạng đầu $u_1=-2$, công bội $q=-1$.</li><li>Dãy số $\left(u_n \right)$ xác định bởi công thức $u_n=3^n+1$ có $u_1=3^1+1=4$, $u_2=3^2+1=10$, $u_3=3^3+1=28$.
		\begin{nx}
			$\dfrac{u_3}{u_2} \ne \dfrac{u_2}{u_1}$ nên $\left(u_n \right)$ không là cấp số nhân.
		\end{nx}</li><li>Dãy số $\left(u_n \right)$, xác định bởi hệ: $\heva{&{u_1=1} \\
		&{u_n=u_{n-1}+2\; \left(n\in \mathbb{N}^{*},n\ge 2\right)}
		}$ có $u_1=1$, $u_1=3$, $u_3=5$.
		\begin{nx}
			$\dfrac{u_3}{u_2} \ne \dfrac{u_2}{u_1}$ nên $\left(u_n \right)$ không là cấp số nhân.
		\end{nx}</li><li>Dãy số các số tự nhiên $1$, $2$, $3$, {\dots} có $u_1=1$, $u_1=2$, $u_3=3$.
		\begin{nx}
			$\dfrac{u_3}{u_2} \ne \dfrac{u_2}{u_1}$ nên không là cấp số nhân.
		\end{nx}</li></ul>

