		\begin{itemize}
			\item Tứ phân vị thứ hai là $\dfrac{x_{41}+x_{42}}{2}\in [8;8{,}5)$. Do đó
			\[Q_2=u_m+\dfrac{\dfrac{n}{2}-C}{n_m}\cdot\left(u_{m+1}-u_m\right)=8+\dfrac{\dfrac{82}{2}-34}{24}\cdot (8{,}5-8)=8{,}15. \]
			\item Tứ phân vị thứ nhất là $x_{21}\in [7{,}5;8)$
			\[Q_1=u_m+\dfrac{\dfrac{n}{4}-C}{n_m}\cdot \left(u_{m+1}-u_m\right)=7{,}5+\dfrac{\dfrac{82}{4}-18}{16}\cdot (8-7{,}5)\approx 7{,}58. \]
			\item Tứ phân vị thứ ba là $x_{61}\in [8{,}5;9)$
			\[Q_3=u_j+\dfrac{\dfrac{3n}{4}-C}{n_j}\cdot \left(u_{j+1}-u_j\right)=8{,}5+\dfrac{\dfrac{3\cdot 82}{4}-58}{13}\cdot (9-8{,}5)\approx 8{,}63. \]
