%[1D5H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Tấn Tuyên]
	Điều tra về chiều cao của học sinh khối $10$, ta có kết quả dưới đây\\
	\centerline{
		\begin{tabular}{|c|c|c|c|c|c|c|}
			\hline
			Chiều cao (cm)	& $[150;152)$ & $[152;154)$ & $[154;156)$ & $[156;158)$ & $[158;160)$ & $[160;162)$ \\
			\hline
			Số học sinh	& $5$ & $18$ & $40$ & $26$ & $8$ & $3$ \\
			\hline
	\end{tabular} }
	Xét tính đúng sai của các khẳng định sau
	\choiceTF
	{\True Tổng số học sinh điều tra là $100$}
	{\True Chiều cao trung bình của học sinh là $155{,}46$}
	{Số trung vị của mẫu số liệu là $156{,}35$}
	{\True Tứ phân vị thứ nhất của mẫu số liệu là $154{,}1$}
	\loigiai{
		\begin{itemchoice}
			\itemch Đúng vì tổng số học sinh điều tra là $5+18+40+26+8+3=100$.
			\itemch Đúng vì chiều cao trung bình của học sinh là 
			$$\bar{x}=\dfrac{151\cdot 5+153\cdot 18+155\cdot 40+157\cdot 26+159\cdot 8+161\cdot 3}{100}\approx 155{,}46 .$$
			\itemch Sai vì $n=100$ nên trung vị là $\dfrac{x_{50}+x_{51}}{2}$ mà $x_{50}; x_{51}\in [154;156)$.\\
			Do đó $M_e=154+\dfrac{\dfrac{100}{2}-(5+18)}{40}\cdot (156-154)\approx 155{,}35$.
			\itemch Đúng vì tứ phân vị thứ nhất $Q_1$ là $\dfrac{x_{25}+x_{26}}{2}$ mà $x_{25}; x_{26}\in[154;156)$. \\
			Do đó $Q_1=154+\dfrac{\dfrac{100}{4}-(5+18)}{40}\cdot (156-154)\approx 154{,}1$.
		\end{itemchoice}
	}

