	Khảo sát cân nặng trung bình của học sinh lớp $11A1$ và thu được kết quả ở bảng số liệu dưới đây\\
	\centerline{
		\begin{tabular}{|c|c|c|c|c|c|c|}
			\hline
			Cân nặng (kg)	& $[40{,}5;45{,}5)$ & $[45{,}5;50{,}5)$ & $[50{,}5;55{,}5)$ & $[55{,}5;60{,}5)$ & $[60{,}5;65{,}5)$ & $[65{,}5;70{,}5)$ \\
			\hline
			Số học sinh	& $9$ & $7$ & $16$ & $5$ & $2$ & $3$\\
			\hline
	\end{tabular} }
	Xét tính đúng sai của các khẳng định sau
	\choiceTF
	{\True Số học sinh được khảo sát là $42$}
	{\True Cân nặng trung bình của học sinh không ít hơn $52$}
	{Mốt của mẫu số liệu là $51{,}75$}
	{Tứ phân vị thứ nhất lớn hơn $47$}
	\loigiai{
		\begin{itemchoice}
			\itemch Đúng vì $n=9+7+16+5+2+3=42$.
			\itemch Đúng vì cân nặng trung bình của học sinh là $$\bar{x}=\dfrac{43\cdot 9+48\cdot 7+53\cdot 16+58\cdot 5+63\cdot 2 +68\cdot 3 }{42}\approx 52{,}17.$$
			\itemch Sai vì tần số lớn nhất thuộc nhóm $[50{,}5;55{,}5)$ nên $$M_O=50{,}5+\dfrac{16-7}{16-7+16-5}\cdot \left(55{,}5-50{,}5\right)=52{,}75.$$
			\itemch Sai vì $n=42$ nên tứ phân vị thứ nhất là $x_{11}\in [45{,}5;50{,}5)$. \\ Do đó
			$Q_1=45{,}5+\dfrac{\dfrac{42}{4}-9}{7}\cdot (45{,}5-40{,}5)\approx 46{,}57$.
		\end{itemchoice}
	}

