	Doanh thu bán hàng trong $20$ ngày được lựa chọn ngẫu nhiên của một cửa hàng được tổng hợp bằng bảng số liệu ghép nhóm dưới đây\\
	\centerline{
		\begin{tabular}{|c|c|c|c|c|c|}
			\hline
			Doanh thu (triệu đồng)	& $[5;7)$ & $[7;9)$ & $[9;11)$ & $[11;13)$ & $[13;15)$ \\
			\hline
			Số ngày	& $2$ & $7$ & $7$ & $3$ & $1$ \\
			\hline
	\end{tabular} }
	Xét tính đúng sai của các khẳng định sau
	\choiceTF
	{Số ngày doanh thu bán hàng ít hơn $9$ triệu là $7$ ngày}
	{\True Số ngày doanh thu vượt quá $11$ triệu là $4$ ngày}
	{\True Doanh thu trung bình trong $20$ ngày là $9{,}4$ triệu}
	{Tứ phân vị thứ nhất của mẫu số liệu là $8{,}87$}
	\loigiai{
		\begin{itemchoice}
			\itemch Sai vì số ngày doanh thu bán hàng ít hơn $9$ triệu là $2+7=9$ ngày.
			\itemch Đúng vì số ngày doanh thu bán hàng vượt quá $11$ triệu là $3+1=4$ ngày .
			\itemch Đúng vì doanh thu trung bình của cửa hàng là 
			$$\bar{x}=\dfrac{6\cdot 2+8\cdot 7+10\cdot 7+12\cdot 3+14\cdot 1}{20}\approx 9{,}4 \ \text{triệu đồng}.$$
			\itemch Sai vì $n=20$ nên tứ phân vị thứ nhất bằng $\dfrac{x_{5}+x_{6}}{2}$ mà $x_{5};\ x_{6}\in [7; 9)$. \\
			Do đó $Q_1=7+\dfrac{\dfrac{30}{4}-(2)}{7}\cdot (9-7)\approx 7{,}86$. 
		\end{itemchoice}
	}

