questions.rawBody:
%[1H4H1-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình chóp $S. ABCD$, đáy là tứ giác lồi $ABCD$ có các cạnh đối không song song với nhau. Gọi $M$ là điểm trên cạnh $SA$, $O$ là giao điểm của $AC$ và $BD$. Khi đó
	\choiceTFt
	{\True Giao tuyến của $(SAC)$ và $(SBD)$ là $SO$}
	{\True Giao tuyến của $(SAB)$ và $(SCD)$ là $SF$, với $F$ là giao điểm của $AB$ và $CD$}
	{Giao tuyến của $(SBC)$ và $(SAD)$ là $SM$}
	{\True Giao tuyến của $(BCM)$ và $(SAD)$ là $ME$, với $E$ là giao điểm của $AD$ và $BC$}
\loigiai{\centerline{
	\begin{tikzpicture}[scale=0.8,line cap=round,line join=round,font=\footnotesize]
		\path (0:0) coordinate(A) (0:4) coordinate(D) (-65:2.4) coordinate(B) ++(20:2.3) coordinate(C) (50:3) coordinate(S);
		\path ($(S)!.4!(A)$) coordinate(M) (intersection of A--C and B--D) coordinate(O) (intersection of A--D and B--C) coordinate(E) (intersection of A--B and C--D) coordinate(F);
		\draw (S)--(A)--(F)--cycle (S)--(C)--(E)--cycle (C)--(F) (S)--(B)--(M);
		\draw[dashed] (S)--(D)--(C)--(A)--(E) (C)--(B)--(D) (S)--(O)--(M)--(C) (M)--(E);
		\foreach \d/\g in {A/180, B/-135, C/-45, D/-45, S/90, O/-95, M/150, E/0, F/-90}
		\fill (\d) circle(1pt) node[shift={(\g:.3)}]{$\d$};
	\end{tikzpicture}}
	\begin{itemchoice}
		\itemch Ta có $S\in (SAC)\cap (SBD)$.\\
		Trong mặt phẳng $(ABCD)$, ta có $\heva{&AC\cap BD =O\\&AC\subset (SAC)\\&BD\subset (SBD)}$ nên $O\in (SAC)\cap (SBD)$.\\
		Vậy giao tuyến của $(SAC)$ và $(SBD)$ là $SO$.
		\itemch Ta có $S\in (SAB)\cap (SCD)$.\\
		Trong mặt phẳng $(ABCD)$, gọi $AB\cap CD =F$, mà $\heva{&AB\subset (SAB)\\&CD\subset (SCD)}$ nên $F\in (SAB)\cap (SCD)$.\\
		Vậy giao tuyến của $(SAB)$ và $(SCD)$ là $SF$.
		\itemch Ta có $S\in (SBC)\cap (SAD)$.\\
		Trong mặt phẳng $(ABCD)$, gọi $BC\cap AD = E$, mà $\heva{&BC\subset (SBC)\\&AD\subset (SAD)}$ nên $E\in (SBC)\cap (SAD)$.\\
		Vậy giao tuyến của $(SBC)$ và $(SAD)$ là $SE$, không phải $SM$.
		\itemch Ta có $M\in (BCM)\cap (SAD)$.\\
		Trong mặt phẳng $(ABCD)$, gọi $BC\cap AD = E$, mà $\heva{&BC\subset (BCM)\\&AD\subset (SAD)}$ nên $E\in (BCM)\cap (SAD)$.\\
		Vậy giao tuyến của $(BCM)$ và $(SAD)$ là $ME$.
	\end{itemchoice}
	}

%[1H4H1-6]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình bình hành $ABCD$ và một điểm $S$ không thuộc mặt phẳng $(ABCD)$, các điểm $M$, $N$ lần lượt là trung điểm của đoạn thẳng $AB$, $SC$. Gọi $O=AC \cap BD$. Khi đó
	\choiceTFt
	{\True $SO$ là giao tuyến của hai mặt phẳng $(SAC)$ và $(SBD)$}
	{\True Giao điểm $I$ của đường thẳng $AN$ và mặt phẳng $(SBD)$ là điểm nằm trên đường thẳng $SO$}
	{Giao điểm $J$ của đường thẳng $MN$ và mặt phẳng $(SBD)$ là điểm nằm trên đường thẳng $SD$}
	{\True Ba điểm $I$, $J$, $B$ thẳng hàng}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=1, font=\footnotesize, line join=round, line cap=round,>=stealth]
			\path
			(0,0) coordinate (A)
			(1.3,-2.1) coordinate (B)
			(4.8,-2.1)coordinate (C)
			($(A)+(C)-(B)$) coordinate (D)
			($(D)+(-0.5,3.2)$) coordinate (S)
			(intersection of A--C and B--D) coordinate (O)
			($(A)!0.5!(B)$) coordinate (M)
			($(S)!0.5!(C)$) coordinate (N)
			(intersection of C--M and B--D) coordinate (P)
			(intersection of A--N and S--O) coordinate (I)
			(intersection of M--N and S--P) coordinate (J)
			;
			\draw (S)--(A)--(B)--(C)--cycle (S)--(B);
			\draw[dashed] (O)--(S)--(D)--(B)--(A)--(C)--(D)--(A)--(N)--(M)--(C)
			(P)--(S);
			\foreach \p/\q in {S/90,A/180,B/-90,C/-90,D/0,O/-90,M/220,N/30, P/-90,I/40,J/160}
			\fill[black] (\p) circle (1.0pt)node[shift={(\q:3mm)}]{$\p$};
		\end{tikzpicture}
	\end{center}
	\begin{itemchoice}
		\itemch $SO$ là giao tuyến của hai mặt phẳng $(SAC)$ và $(SBD)$ (hiển nhiên vì $S, O$ là điểm chung).
		\itemch Trong mặt phẳng $(SAC)$, $AN$ cắt $SO$ tại $I$.\\ Vì $SO \subset (SBD)$ nên $I = AN \cap (SBD)$.\\ Vậy $I$ nằm trên $SO$.
		\itemch Trong mặt phẳng $(SCM)$, $MN$ cắt $SP$ tại $J$ (với $P=CM \cap BD$).\\ Vì $SP \subset (SBD)$ nên $J = MN \cap (SBD)$.\\ Vậy $J$ nằm trên $SP$, không phải $SD$.
		\itemch Ta có $B, I, J$ đều thuộc giao tuyến của hai mặt phẳng $(ABN)$ và $(SBD)$.\\ Do đó $3$ điểm này thẳng hàng.
	\end{itemchoice}
	}

