%[1H4V1-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình chóp $S. ABCD$ có đáy $ABCD$ là hình bình hành tâm $O$. Gọi $M$ là trung điểm của $SC$, $N$ là trung điểm của $OB$ và $I$ là trọng tâm của tam giác $SAC$. Khi đó
	\choiceTFt
	{Giao điểm của $SC$ và mặt phẳng $(AMN)$ là điểm $N$}
	{\True Giao điểm của $AM$ và mặt phẳng $(SBD)$ là điểm $I$}
	{Giao điểm của $NI$ và mặt phẳng $(SAD)$ là điểm $K$ thuộc đường thẳng $SA$}
	{Giao điểm của đường thẳng $SD$ và mặt phẳng $(AMN)$ là trung điểm của $SD$}
	\loigiai
	{
	\centerline
	{
	\begin{tikzpicture}[scale=1.2,line cap=round,line join=round,font=\footnotesize, >=stealth]
		% --- ĐỊNH NGHĨA CÁC ĐIỂM ---
		\coordinate (A) at (0,0);
		\coordinate (B) at (4,0);
		\coordinate (D) at (1.2, 1.5);
		% Tính C theo quy tắc hình bình hành: C = B + D - A
		\coordinate (C) at ($(B)+(D)-(A)$);
		\coordinate (S) at (2.8, 4);
		% Các điểm phụ thuộc
		\coordinate (O) at ($(A)!.5!(C)$);
		\coordinate (M) at ($(S)!.5!(C)$);
		\coordinate (N) at ($(O)!.5!(B)$);
		% --- TÌM GIAO ĐIỂM ---
		\coordinate (I) at (intersection of A--M and S--O);
		\coordinate (K) at (intersection of N--I and S--D);
		% --- XỬ LÝ ĐIỂM H (TÁCH RA ĐỂ TRÁNH LỖI) ---
		% Cần vẽ đường qua O song song NK.
		% Ta tạo điểm phụ H_dir sao cho vecto OH_dir = vecto NK
		% => H_dir = O + (K - N)
		\coordinate (H_dir) at ($(O)+(K)-(N)$);
		% H là giao điểm của SD và đường thẳng O--H_dir
		\coordinate (H) at (intersection of S--D and O--H_dir);
		% --- VẼ HÌNH ---
		% Nét liền
		\draw (S)--(A)--(B)--(C)--(S) (S)--(B);
		\draw (S)--(M);
		% Nét đứt
		\draw[dashed] (S)--(D)--(C) (D)--(A) (D)--(B);
		\draw[dashed] (A)--(M)--(N) (N)--(K);
		\draw[dashed] (S)--(O);
		% Vẽ đường phụ OH màu xanh
		\draw[dashed, blue, thick] (O)--(H);
		% --- VẼ ĐIỂM VÀ NHÃN ---
		\foreach \d/\g in {A/-135, B/-45, C/0, D/180, S/90, O/-95, M/45, N/-90, I/170, K/135}
		\fill (\d) circle(1.2pt) node[shift={(\g:.35)}]{$\d$};
		% Nhãn điểm H riêng
		\fill[blue] (H) circle(1.2pt) node[left, blue]{$H$};
	\end{tikzpicture}
	}
	\begin{itemchoice}
		\itemch Vì $M \in SC$ và $M \in (AMN)$ nên giao điểm của $SC$ và $(AMN)$ là điểm $M$.
		\itemch Trong $\triangle SAC$, $SO$ là trung tuyến.\\ $I$ là trọng tâm $\triangle SAC$ nên $I \in SO$.\\ Mà $SO \subset (SBD) \Rightarrow I \in (SBD)$.\\ Vậy $I = AM \cap (SBD)$.
		\itemch Ta có $I \in SO \subset (SBD)$ và $N \in OB \subset (SBD)$ nên $NI \subset (SBD)$.\\
		Trong $(SBD)$, $NI$ cắt $SD$ tại $K$. Mà $SD \subset (SAD)$ nên $K$ là giao điểm của $NI$ và $(SAD)$.\\
		Vậy $K$ thuộc $SD$ (không phải $SA$).
		\itemch
		Trong mặt phẳng $(SBD)$, kẻ đường thẳng qua $O$ song song với $NK$ cắt $SD$ tại $H$.\\
		Theo định lý Ta-lét
		\begin{itemize}
			\item Xét $\triangle DNK$ có $OH \parallel NK$\\
			Do $O$ là trung điểm $BD$, $N$ là trung điểm $OB$ nên $DO = 2ON \Rightarrow DN = 3ON$. Khi đó
			\[ \dfrac{DH}{DK} = \dfrac{DO}{DN} = \dfrac{2ON}{3ON} = \dfrac{2}{3} \Rightarrow DH = \dfrac{2}{3}DK \Rightarrow KH = \dfrac{1}{3}DK. \quad (1) \]
			\item Xét $\triangle SOH$ có $IK \parallel OH$ (do $K \in NI$):
			Do $I$ là trọng tâm $\triangle SAC$ nên $\dfrac{SI}{SO} = \dfrac{2}{3}$.
			\[ \dfrac{SK}{SH} = \dfrac{SI}{SO} = \dfrac{2}{3} \Rightarrow SK = \dfrac{2}{3}SH \Rightarrow KH = \dfrac{1}{3}SH. \quad (2) \]
		\end{itemize}
		Từ $(1)$ và $(2)$ suy ra $DK = SH$.\\ Thay vào $SK = \dfrac{2}{3}SH$, ta được $SK = \dfrac{2}{3}DK$.\\
		Vậy $\dfrac{SK}{KD} = \dfrac{2}{3}$, nghĩa là $K$ không phải trung điểm của $SD$.
	\end{itemchoice}
	}

