%[1H4V1-6]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình chóp $S. ABCD$ có đáy $ABCD$ là hình thang với hai đáy $AB$, $CD$ sao cho $AB=2CD$. Gọi $E$ là giao điểm của $AD$ và $BC$; $F$ là trung điểm cạnh $SA$ và điểm $G$ thuộc đoạn thẳng $SD$ sao cho $GS=2GD$. Tính tỉ số $\dfrac{EG}{EF}$ (\textit{làm tròn kết quả đến hàng phần trăm}).
	\par
	\shortans[0]{0{,}67}
\loigiai{
	\immini{
	Xét tam giác $ABE$ ta có $AB \parallel DC$ và $AB=2DC$ nên $CD$ là đường trung bình của tam giác $ABE$.\\ Suy ra $D$ là trung điểm $AE$ và $C$ là trung điểm $BE$.\\
	Xét tam giác $SAE$ ta có $SD$ là đường trung tuyến và $SG=2GD$.\\ Suy ra $G$ là trọng tâm tam giác $SAE$.\\
	Mà $EF$ là trung tuyến trong tam giác $SAE$.\\ Do đó $G \in EF \Rightarrow E,G,F$ thẳng hàng và $\dfrac{EG}{EF}=\dfrac23\approx0{,}67$.
	}{
	\begin{tikzpicture}[scale=0.8, font=\footnotesize, line join=round, line cap=round,>=stealth]
		\tikzset{label style/.style={font=\footnotesize}}
		\pgfmathsetmacro\h{2}
		\pgfmathsetmacro\goc{40}
		\coordinate (A) at (0,0);
		\coordinate (S) at ($(A)+(70:2*\h)$);
		\coordinate (B) at ($(A)+(0:2*\h)$);
		\coordinate (D) at ($(A)+(-\goc:0.8*\h)$);
		\coordinate (C) at ($(D)+(0:\h)$);
		\path (intersection of A--D and B--C) coordinate(E)
		--($(S)!1/2!(A)$) coordinate(F)
		--($(S)!2/3!(D)$) coordinate(G)
		--(intersection of A--G and S--E) coordinate(H)
		--(intersection of B--H and S--C) coordinate(K)
		;
		\pgfresetboundingbox
		\draw[dashed] (A)--(B) (C)--(D);
		\draw (A)--(E)--(B)--(S)--cycle (C)--(S)--(D) (S)--(E)--(F) ;
		\foreach \x/\g in {A/180,B/0,C/0,D/210,S/90,E/-90,F/180,G/170}
		\fill [black] (\x) circle (1.5pt)
		+(\g:3mm) node{$\x$};
	\end{tikzpicture}
	}
	}

questions.solution:
\immini{
	Gọi $O = AC \cap BD$.\\ Trong $\triangle SBD$, $MN$ là đường trung bình nên $MN$ cắt $SO$ tại trung điểm $I$ của $SO$.\\
	Trong $(SAC)$, gọi $P = AI \cap SC$.\\ Vì $AI \subset (AMN)$ nên $P = SC \cap (AMN)$.\\
	Tính tỉ số bằng định lý Ta-lét\\
	Kẻ $OK \parallel AP$ ($K \in SC$).
	<ul class="kntt-list"><li>Xét $\triangle APC$ có $O$ là trung điểm $AC$, $OK \parallel AP$.\\ Suy ra $K$ là trung điểm $PC$, hay $PK = KC$ $(1)$.</li><li>Xét $\triangle SOK$ có $I$ là trung điểm $SO$ (cmt), $IP \parallel OK$ (do $P \in AI$).\\ Suy ra $P$ là trung điểm $SK$, hay $SP = PK$ $(2)$.</li></ul>
	Từ $(1)$ và $(2)$ suy ra $SP = PK = KC$.\\
	Do đó $SC = SP + PK + KC = 3SP \Rightarrow \dfrac{SP}{SC} = \dfrac{1}{3}$.\\
	Vậy $a=1$, $b=3 \Rightarrow a+b=4$.
	}{
	\begin{tikzpicture}[scale=0.7,font=\footnotesize,line join=round,line cap=round,>=stealth]
		\path
		(0,0) coordinate (A)
		(3,0) coordinate (D)
		(-1,-2) coordinate (B)
		($(B)-(A)+(D)$) coordinate (C)
		(0.3,3.2) coordinate (S)
		($(S)!0.5!(B)$) coordinate (M)
		($(S)!0.5!(D)$) coordinate (N)
		(intersection of A--C and B--D) coordinate (O)
		($(S)!0.5!(O)$) coordinate (I)
		(intersection of A--I and S--C) coordinate (P)
				($(P)!0.5!(C)$) coordinate (K)
		;
		\draw[dashed] (S)--(A)--(B)	(A)--(D) (A)--(M) (A)--(P) (A)--(N) (M)--(N) (S)--(O) (S)--(C) (B)--(D) (A)--(C);
				\draw[dashed, blue] (O)--(K) node[right, scale=0.7, blue]{$K$};
		\draw (S)--(B)--(C)--(D)--(S) (S)--(C) (M)--(P) (N)--(P);
		\foreach \x/\g in {A/-90,B/-90,C/-90,D/0,S/90,N/45,M/135,P/45,O/-90,I/-100}
		\fill[black](\x) circle (1pt)
		($(\g:3mm)+(\x)$) node {$\x$};
	\end{tikzpicture}
	}

questions.rawBody:
%[1H4C1-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình chóp $S. ABCD$ có đáy là hình bình hành. $M$, $N$ lần lượt là trung điểm của $SB$, $SD$. Mặt phẳng $(AMN)$ cắt $SC$ tại $P$, khi đó $\dfrac{SP}{SC}=\dfrac{a}{b}$ với $\dfrac{a}{b}$ là phân số tối giản và $b>0$. Giá trị của $a+b$ bằng bao nhiêu?
	\par
	\shortans[0]{4}
	\loigiai
	{
	\immini{
	Gọi $O = AC \cap BD$.\\ Trong $\triangle SBD$, $MN$ là đường trung bình nên $MN$ cắt $SO$ tại trung điểm $I$ của $SO$.\\
	Trong $(SAC)$, gọi $P = AI \cap SC$.\\ Vì $AI \subset (AMN)$ nên $P = SC \cap (AMN)$.\\
	Tính tỉ số bằng định lý Ta-lét\\
	Kẻ $OK \parallel AP$ ($K \in SC$).
	\begin{itemize}
		\item Xét $\triangle APC$ có $O$ là trung điểm $AC$, $OK \parallel AP$.\\ Suy ra $K$ là trung điểm $PC$, hay $PK = KC$ $(1)$.
		\item Xét $\triangle SOK$ có $I$ là trung điểm $SO$ (cmt), $IP \parallel OK$ (do $P \in AI$).\\ Suy ra $P$ là trung điểm $SK$, hay $SP = PK$ $(2)$.
	\end{itemize}
	Từ $(1)$ và $(2)$ suy ra $SP = PK = KC$.\\
	Do đó $SC = SP + PK + KC = 3SP \Rightarrow \dfrac{SP}{SC} = \dfrac{1}{3}$.\\
	Vậy $a=1$, $b=3 \Rightarrow a+b=4$.
	}{
	\begin{tikzpicture}[scale=0.7,font=\footnotesize,line join=round,line cap=round,>=stealth]
		\path
		(0,0) coordinate (A)
		(3,0) coordinate (D)
		(-1,-2) coordinate (B)
		($(B)-(A)+(D)$) coordinate (C)
		(0.3,3.2) coordinate (S)
		($(S)!0.5!(B)$) coordinate (M)
		($(S)!0.5!(D)$) coordinate (N)
		(intersection of A--C and B--D) coordinate (O)
		($(S)!0.5!(O)$) coordinate (I)
		(intersection of A--I and S--C) coordinate (P)
		% Điểm K cho lời giải Ta-lét
		($(P)!0.5!(C)$) coordinate (K)
		;
		\draw[dashed] (S)--(A)--(B)	(A)--(D) (A)--(M) (A)--(P) (A)--(N) (M)--(N) (S)--(O) (S)--(C) (B)--(D) (A)--(C);
		% Vẽ đường phụ OK
		\draw[dashed, blue] (O)--(K) node[right, scale=0.7, blue]{$K$};
		\draw (S)--(B)--(C)--(D)--(S) (S)--(C) (M)--(P) (N)--(P);
		\foreach \x/\g in {A/-90,B/-90,C/-90,D/0,S/90,N/45,M/135,P/45,O/-90,I/-100}
		\fill[black](\x) circle (1pt)
		($(\g:3mm)+(\x)$) node {$\x$};
	\end{tikzpicture}
	}
	}

questions.solution:
\immini{
	Gọi $h$ là độ dài cạnh bên của hình hộp ($h = AA'=BB'=CC'=DD'$).\\
	Theo giả thiết ta có độ dài các đoạn thẳng tính từ đỉnh phía trên ($A'$, $B'$, $C'$, $D'$) xuống mặt phẳng $(MNP)$ là
	<ul class="kntt-list"><li>$A'M = \dfrac{1}{3}AA' = \dfrac{1}{3}h$.</li><li>$B'N = \dfrac{2}{3}BB' = \dfrac{2}{3}h$.</li><li>$C'P = \dfrac{1}{2}CC' = \dfrac{1}{2}h$.</li></ul>
	}{
	\begin{tikzpicture}[line join=round,line cap=round,>=stealth,scale=0.7,font=\footnotesize]
		\tikzset{every node/.style={outer sep=-0.5mm}}
		\foreach \x/\y/\n in {0/0/A,4/0/D,-2/-1.5/B,2/-1.5/C} \coordinate (\n) at (\x,\y);
		\coordinate (O) at ($(A)!0.5!(C)$);
		\coordinate (A') at ($(A)+(0,5)$);
		\coordinate (B') at ($(B)+(0,5)$);
		\coordinate (C') at ($(C)+(0,5)$);
		\coordinate (D') at ($(D)+(0,5)$);
		\coordinate (O') at ($(O)+(0,5)$);
		\coordinate (M) at ($(A)!2/3!(A')$);
		\coordinate (N) at ($(B)!1/3!(B')$);
		\coordinate (P) at ($(C)!0.5!(C')$);
		\coordinate (Q) at ($(D)!5/6!(D')$);
		\draw (C')--(B')--(B)--(C)--(C')--(D')--(D)--(C) (D')--(A')--(B') (A')--(C') (B')--(D') (Q)--(P)--(N) ;
		\draw[dashed] (D)--(A)--(B)--(D) (A)--(A') (A)--(C) (O)--(O') (Q)--(M)--(N)--(Q) (M)--(P);
		\foreach \t/\g in {A/170,B/180,C/0,A'/90,C'/0,B'/130, D/0, D'/0, O/-90, O'/80,M/180,N/180,P/0,Q/0}{
		\draw[fill=black] (\t) circle (1pt) node[shift={(\g:10pt)}]{$ \t $};}
	\end{tikzpicture}
	}
	Gọi $O'$ là tâm của hình bình hành $A'B'C'D'$, ta có $O'$ là trung điểm của $A'C'$ và $B'D'$.\\
	Gọi $I$ là giao điểm của $OO'$ và mặt phẳng $(MNP)$.\\
	Xét hình thang tạo bởi các cạnh bên và mặt phẳng cắt, ta có tính chất
	\[ A'M + C'P = 2O'I \quad và \quad B'N + D'Q = 2O'I \]
	Suy ra $A'M + C'P = B'N + D'Q$.\\
	Thay số vào đẳng thức trên
	\[ \dfrac{1}{3}h + \dfrac{1}{2}h = \dfrac{2}{3}h + D'Q \Leftrightarrow \dfrac{5}{6}h = \dfrac{4}{6}h + D'Q \Leftrightarrow D'Q = \dfrac{1}{6}h = \dfrac{1}{6}DD'. \]
	Vậy tỉ số cần tìm là $\dfrac{DD'}{D'Q} = 1:\dfrac{1}{6} = 6$.

questions.rawBody:
 %Câu 5 %[1H4V5-3]
	Cho hình hộp $ABCD.A'B'C'D'$. Trên các cạnh $AA'$, $BB'$, $CC'$ lần lượt lấy ba điểm $M$, $N$, $P$ sao cho $\dfrac{A'M}{AA'} = \dfrac{1}{3}$;$\dfrac{B'N}{BB'} = \dfrac{2}{3}$; $\dfrac{C'P}{CC'} = \dfrac{1}{2}$. Biết mặt phẳng $(MNP)$ cắt $DD'$ tại $Q$. Tính tỉ số $\dfrac{DD'}{D'Q}$.
	\par
	\shortans[oly]{6}
\loigiai{
	\immini{
	Gọi $h$ là độ dài cạnh bên của hình hộp ($h = AA'=BB'=CC'=DD'$).\\
	Theo giả thiết ta có độ dài các đoạn thẳng tính từ đỉnh phía trên ($A'$, $B'$, $C'$, $D'$) xuống mặt phẳng $(MNP)$ là
	\begin{itemize}
		\item $A'M = \dfrac{1}{3}AA' = \dfrac{1}{3}h$.
		\item $B'N = \dfrac{2}{3}BB' = \dfrac{2}{3}h$.
		\item $C'P = \dfrac{1}{2}CC' = \dfrac{1}{2}h$.
	\end{itemize}
	}{
	\begin{tikzpicture}[line join=round,line cap=round,>=stealth,scale=0.7,font=\footnotesize]
		\tikzset{every node/.style={outer sep=-0.5mm}}
		\foreach \x/\y/\n in {0/0/A,4/0/D,-2/-1.5/B,2/-1.5/C} \coordinate (\n) at (\x,\y);
		\coordinate (O) at ($(A)!0.5!(C)$);
		\coordinate (A') at ($(A)+(0,5)$);
		\coordinate (B') at ($(B)+(0,5)$);
		\coordinate (C') at ($(C)+(0,5)$);
		\coordinate (D') at ($(D)+(0,5)$);
		\coordinate (O') at ($(O)+(0,5)$);
		\coordinate (M) at ($(A)!2/3!(A')$);
		\coordinate (N) at ($(B)!1/3!(B')$);
		\coordinate (P) at ($(C)!0.5!(C')$);
		\coordinate (Q) at ($(D)!5/6!(D')$);
		\draw (C')--(B')--(B)--(C)--(C')--(D')--(D)--(C) (D')--(A')--(B') (A')--(C') (B')--(D') (Q)--(P)--(N) ;
		\draw[dashed] (D)--(A)--(B)--(D) (A)--(A') (A)--(C) (O)--(O') (Q)--(M)--(N)--(Q) (M)--(P);
		\foreach \t/\g in {A/170,B/180,C/0,A'/90,C'/0,B'/130, D/0, D'/0, O/-90, O'/80,M/180,N/180,P/0,Q/0}{
		\draw[fill=black] (\t) circle (1pt) node[shift={(\g:10pt)}]{$ \t $};}
	\end{tikzpicture}
	}
	Gọi $O'$ là tâm của hình bình hành $A'B'C'D'$, ta có $O'$ là trung điểm của $A'C'$ và $B'D'$.\\
	Gọi $I$ là giao điểm của $OO'$ và mặt phẳng $(MNP)$.\\
	Xét hình thang tạo bởi các cạnh bên và mặt phẳng cắt, ta có tính chất
	\[ A'M + C'P = 2O'I \quad \text{và} \quad B'N + D'Q = 2O'I \]
	Suy ra $A'M + C'P = B'N + D'Q$.\\
	Thay số vào đẳng thức trên
	\[ \dfrac{1}{3}h + \dfrac{1}{2}h = \dfrac{2}{3}h + D'Q \Leftrightarrow \dfrac{5}{6}h = \dfrac{4}{6}h + D'Q \Leftrightarrow D'Q = \dfrac{1}{6}h = \dfrac{1}{6}DD'. \]
	Vậy tỉ số cần tìm là $\dfrac{DD'}{D'Q} = 1:\dfrac{1}{6} = 6$.
	}

%[1H4H1-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Vuong]
	Cho hình chóp $S. ABCD$, đáy $ABCD$ là tứ giác có các cặp cạnh đối không song song, điểm $M$ thuộc cạnh $SA$. Tìm giao tuyến của các cặp mặt phẳng sau
	\begin{enumEX}{2}
		\item $(SAC)$ và $(SBD)$;
		\item $(SAC)$ và $(MBD)$;
		\item $(MBC)$ và $(SAD)$;
		\item $(SAB)$ và $(SCD)$.
	\end{enumEX}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=0.8, font=\footnotesize, line join=round, line cap=round, >=stealth]
			\path 	(0,0) coordinate (A)
			(2,-1.5) coordinate (B)
			(4,-1) coordinate (C)
			(5,0) coordinate (D)
			(3,5) coordinate (S)
			(intersection of A--C and B--D) coordinate (O)
			($(A)!0.6!(S)$) coordinate (M)
			(intersection of A--D and B--C) coordinate (F)
			(intersection of S--D and M--F) coordinate (N)
			(intersection of A--B and C--D) coordinate (E);
			\draw	(S)--(A)--(E)--cycle (M)--(B)--(S)--(N)--(F) (E)--(C)--(F) (N)--(C) ;
			\draw[dashed] 	(A)--(C) (B)--(D) (C)--(D)
			(S)--(O) (A)--(F) (D)--(N) (M)--(C)--(B) (M)--(N);
			\foreach \x/\g in {S/90,A/180,B/200,C/-45,D/45,E/-90,F/0,M/135,O/130}
			\fill[black] 	(\x) circle (1pt)
			($(\g:3mm)+(\x)$) node {$\x$};
		\end{tikzpicture}
	\end{center}
	\begin{enumEX}{1}
		\item
		Trong mặt phẳng $(ABCD)$, gọi $O$ là giao điểm của $AC$ và $BD$.\\
		Ta có $\heva{&O \in AC \subset (SAC)\\&O \in BD \subset (SBD)} \Rightarrow O \in (SAC) \cap (SBD)$.\\
		Mà $S \in (SAC) \cap (SBD)$.\\
		Vậy $SO$ là giao tuyến của hai mặt phẳng $(SAC)$ và $(SBD)$.
		\item
		Ta có $\heva{&O \in AC \subset (SAC)\\&O \in BD \subset (MBD)} \Rightarrow O \in (SAC) \cap (MBD)$.\\
		Tương tự, ta có $M \in (SAC) \cap (MBD)$.\\
		Vậy $OM$ là giao tuyến của hai mặt phẳng $(SAC)$ và $(MBD)$.
		\item
		Trong mặt phẳng $(ABCD)$, gọi $F = BC \cap AD$.\\
		Ta có $\heva{&F \in BC \subset (MBC)\\&F \in AD \subset (SAD)} \Rightarrow F \in (MBC) \cap (SAD)$.\\
		Tương tự, ta có $M \in (MBC) \cap (SAD)$.\\
		Vậy $FM$ là giao tuyến của hai mặt phẳng $(MBC)$ và $(SAD)$.
		\item
		Trong mặt phẳng $(ABCD)$, gọi $E = AB \cap CD$.\\
		Ta có $\heva{&E \in AB \subset (SAB)\\&E \in CD \subset (SCD)} \Rightarrow E \in (SAB) \cap (SCD)$.\\
		Mặt khác, $S \in (SAB) \cap (SCD)$.\\ Vậy $SE$ là giao tuyến của hai mặt phẳng $(SAB)$ và $(SCD)$.
