questions.rawBody:
%[1H4N2-4]
	Cho lăng trụ $ABCD.A'B'C'D'$ có hai đáy là các hình bình hành. Các điểm $M$, $N$, $P$ lần lượt là trung điểm của cạnh $AD$, $BC$, $CC'$ (tham khảo hình vẽ). Xét các khẳng định sau:
	\begin{center}
		\begin{tikzpicture}[scale=0.8,font=\footnotesize,line join=round,line cap=round,>=stealth]
			\coordinate (A) at (0,0);
			\coordinate (B) at (-2,-2);
			\coordinate (D) at (6,0);
			\coordinate (C) at ($(B)+(D)-(A)$);
			\foreach \i in {A,B,C,D}{\coordinate (\i') at ($(\i)+(0,5)$);}
			\coordinate (M) at ($(A)!0.5!(D)$);
			\coordinate (N) at ($(B)!0.5!(C)$);
			\coordinate (P) at ($(C')!0.5!(C)$);
			\draw (B)--(C)--(D);
			\draw (B)--(B')
			(C)--(C')
			(D)--(D')
			(A')--(D')--(C')--(B')--(A')
			(N)--(P);
			\draw[dashed,thin] (A')--(A)--(B)
			(A)--(D)
			(P)--(M)--(N);
			\foreach \i/\g in {A'/170,B'/170,C'/-10,D'/0,A/30,B/140,C/-20,D/10,M/150,N/120,P/10}{\draw[fill=blue](\i) circle (1pt)
			($(\i)+(\g:5mm)$) node[scale=1]{$\i$};}
		\end{tikzpicture}
	\end{center}
	\begin{enumerate}
		\item Mặt phẳng $\left(MNP\right)$ cắt cạnh $A'D'$.
		\item Mặt phẳng $\left(MNP\right)$ cắt cạnh $DD'$ tại trung điểm của $DD'$.
		\item Mặt phẳng $\left(MNP\right)$ song song với mặt phẳng $\left(ABC'D'\right)$.
	\end{enumerate}
	Trong các khẳng định trên, số khẳng định đúng là
	\choice
	{$4$}
	{$3$}
	{\True$2$}
	{$1$}
\loigiai{
	\begin{itemize}
		\item Lấy $E$ là trung điểm $D D^{\prime} \Rightarrow E P \parallel C D \parallel M N$ suy ra $(MNP)\equiv (MNPE)$.
		Do đó $(MNP)\cap DD^{\prime}=E$ với $E$ là trung điểm $D D^{\prime}$ nên b) đúng.
		\item Trong $\left(ADD^{\prime}A^{\prime}\right)$ có $ME$ cắt tia $A^{\prime}D^{\prime}$ tại $F$ suy ra $(MNPE)\cap A^{\prime}D^{\prime}=\{F\}$.
		Ta có $AMFD^{\prime}$ là hình bình hành (do $MF \parallel AD^{\prime};\; AM \parallel D^{\prime}F$) nên
		\[
		AM = D^{\prime}F = \dfrac{1}{2}A^{\prime}D^{\prime} \;\Rightarrow\; A^{\prime}F = \dfrac{3}{2}A^{\prime}D.
		\]
		Nên $F$ không thuộc cạnh $A^{\prime}D^{\prime}$, do đó a) sai.
		\item Ta có $ME \parallel AD^{\prime}$ (do $ME$ là đường trung bình của $\triangle DAD^{\prime}$) và $MN \parallel AB$ nên $(MNP)\parallel (ABC^{\prime}D^{\prime})$, do đó c) đúng.
	\end{itemize}
	}

%[1H4H2-1]
	Khẳng định nào sau đây là \textbf{sai}?
	\choice
	{\True Qua ba điểm phân biệt xác định duy nhất một mặt phẳng}
	{Qua một đường thẳng và một điểm không thuộc đường thẳng xác định duy nhất một mặt phẳng}
	{Qua hai đường thẳng song song xác định duy nhất một mặt phẳng}
	{Qua hai đường thẳng cắt nhau xác định duy nhất một mặt phẳng}
\loigiai{
	Khẳng định sai là: \lq\lq Qua ba điểm phân biệt xác định duy nhất một mặt phẳng\rq\rq. Vì ba điểm thẳng hàng thì có vô số mặt phẳng chứa ba điểm đó.
	}

%[1H4N2-1]
	Chọn mệnh đề đúng trong các mệnh đề sau.
	\choice
	{Hai đường thẳng không có điểm chung thì chéo nhau}
	{Hai đường thẳng phân biệt không có điểm chung thì chéo nhau}
	{\True Hai đường thẳng chéo nhau thì không có điểm chung}
	{Hai đường thẳng lần lượt nằm trên hai mặt phẳng phân biệt thì chéo nhau}
\loigiai{
	- Hai đường thẳng chéo nhau thì không có điểm chung là \textbf{đúng}.
	- Hai đường thẳng không có điểm chung thì chéo nhau \textbf{hoặc song song nhau}.
	- Hai đường thẳng lần lượt nằm trên hai mặt phẳng phân biệt thì chéo nhau hoặc song song nhau cũng có thể cắt nhau.
	}

