			($(C)!.5!(D)$) coordinate (P)
			($(C)!.5!(B)$) coordinate (Q);
			\draw[dashed] (B)--(D)
			(M)--(N)
			(P)--(Q);
			\draw (A)--(C)
			(A)--(B)--(C)--(D)--cycle (M)--(Q)
			(N)--(P);
			\foreach \x/\goc in {D/0,A/90,C/-60,B/180,M/180,N/20,P/0,Q/180}
			\draw[fill=white] (\x) node[shift={(\goc:7pt)},font=\scriptsize]{$\x$} circle (1pt);
