questions.rawBody:
%[1H4H2-2]
	Cho hình chóp $S.ABCD$ có đáy là hình bình hành. Khi đó
	\choiceTF
	{\True $AB$ song song $CD$}
	{\True $SA$ cắt $SC$}
	{$SA$ song song $BC$}
	{\True $SC$ chéo nhau $AB$}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=1,font=\footnotesize,line join=round,line cap=round,>=stealth]
			\def\canhAD{4}; \def\canhBA{2}; \def\gocBAD{-140}; \def\h{3}; \def\xdinhS{1};
			\coordinate (A) at (0,0);
			\coordinate (B) at ($(A)+(\gocBAD:\canhBA)$);
			\coordinate (C) at ($(B)+(0:\canhAD)$);
			\coordinate (D) at ($(A)+(0:\canhAD)$);
			\coordinate (S) at ($(A)+(\xdinhS,\h)$);
			\draw (B)--(S)--(C)--cycle (S)--(D)--(C);
			\draw[dashed] (A)--(D)
			(S)--(A)--(B);
			\foreach \x/\y in {A/180,B/-90,C/-90,D/0,S/90}{\fill (\x) circle (1pt)
			($(\x)+(\y:0.3cm)$) node{$\x$};}
		\end{tikzpicture}
	\end{center}
	\begin{itemchoice}
		\itemch {\bf Đúng}.\\
		Ta có $AB$ và $CD$ cùng nằm trong một mặt phẳng và không có điểm chung nên $AB$ song song với $CD$ (hai cạnh đối của hình bình hành thì song song với nhau).
		\itemch {\bf Đúng}.\\
		Hai đường thẳng $SA$ và $SC$ cắt nhau tại $S$.
		\itemch {\bf Sai}.\\
		Hai đường thẳng $SA$ và $BC$ không đồng phẳng, vì vậy $SA$ và $BC$ là hai đường thẳng chéo nhau.
		\itemch {\bf Đúng}.\\
		$SC$ chéo nhau $AB$.
	\end{itemchoice}
	}

%[1H4H2-3]
	Cho hình chóp $S.ABCD$ có đáy $ABCD$ là hình thang, $AD\parallel BC$ và $AD=2BC$. Gọi $O$ là giao điểm của $AC$ và $BD$, $E$ là điểm trên cạnh $AD$ sao cho $ED=2EA$ và $N$ là điểm trên cạnh $SD$ sao cho $ND=2NS$. Khi đó
	\choiceTF
	{\True $BC\parallel (SAD)$}
	{Giao tuyến của hai mặt phẳng $(SBC)$ và $(SAD)$ đường thẳng qua $S$ và song song với $AB$}
	{\True Hai mặt phẳng $(OEN)$ và $(SAB)$ song song với nhau}
	{Gọi $F$ là giao điểm của đường thẳng $SC$ và mặt phẳng $(OEN)$. Tỉ số $\dfrac{SF}{SC}=\dfrac{1}{2}$}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=1,font=\footnotesize,line join=round,line cap=round,>=stealth]
			\def\h{3}
			\path (0,0) coordinate (A)
			(-1.2,-1.4) coordinate (B) ++(0:4) coordinate (C)
			($(A)+2*(C)-2*(B)$) coordinate (D)
			($(A)!1/3!(D)$) coordinate (E)
			(intersection cs: first line = {(A)--(C)},second line = {(B)--(D)}) coordinate (O)
			(0.5,\h) coordinate (S)
			($(S)!1/3!(D)$) coordinate (N)
			($(C)!1/3!(B)$) coordinate (M)
			($(C)!1/3!(S)$) coordinate (F);
			\draw (S)--(B)--(C)--(D)--(S)--(C)
			(N)--(F)--(M);
			\draw[dashed] (O)--(S)--(A)--(B)--(D)--(A)--(C)
			(O)--(E)--(N)--cycle (O)--(M);
			\draw ($(S)+(0:6)$) coordinate (S1) node[above left]{$x$}--($(S)+(180:6/3)$) coordinate (S2);
			\foreach \i/\j in {S/90,A/170,B/-90,C/-90,D/0,O/-90,E/40,N/70,F/80,M/-90} \fill (\i) node[shift={(\j:0.3)}]{$\i$} circle (1pt);
		\end{tikzpicture}
	\end{center}
	\begin{itemchoice}
		\itemch \textbf{Đúng}.\\ Ta có $BC\not\subset (SAD)$, $BC\parallel AD$, $AD\subset (SAD)$ nên $BC\parallel (SAD)$.
		\itemch \textbf{Sai}.\\ Ta có $\heva{&S \in(SBC) \cap(SAD) \\& BC \subset(SBC); AD \subset(SAD)\\& BC \parallel AD}\Rightarrow Sx=(SAB) \cap(SCD)$, $Sx \parallel BC \parallel AD$.
		\itemch \textbf{Đúng}.\\ Trong mặt phẳng $(ABCD)$, gọi $\{M\}=EO\cap BC$. Ta có $\triangle AOD\backsim\triangle COB$ (g.g), do đó
		\[\dfrac{AO}{CO}=\dfrac{AD}{BC}=2 \Rightarrow \dfrac{CO}{CA}=\dfrac{1}{3}.\]
		Lại có $\triangle AEO\backsim\triangle CMO$, $AE=\dfrac{1}{3}AD=\dfrac{2}{3}BC$ nên $\dfrac{CM}{AE}=\dfrac{CO}{AO}=\dfrac{1}{2} \Rightarrow \dfrac{CM}{BC}=\dfrac{1}{3}$.\\
		Xét $\triangle ABC$, ta có $\dfrac{CO}{CA} =\dfrac{CM}{CB} = \dfrac{1}{3}$ nên $OM\parallel AB$ hay $OE\parallel AB \Rightarrow OE\parallel (SAB)$. \hfill $(1)$\\
		Xét $\triangle SAD$, từ giả thiết suy ra $\dfrac{DE}{DA} =\dfrac{DN}{DS} = \dfrac{2}{3}$ nên $EN\parallel AS \Rightarrow EN\parallel (SAB)$. \hfill $(2)$\\
		Từ $(1)$ và $(2)$ suy ra $(OEN)\parallel (SAB)$.
		\itemch \textbf{Sai}.
		Ta có $\{F\}=SC\cap (OEN)$, $\{M\}=BC\cap (OEN)$ nên $MF$ là giao tuyến của hai mặt phẳng $(OEN)$ và $(SBC)$.\\
		Lại có $SB$ là giao tuyến của $(SAB)$ và $(SBC)$, $(OEN)\parallel (SAB)$ nên $MF\parallel BS$.\\
		Trong tam giác $SBC$, có $M\in BC$, $F\in SC$ và $MF\parallel BS$ nên theo định lý Ta-lét ta có
		\[\dfrac{SF}{SC}=\dfrac{BM}{BC} = \dfrac{BC-MC}{BC}=1-\dfrac{1}{3}=\dfrac{2}{3}.\]
		Vậy $F$ là điểm nằm trên đoạn $SC$ sao cho $\dfrac{SF}{SC}=\dfrac{2}{3}$.
	\end{itemchoice}
	}

