%[1H4H2-3]
	Cho hình chóp $S. ABCD$ đáy $ABCD$ là hình bình hành tâm $H$. Mặt phẳng $(P)$ đi qua $H$ và song song với $(SAB)$. Tìm giao tuyến của
	\begin{enumerate}
		\item Mặt phẳng $(P)$ và mặt phẳng $(ABCD)$.
		\item Mặt phẳng $(P)$ và mặt phẳng $(SBC)$.
	\end{enumerate}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[line join = round,line cap = round,>=stealth,font=\footnotesize,scale=1,declare function={ab=2.5; ad=4.5; gs=80; sa=3; gocA=-130;}]
			\path
			(0,0) coordinate (A)
			(ad,0) coordinate (D)
			(gocA:ab) coordinate (B)
			($(D)-(A)+(B)$) coordinate (C)
			(gs:sa) coordinate (S)
			(intersection of A--C and B--D) coordinate (H)
			($(B)!0.5!(C)$) coordinate (E)
			($(S)!0.5!(C)$) coordinate (K)
			($(A)!0.5!(D)$) coordinate (F);
			\draw (S)--(B)--(C)--(D)--(S)--(C)
			(K)--(E);
			\draw[dashed] (S)--(A)--(D)
			(B)--(A)
			(A)--(C)
			(B)--(D)
			(E)--(F);
			\foreach \x/\gm in {A/150,B/180,C/-20,D/0,S/90,K/70,E/-90,F/50,H/-90} \fill (\x) circle (1pt)
			($(\x)+(\gm:3.5mm)$) node{$\x$};
		\end{tikzpicture}
	\end{center}
	\begin{enumerate}
		\item Giao tuyến của mặt phẳng $(P)$ và mặt phẳng $(ABCD)$.\\
		Ta có $\heva{& (P) \parallel(SAB) \\ & \left(ABCD\right)\cap\left(SAB\right)=AB \\ & (P)\cap (ABCD)=H}\Rightarrow (P)\cap(ABCD)=EF$ với $\heva{& EF \text{qua } H \\ & EF\parallel AB \\ & E\in BC, F\in AD.}$
		\item Giao tuyến của mặt phẳng $(P)$ và mặt phẳng $(SBC)$.
	\end{enumerate}
	Ta có $\heva{& (P)\parallel(SAB) \\ & (SBC)\cap (SAB)=SB \\ & (P)\cap (SBC)=E}\Rightarrow (P)\cap (ABCD)=EK$ với $\heva{& EK\cap SC=K \\ & EK\parallel SB.}$
	}

%[1H4V2-2]
	Cho tứ diện $ABCD$ có $AB$ vuông góc với $CD$, $M$ là một điểm thuộc cạnh $BC$ (không trùng với $B$ và $C$). Mặt phẳng $(\alpha)$ qua $M$ song song với $AB$ và $CD$ lần lượt cắt $BD$, $AD$, $AC$ tại $N$, $P$, $Q$. Tứ giác $MNPQ$ là hình gì?
\loigiai{
	\immini[thm]{Ta có \\
	$\heva{&(\alpha)\parallel AB, AB\subset (ABC)\\&(\alpha)\cap(ABC)=MQ}\Rightarrow MQ\parallel AB$.\\
