		\coordinate (J) at ($(A)!0.6667!(D)$);
		\draw[dashed] (M) -- (I);
		\draw (B) -- (C);
		\coordinate (E) at (intersection cs: first line={(M)--(I)},second line={(B)--(C)});
		\filldraw (E) circle (0.1pt) node[font=\small,right] {E};
		\draw (E) -- (I);
		\draw (E) -- (C);
		\coordinate (F) at (intersection cs: first line={(B)--(D)},second line={(M)--(J)});
		\filldraw (F) circle (0.1pt) node[font=\small,right] {F};
		\draw (F) -- (J);
		\draw (F) -- (D);
		\draw (M) -- (I);
		\draw (I) -- (J);
		\draw (J) -- (M);
		\fill[pattern=north east lines,opacity=0.5] (M)--(I)--(J)--cycle;
		\draw[dashed] (M) -- (E);
		\coordinate (G) at (intersection cs: first line={(C)--(D)},second line={(M)--(E)});
		\draw[dashed] (G) -- (C);
		\draw (G) -- (D);
		\foreach \point/\pos in {A/above,B/below left,C/below right,D/above right,M/left,I/left,J/above}
		\filldraw (\point) circle (0.3pt) node[font=\small,\pos] {\point};
	\end{tikzpicture}
	<ol class="kntt-list" type="a"><li>Xét mặt phẳng $(MEF)$ cắt tứ diện đều $ABCD$. Ta xác định các giao tuyến của mặt phẳng này với các mặt bên của tứ diện như sau:
		<ul class="kntt-list"><li><strong>Trên mặt $(ABC)$:</strong> Giao tuyến của mặt phẳng $(MEF)$ với $(ABC)$ là đường thẳng $MI$, trong đó $I$ là giao điểm của $ME$ với $AC$.</li><li><strong>Trên mặt $(ABD)$:</strong> Giao tuyến của mặt phẳng $(MEF)$ với $(ABD)$ là đường thẳng $MJ$, trong đó $J$ là giao điểm của $MF$ với $AD$.</li><li><strong>Trên mặt $(ACD)$:</strong> Giao tuyến của mặt phẳng $(MEF)$ với $(ACD)$ là đường thẳng $IJ$, nối hai điểm $I$ và $J$ vừa xác định ở trên.</li></ul>
		Vậy thiết diện của tứ diện đều $ABCD$ với mặt phẳng $(MEF)$ là tam giác $MIJ$.</li><li>Theo cách dựng, điểm $I$ là giao điểm của hai trung tuyến tam giác $ABE$:
		<ul class="kntt-list"><li>Trung tuyến thứ nhất đi từ $A$ đến trung điểm $BE$ (với $B$ là đỉnh, $E$ là điểm kéo dài $BC$ đoạn $a$).</li><li>Trung tuyến thứ hai đi từ $M$ (trung điểm $AB$) đến đỉnh $E$. Giao điểm của hai trung tuyến này chính là trọng tâm tam giác $ABE$. Tương tự, $J$ là trọng tâm tam giác $ABF$.</li></ul>
		Vì $ABCD$ là tứ diện đều cạnh $a$, nên $AC=AD=a$. Theo tính chất chia đoạn của trọng tâm, ta có
		\[AI=\dfrac{2}{3} AC=\dfrac{2a}{3}, \qquad AJ=\dfrac{2}{3} AD=\dfrac{2a}{3}.\]
		Do các đoạn $AI$, $AJ$ có độ dài bằng nhau, tam giác $AIJ$ là tam giác đều cạnh $\dfrac{2a}{3}$ nên $IJ=\dfrac{2a}{3}$.\\
		Xét tam giác $AMI$ có $AM=\dfrac{a}{2}$, $AI=\dfrac{2a}{3}$ và góc giữa $AM$ và $AI$ là $60^{\circ}$ (vì tứ diện đều):
		\[MI=\sqrt{AM^2+AI^2-2 \cdot AM\cdot AI\cdot \cos 60^{\circ}}=\sqrt{\left(\dfrac{a}{2}\right)^2+\left(\dfrac{2a}{3}\right)^2-2 \cdot \dfrac{a}{2} \cdot \dfrac{2a}{3} \cdot \dfrac{1}{2}}=\dfrac{a\sqrt{13}}{6}.\]
		Tính chiều cao từ $M$ tới cạnh $IJ$:
		\[h=\sqrt{MI^2-\left(\dfrac{IJ}{2}\right)^2}=\sqrt{\left(\dfrac{a\sqrt{13}}{6}\right)^2-\left(\dfrac{a}{3}\right)^2}=\dfrac{a}{2}\]
		Do đó, diện tích tam giác $MIJ$ là
		\[S_{\triangle MIJ}=\dfrac{1}{2} \cdot IJ\cdot h=\dfrac{1}{2} \cdot \dfrac{2a}{3} \cdot \dfrac{a}{2}=\dfrac{a^2}{6}.\]</li></ol>

questions.rawBody:
%[1H4V2-5]
	Cho tứ diện đều $ABCD$, cạnh bằng $a$. Kéo dài $BC$ một đoạn $CE=a$. Kéo dài $BD$ một đoạn $DF=a$. Gọi $M$ là trung điểm của $A B$.
	\begin{enumerate}[a)]
		\item Tìm thiết diện của tứ diện với mặt phẳng $(MEF)$.
		\item Tính diện tích của thiết diện.
	\end{enumerate}
\loigiai{\begin{center}
	\begin{tikzpicture}[scale=3,font=\footnotesize,line join=round,line cap=round,>=stealth]
		\coordinate (B) at (-1,0);
		\coordinate (D) at (1,0);
		\coordinate (C) at (-0.5,-1);
		\coordinate (A) at (0.5,1,0.6);
		\draw (B) -- (C);
		\draw[dashed] (D) -- (B);
		\draw (A) -- (B);
		\draw (A) -- (C);
		\draw (A) -- (D);
		\coordinate (M) at ($(A)!0.5!(B)$);
		\coordinate (I) at ($(A)!0.6667!(C)$);
		\coordinate (J) at ($(A)!0.6667!(D)$);
		\draw[dashed] (M) -- (I);
		\draw (B) -- (C);
		\coordinate (E) at (intersection cs: first line={(M)--(I)},second line={(B)--(C)});
		\filldraw (E) circle (0.1pt) node[font=\small,right] {E};
		\draw (E) -- (I);
		\draw (E) -- (C);
		\coordinate (F) at (intersection cs: first line={(B)--(D)},second line={(M)--(J)});
		\filldraw (F) circle (0.1pt) node[font=\small,right] {F};
		\draw (F) -- (J);
		\draw (F) -- (D);
		\draw (M) -- (I);
		\draw (I) -- (J);
		\draw (J) -- (M);
		\fill[pattern=north east lines,opacity=0.5] (M)--(I)--(J)--cycle;
		\draw[dashed] (M) -- (E);
		\coordinate (G) at (intersection cs: first line={(C)--(D)},second line={(M)--(E)});
		\draw[dashed] (G) -- (C);
		\draw (G) -- (D);
		\foreach \point/\pos in {A/above,B/below left,C/below right,D/above right,M/left,I/left,J/above}
		\filldraw (\point) circle (0.3pt) node[font=\small,\pos] {\point};
	\end{tikzpicture}
	\end{center}
	\begin{enumerate}[a)]
		\item Xét mặt phẳng $(MEF)$ cắt tứ diện đều $ABCD$. Ta xác định các giao tuyến của mặt phẳng này với các mặt bên của tứ diện như sau:
		\begin{itemize}
			\item \textbf{Trên mặt $(ABC)$:} Giao tuyến của mặt phẳng $(MEF)$ với $(ABC)$ là đường thẳng $MI$, trong đó $I$ là giao điểm của $ME$ với $AC$.
			\item \textbf{Trên mặt $(ABD)$:} Giao tuyến của mặt phẳng $(MEF)$ với $(ABD)$ là đường thẳng $MJ$, trong đó $J$ là giao điểm của $MF$ với $AD$.
			\item \textbf{Trên mặt $(ACD)$:} Giao tuyến của mặt phẳng $(MEF)$ với $(ACD)$ là đường thẳng $IJ$, nối hai điểm $I$ và $J$ vừa xác định ở trên.
		\end{itemize}
		Vậy thiết diện của tứ diện đều $ABCD$ với mặt phẳng $(MEF)$ là tam giác $MIJ$.
		\item Theo cách dựng, điểm $I$ là giao điểm của hai trung tuyến tam giác $ABE$:
		\begin{itemize}
			\item Trung tuyến thứ nhất đi từ $A$ đến trung điểm $BE$ (với $B$ là đỉnh, $E$ là điểm kéo dài $BC$ đoạn $a$).
			\item Trung tuyến thứ hai đi từ $M$ (trung điểm $AB$) đến đỉnh $E$. Giao điểm của hai trung tuyến này chính là trọng tâm tam giác $ABE$. Tương tự, $J$ là trọng tâm tam giác $ABF$.
		\end{itemize}
		Vì $ABCD$ là tứ diện đều cạnh $a$, nên $AC=AD=a$. Theo tính chất chia đoạn của trọng tâm, ta có
		\[AI=\dfrac{2}{3} AC=\dfrac{2a}{3}, \qquad AJ=\dfrac{2}{3} AD=\dfrac{2a}{3}.\]
		Do các đoạn $AI$, $AJ$ có độ dài bằng nhau, tam giác $AIJ$ là tam giác đều cạnh $\dfrac{2a}{3}$ nên $IJ=\dfrac{2a}{3}$.\\
		Xét tam giác $AMI$ có $AM=\dfrac{a}{2}$, $AI=\dfrac{2a}{3}$ và góc giữa $AM$ và $AI$ là $60^{\circ}$ (vì tứ diện đều):
		\[MI=\sqrt{AM^2+AI^2-2 \cdot AM\cdot AI\cdot \cos 60^{\circ}}=\sqrt{\left(\dfrac{a}{2}\right)^2+\left(\dfrac{2a}{3}\right)^2-2 \cdot \dfrac{a}{2} \cdot \dfrac{2a}{3} \cdot \dfrac{1}{2}}=\dfrac{a\sqrt{13}}{6}.\]
		Tính chiều cao từ $M$ tới cạnh $IJ$:
		\[h=\sqrt{MI^2-\left(\dfrac{IJ}{2}\right)^2}=\sqrt{\left(\dfrac{a\sqrt{13}}{6}\right)^2-\left(\dfrac{a}{3}\right)^2}=\dfrac{a}{2}\]
		Do đó, diện tích tam giác $MIJ$ là
		\[S_{\triangle MIJ}=\dfrac{1}{2} \cdot IJ\cdot h=\dfrac{1}{2} \cdot \dfrac{2a}{3} \cdot \dfrac{a}{2}=\dfrac{a^2}{6}.\]
	\end{enumerate}
	}

