		(3.76,1.23) -- (4.44,1.23) -- (4.44,-0.48) -- (3.76,-0.48) -- cycle
		(0.38,1.38) -- (1.06,1.38) -- (1.06,-0.33) -- (0.38,-0.33) -- cycle;
		\path[fill=c7a8189] (13.32,7.39) rectangle (14.06,1.85);
		\path[fill=cabb5bc] (0,0) -- (11.92,-0.69).. controls +(-2:0.5) and +(-2:0.4).. (11.94,-1.3) --
		(-0.08,-0.6).. controls +(173:0.3) and +(178:0.4).. cycle;
		\path[fill=cabb5bc] (3.74,2.48) -- (14.79,2.03).. controls +(-4:0.4) and +(-9:0.3).. (14.79,1.37) -- (3.74,1.82) -- cycle;
		\def\vienngoai{(2.92,8.56) -- (-0.32,0.88) -- (11.79,0.19) -- (14.6,8.57) -- cycle}
		\path[fill=c0065b3,rounded corners=6pt] \vienngoai;
		\path[draw=white,line width=2pt] (13.18,8.5) -- (10.39,0.58)
		(12.19,8.51) -- (9.36,0.63)
		(11.19,8.51) -- (8.33,0.68)
		(10.2,8.52) -- (7.3,0.73)
		(9.2,8.52) -- (6.27,0.79)
		(8.21,8.53) -- (5.24,0.84)
		(7.22,8.54) -- (4.21,0.89)
		(6.22,8.54) -- (3.18,0.94)
		(5.23,8.55) -- (2.15,0.99)
		(4.24,8.55) -- (1.12,1.05)
		(4.24,8.55) -- (1.12,1.05)
		(13.18,8.5) -- (10.39,0.58)
		(1.92,6) -- (13.5,5.64)
		(0.94,3.53) -- (12.57,3.06);
		\path[even odd rule,fill=cabb5bc,rounded corners=5pt] \vienngoai
		(3.23,8.29) -- (14.12,8.29) -- (11.53,0.55) -- (0.17,1.15) -- cycle;
		\path (current bounding box.south) node[below]{\Huge Hình 1};
		\end{tikzpicture}}
		\begin{tikzpicture}[scale=0.8, font=\footnotesize, line join=round, line cap=round, >=stealth]
			\tikzset{declare function={a=6.5;b=0.35*a;goc=-130;h=0.5*a;k=0.2*h;}}
			\path (0:0) coordinate (H')
			(a,0) coordinate (G')
			(goc:b) coordinate (E')++(a,0) coordinate (F')
			\foreach \x/\y/\z in {H'/H/h,G'/G/h,E'/E/k,F'/F/k} {($(\x)+(0,\z)$) coordinate (\y)};
			\fill[cyan!60!black!40, opacity=70] (E)--(F)--(G)--(H)--cycle;
			\draw[dashed](E')--(H')--(G');
			\draw[gray,thick] (H)--(H') (E)--(E') (F)--(F') (G)--(G') (E)--(F)--(G)--(H)--cycle (E')--(F')--(G');
			\foreach \x /\gN in {H'/180,G'/0,F'/-10,E'/-90,H/180,G/-10,F/0,E/180}
			\fill (\x) circle (1pt)($(\x)+(\gN:8pt)$) node {$\x$};
			\path (current bounding box.south) node[below]{Hình 2} pic["\scriptsize$(Q)$", draw,angle radius=25pt]{angle= F'--E'--H'};
		\end{tikzpicture}
	\end{center}
	\choiceTF
	{\True Đường thẳng $EF$ song song với mặt phẳng mái nhà $(Q)$}
	{Đường thẳng $EG$ song song với mặt phẳng mái nhà $(Q)$}
	{\True Nếu người thợ điều chỉnh các chân trụ sao cho $HH'=FF'$ thì mặt phẳng chứa tấm pin $(EFGH)$ sẽ song song với $H'F'$}
	{\True Nếu mặt phẳng chứa tấm pin $(EFGH)$ cắt mặt phẳng chứa mái nhà $(Q)$ theo giao tuyến $d$, thì $d$ phải song song với đường thẳng $EF$}
\loigiai{
	\begin{itemchoice}
		\itemch Vì $\heva{&EF\not \subset (Q)\\&EF\parallel E'F'\\&E'F'\subset (Q)}\Rightarrow EF\parallel (Q)$.
		\itemch Theo hình 2 ta có tứ giác $EE'G'G$ là hình thang với $GG'\parallel EE'$ và $GG'>EE'$ nên $EG$ và $E'G'$ cắt nhau. Hay $EG$ cắt $(Q)$.
		\itemch Nếu $HH'=FF'$ thì tứ giác $HH'F'F$ là hình chữ nhật do đó $HF\parallel H'F'$. Suy ra $H'F'\parallel (EFGH)$.
		\itemch Vì $\heva{&(EFGH)\cap (Q)=d\\&EF\subset (EFGH)\\&E'F'\subset (Q)\\&EF\parallel E'F'}\Rightarrow d\parallel EF$.
	\end{itemchoice}
	}

%[1H4H3-4]%[SP-LamchuanLT-KNTT-11-full]%[Vũ Hồng Toàn]
	Cho tứ diện $ABCD$. Lấy ba điểm $P$, $Q$, $R$ lần lượt trên ba cạnh $AB$, $CD$, $BC$ sao cho $PR\parallel AC$ và $CQ=2QD$. Gọi giao điểm của đường thẳng $AD$ và mặt phẳng $(PQR)$ là $S$. Tính tỉ số $\dfrac{AD}{DS}$.
	\shortans{3}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=0.5, font=\footnotesize, line join=round, line cap=round, >=stealth]
			\def\r{5}
			\path
			(0,0) coordinate (B)
			++ (0: 2*\r) coordinate (D)
			($(B) + (-40:\r)$) coordinate (C)
			($(B) + (70:1.5*\r)$) coordinate (A)
			($(B)!3/5!(C)$) coordinate (R)
			($(B)!3/5!(A)$) coordinate (P)
			($(C)!2/3!(D)$) coordinate (Q)
			($(A)!2/3!(D)$) coordinate (S)
			($(Q)!2!(S)$) coordinate (x)
			($(S)!1.3!(Q)$) coordinate (y)
			;
			\draw (A) -- (B) -- (C) -- (D) -- (A) (A) -- (C)
			(P) -- (R) (x) -- (y);
			\draw[dashed] (B) -- (D) (R) -- (Q) -- (P);
			\foreach \i/\g in {A/90, B/180, D/0 , C/-90, R/-135, Q/-30, P/135, S/45}
			\fill (\i) circle(1pt)+(\g:4mm)node{$\i$};
			\draw (x) node[right]{$d$};
		\end{tikzpicture}
	\end{center}
	Do $Q\in CD$, $CD\subset (ACD)$ nên $Q\in (ACD)$. \\
	Ta có $\heva{&Q\in (PQR)\cap (ACD)\\&PR\parallel AC\\&PR\subset (PQR)\\&AC\subset (ACD).}$ \\
	Suy ra $(PQR)\cap (ACD)=d$ với $d$ là đường thẳng đi qua $Q$ và $d\parallel PR\parallel AC$. \\
	Gọi $S$ là giao điểm của $d$ và $AD$. Khi đó $S$ là giao điểm của $AD$ và $(PQR)$. \\
	Xét tam giác $ACD$, ta có $QS\parallel AC$ suy ra $\dfrac{AD}{DS}=\dfrac{CD}{DQ}=3$.
	}

%[1H4H3-5]%[SP-LamchuanLT-KNTT-11-full]%[Vũ Hồng Toàn]
	Cho hình chóp tứ giác $S.ABCD$ có đáy là hình vuông cạnh bằng $20$\,cm. Gọi $M$ là điểm trên cạnh $SC$ sao cho $CM=3MS$. Mặt phẳng ($\alpha$) đi qua $M$ song song với $BC$ và $CD$ cắt hình chóp theo một tứ giác có diện tích là bao nhiêu  {\it(đơn vị tính cm$^2$)}?
	\par\shortans[oly]{25}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=1, font=\footnotesize, line join=round, line cap=round, >=stealth]
			\path (0,0) coordinate (A)	(-1,-1) coordinate (B)	(4,0) coordinate (D)	($(B)+(D)-(A)$) coordinate (C)	(A)+(-0.5,3) coordinate (S)
			($(C)!3/4!(S)$) coordinate (M)
			($(B)!3/4!(S)$) coordinate (N)
			($(D)!3/4!(S)$) coordinate (Q)
			($(A)!3/4!(S)$) coordinate (P)
			;
			\draw (S)--(B)--(C)--(D)--cycle (S)--(C) (N)--(M)--(Q);
			\draw[dashed] (S)--(A) (B)--(A)--(D) (N)--(P)--(Q);
			\foreach \x/\y in {S/90,A/180,B/180,C/-20,D/20,M/-130,N/180,Q/20,P/35}
			\fill (\x) circle (1pt) node[shift={(\y:7pt)}]{$\x$};
		\end{tikzpicture}
	\end{center}
	Ta có $\heva{&(\alpha)\parallel BC,\, BC\subset (SBC)\\&M\in (\alpha)\cap (SBC).}$\\
	Suy ra $(\alpha)\cap (SBC)=MN$ với $MN\parallel BC$.\\
	Mặt khác $\heva{&(\alpha)\parallel CD,\, CD\subset (SCD)\\&M\in (\alpha)\cap (SCD).}$\\
	Suy ra $(\alpha)\cap (SCD)=MQ$ với $MQ\parallel CD$.\\
	Tương tự, $(\alpha)\cap (SAB)=NP$ với $NP\parallel AB\parallel CD$ và $(\alpha)\cap (SAD)=PQ$ với $PQ\parallel AD\parallel BC$.\\
	Suy ra $(MNPQ)\equiv (\alpha)$.\\
	Ta có $\triangle SMN\backsim \triangle SBC$ nên $\dfrac{NM}{BC}=\dfrac{SM}{SC}=\dfrac{1}{4}$.\\
	Suy ra $NM=\dfrac{1}{4}BC=5$\,cm.\\
	Vì $ABCD$ là hình vuông nên $MNPQ$ là hình vuông.\\
