%[1H4H3-3]%[SP-LamchuanLT-KNTT-11-full]%[Vũ Hồng Toàn]
	Cho hai hình bình hành $ABCD$ và $ABEF$ không cùng nằm trong $1$ mặt phẳng. Gọi $O$, $O'$ lần lượt là tâm của $ABCD$ và $ABEF$. Chứng minh $OO'$ song song với các mặt phẳng $(ADF)$ và $(BCE)$.
\loigiai{
	\begin{center}
		\begin{tikzpicture}[line join=round, line cap=round,thick]
			\coordinate (A) at (2,3);
			\coordinate (B) at (6,3);
			\coordinate (D) at (0,0);
			\coordinate (F) at (0,6);
			\coordinate (C) at ($(B)+(D)-(A)$);
			\coordinate (E) at ($(B)+(F)-(A)$);
			\coordinate (O') at ($(A)!0.5!(E)$);
			\coordinate (O) at ($(A)!0.5!(C)$);
			\draw (E)--(F)--(D)--(C)--(B)--(E)--(C);
			\draw[dashed] (E)--(A)--(B) (A)--(F)--(B) (C)--(A)--(D)--(B) (O)--(O');
			\foreach \i/\g in {A/180,B/0,C/-90,D/-90,E/90,F/90,O/-110,O'/100}{\draw[fill=black](\i) circle (1pt) ($(\i)+(\g:3mm)$) node[scale=1]{$\i$};}
		\end{tikzpicture}
	\end{center}
	Ta có $BO=\dfrac{1}{2}BD$; $BO'=\dfrac{1}{2}BF$.\\
	Suy ra $OO'\parallel DF$.\\
	Mà $DF\subset (ADF)\Rightarrow OO'\parallel (ADF)$.
	}

