			\coordinate (R) at ($(S)!0.5!(B)$);
			\coordinate (d1) at ($(S)+(B)-(A)$);
			\coordinate (d2) at ($(S)+(A)-(B)$);
			\coordinate (I) at (intersection of M--R and d1--d2);
			\coordinate (Q) at (intersection of P--I and S--C);
			\coordinate (s) at (intersection of R--I and S--C);
			\draw(S)--(A) (S)--(B) (A)--(B) (B)--(C) (R)--(Q)--(I)--(R) (S)--(s) (Q)--(C);
