%[1H4V3-3]%[SP-LamchuanLT-KNTT-11-full]%[Vũ Hồng Toàn]
	Cho hình chóp tam giác $S.ABC$. Gọi hai điểm $M$, $N$ lần lượt thuộc các cạnh $SA$, $SC$ sao cho $SM=\dfrac{2}{3} SA$, $SN=\dfrac{2}{3} SC$.
	\begin{enumerate}
		\item Chứng minh rằng đường thẳng $MN$ song song với mặt phẳng $(ABC)$.
		\item Gọi $P$ là trung điểm của cạnh $BC$. Tìm giao điểm của đường thẳng $AB$ với mặt phẳng $(MNP)$.
	\end{enumerate}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[scale=1, font=\footnotesize,line join=round, line cap=round, >=stealth]
			%hidden: TV015
			\path
			(0,0) coordinate (A)
			++(-60:2) coordinate (B)
			(4,0) coordinate (C)
			($(A)+(1,3)$) coordinate (S)
			($(S)!2/3!(A)$) coordinate (M)
			($(S)!2/3!(C)$) coordinate (N)
			($(B)!1/2!(C)$) coordinate (P)
			($(B)!1/2!(A)$) coordinate (Q)
			;
			\foreach \i in{B,C,A}{\draw (S)--(\i);};
			\draw (A)--(B)--(C) (M)--(Q)--($(Q)!-0.5!(P)$)node[above]{$\Delta$} (P)--(N);
			\draw[dashed] (A)--(C) (N)--(M)--(P) (P)--(Q);
			\foreach \i/\g in {A/180,B/-90,C/0,S/90,M/135,N/45,P/-45,Q/-135}
			\fill[] (\i) circle(1pt)+(\g:3mm)node[scale=1]{$\i$};
			\node at (0,0){\href{1S5LRQ}{\tiny \phantom{1S5LRQ}}};
		\end{tikzpicture}
	\end{center}
	\begin{enumerate}
		\item Xét tam giác $SAC$ có
		$\dfrac{SM}{SA} = \dfrac{SN}{SC} = \dfrac{2}{3}$.\\ Theo định lí Thalès đảo ta suy ra $MN \parallel AC$.\\
		Ta có
		\[ \heva{&MN\not\subset (ABC)\\&MN \parallel AC\\&AC\subset(ABC)}\Rightarrow MN\parallel (ABC).\]
		\item
		Ta có $P$ là điểm chung của hai mặt phẳng $(MNP)$ và $(ABC)$.\\
		Vì $MN \parallel AC$ và $AC \subset (ABC)$ nên giao tuyến của mặt phẳng $(MNP)$ và mặt phẳng $(ABC)$ là một đường thẳng $\Delta$ đi qua $P$ và song song với $AC$.\\
		Gọi $Q=\Delta\cap AB$ suy ra $PQ \parallel AC$.
		Vì $P$ là trung điểm của $BC$ và $PQ \parallel AC$  nên theo định lí đường trung bình trong tam giác $ABC$, $Q$ phải là trung điểm của $AB$.\\
		Do đó $Q$ là giao điểm của đường thẳng $AB$ với mặt phẳng $(MNP)$.\\
		Vậy giao điểm cần tìm là trung điểm $Q$ của đoạn thẳng $AB$.
	\end{enumerate}
	}

