	\begin{enumerate}%[label=\alph*)]
		\item Tính độ dài của thanh đà $HK$.
		\item Nếu thanh đà này được nối thêm các điểm $I$, $J$ trên $SC$ và $SD$ tạo thành một khung hình chữ nhật $HKIJ$ song song với mặt sàn, hãy tính diện tích của khung thạch cao $HKIJ$ đó.
	\end{enumerate}
