	\begin{enumerate}%[label=\alph*)]
		\item Xét $\triangle SAB$ có $SA=3SH\Rightarrow \dfrac{SH}{SA}=\dfrac{1}{3}$.\\
		Vì $HK \parallel (ABCD)$ và $HK \subset (SAB)$ nên $HK \parallel AB$.\\
		Khi đó
		\[\dfrac{SH}{SA}=\dfrac{SK}{SB}=\dfrac{HK}{AB}=\dfrac{1}{3}.\]
		Vậy $HK=\dfrac{1}{3}AB=\dfrac{1}{3}\cdot 8=\dfrac{8}{3}$\,(m).
		\item Tương tự, cạnh $KI$ của khung chữ nhật $HKIJ$ sẽ song song với $BC$ (hoặc $AD$).\\
