%[1H4V3-8]%[SP-LamchuanLT-KNTT-11-full]%[Vũ Hồng Toàn]
	Trong một công viên, người quản lý cho xây dựng một chiếc lồng chim hình chóp tứ giác $S.ABCD$ có tất cả các cạnh đều bằng $4$\,m. Để thuận tiện cho việc quan sát, phần thân dưới của lồng chim được lắp kính cường lực xung quanh ($4$ mặt bên), phần chóp phía trên được bao bởi lưới sắt. Ranh giới giữa phần lắp kính và lưới sắt là một khung inox hình tứ giác nằm trong mặt phẳng song song với mặt đáy $(ABCD)$. Biết khung inox này đi qua điểm $Q$ trên cạnh $SD$ sao cho $DQ = 1$ m. Tính chi phí làm phần kính xung quanh, biết giá kính cường lực là $500\,000$ đồng/m$^2$ {\it (kết quả làm tròn đến hàng nghìn đồng)}.
	\begin{center}
		\begin{tikzpicture}[line cap=round,line join=round,font=\footnotesize,declare function={a=4;b=0.65*a;h=0.85*a;goc=-140;k=0.75;}]
			\path
			(0:0) coordinate (A)
			(0:a) coordinate (B)
			(goc:b) coordinate (D)
			($(B)+(D)-(A)$) coordinate (C)
			($(A)!0.5!(C)$)coordinate (O)++(90:h) coordinate (S)
			\foreach \x/\y in {A/M,B/N,C/P,D/Q}{($(S)!k!(\x)$)coordinate (\y)};
			\fill[cyan!30, opacity=70](M)--(N)--(B)--(A)--cycle (A)--(D)--(Q)--(M)--cycle (P)--(N)--(B)--(C)--cycle;
			\fill[cyan!25, opacity=70](Q)--(P)--(C)--(D)--cycle;
			\fill[pattern=grid, opacity=70] (S)--(Q)--(P)--cycle (S)--(P)--(N)--cycle;
			\draw[dashed](D)--(A)--(B) (S)--(A) (Q)--(M)--(N);
			\draw (S)--(C)--(D)--cycle--(B)--(C) (Q)--(P)--(N);
			\foreach \x/\g in {A/135,B/0,C/-45,D/180,S/90,Q/180}
			\fill (\x) circle (1pt)+(\g:7pt) node {$\x$};
		\end{tikzpicture}
	\end{center}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[line cap=round,line join=round,font=\footnotesize,declare function={a=4;b=0.65*a;h=0.85*a;goc=-140;k=0.75;}]
			\path
			(0:0) coordinate (A)
			(0:a) coordinate (B)
			(goc:b) coordinate (D)
			($(B)+(D)-(A)$) coordinate (C)
			($(A)!0.5!(C)$)coordinate (O)++(90:h) coordinate (S)
			\foreach \x/\y in {A/M,B/N,C/P,D/Q}{($(S)!k!(\x)$)coordinate (\y)};
			\draw[dashed](D)--(A)--(B) (S)--(A) (Q)--(M)--(N);
			\draw (S)--(C)--(D)--cycle--(B)--(C) (Q)--(P)--(N);
			\foreach \x/\g in {A/-90,B/0,C/-45,D/180,S/90,M/-60,N/0,P/-20,Q/180}
			\fill (\x) circle (1pt)+(\g:7pt) node {$\x$};
		\end{tikzpicture}
	\end{center}
	Vì hình chóp $S.ABCD$ có tất cả các cạnh đều bằng $4$ m nên đáy $ABCD$ là hình vuông cạnh $4$\,m và các mặt bên là các tam giác đều cạnh $4$\,m.\\
	Xét mặt bên $SCD$ là tam giác đều cạnh $a = 4$\,m. Do đó diện tích một mặt bên là
	\[S_{SCD} = \dfrac{a^2 \sqrt{3}}{4} = \dfrac{4^2 \sqrt{3}}{4} = 4\sqrt{3}\;\text{m}^2.\]
	Gọi mặt phẳng chứa khung inox cắt các cạnh $SA$, $SB$, $SC$ lần lượt tại $M$, $N$, $P$.\\
	Vì $SD = 4$\,m và $DQ = 1$\,m $\Rightarrow SQ = SD - DQ = 4 - 1 = 3$\,m.\\
	Do các cạnh của tứ giác $MNPQ$ lần lượt song song với các cạnh tương ứng của tứ giác $ABCD$ nên theo định lý Ta-lét, ta có
	\[\dfrac{SM}{SA} = \dfrac{SN}{SB} = \dfrac{SP}{SC} = \dfrac{SQ}{SD} = \dfrac{3}{4}.\]
	Tam giác $SPQ$ (phần lưới sắt trên mặt bên $SCD$) đồng dạng với tam giác $SCD$ với tỉ số $k = \dfrac{3}{4}$ nên
	\[S_{SPQ} = \left( \dfrac{3}{4} \right)^2 \cdot S_{SCD} = \frac{9}{16} \cdot 4\sqrt{3} = \dfrac{9\sqrt{3}}{4}\;\text{m}^2.\]
	Diện tích phần kính trên một mặt bên (hình thang cân $PQCD$) là
	\[S_1 = S_{SCD} - S_{SPQ} = 4\sqrt{3} - \dfrac{9\sqrt{3}}{4} = \dfrac{7\sqrt{3}}{4}\;\text{m}^2.\]
	Tổng diện tích kính xung quanh của $4$ mặt bên là
	\[S = 4 \cdot \dfrac{7\sqrt{3}}{4} = 7\sqrt{3}\;\text{m}^2.\]
	Tổng chi phí làm phần kính là
	\[T = S \cdot 500\,000 = 7\sqrt{3} \cdot 500\,000 \approx 6\,062\,000\; \text{(đồng)}.\]
	}

