	}

%[1H4N4-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Kieu Hoa Luan]
	Trong các mệnh đề dưới đây, có bao nhiêu mệnh đề \textbf{sai}?
	\begin{listEX}[1]
		\item [\ding{173}] Hai mặt phẳng cùng song song với một mặt phẳng thứ ba thì chúng song song với nhau.
		\item [\ding{174}] Bất kì đường thẳng nào cắt một trong hai mặt phẳng song song thì nó cũng cắt mặt phẳng còn lại.
		\item [\ding{172}] Hai mặt phẳng phân biệt cùng song song với một đường thẳng thì chúng song song với nhau.
	\end{listEX}
	\choice
	{$0$}
	{$1$}
	{\True $2$}
	{$3$}
\loigiai{
	Mệnh đề $(1)$ là \textbf{đúng}. \\
	Mệnh đề $(2)$ \textbf{sai} vì hai mặt phẳng đó có thể trùng nhau.\\
	Mệnh đề $(3)$ là \textbf{sai} vì hãy tưởng tượng hai trang của một cuốn sách đang mở ra. Cả hai trang giấy (mặt phẳng) đều song song với cái gáy sách (đường thẳng), nhưng rõ ràng hai trang giấy đó đang cắt nhau tại chính cái gáy sách đó.
	}

