		\foreach \x/\g in {A/135,B/0,C/-45,D/180,S/90,O/-90,M/180,X/-90,T/-90,P/180,V/-30,R/-90,Q/0}
		\fill (\x) circle (1pt)
		+(\g:2.5mm) node {$\x$};
	\end{tikzpicture}}
	Áp dụng định lý đường trung bình ta có\\
	$PQ=\dfrac{1}{2}BC=20$\,cm, $RS=40$\,cm, $MO=\dfrac{1}{2} SX=\dfrac{1}{2}\cdot 20\sqrt{3}=10\sqrt{3}$.\\
	Vậy $S_{PQRS}=\dfrac{1}{2}\cdot (40+20)\cdot10\sqrt{3} \approx 520$\,(cm$^2$).

