%[1H4V4-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Kieu Hoa Luan]
	Trong xưởng điêu khắc, nghệ nhân tài hoa vừa hoàn thiện một khối gỗ có hình dáng hình chóp tứ giác đều $S.ABCD$. Đây là một khối gỗ cực kỳ cân đối với tất cả các cạnh bên và cạnh đáy đều dài đúng $40$\,cm. Để tạo thêm điểm nhấn độc đáo cho tác phẩm, nghệ nhân quyết định thực hiện một đường cưa đầy táo bạo:\immini{Đường cưa là một mặt phẳng phẳng mịn, đi qua đúng trung điểm của cạnh bên $SC$. Điều đặc biệt là nhát cưa này phải song song tuyệt đối với mặt bên ($SAD$) của khối gỗ để giữ được ý đồ nghệ thuật đối xứng. Nhát cưa ngọt lịm đi qua, để lộ ra một mặt cắt phẳng (thiết diện) có màu gỗ tươi mới bên trong. Bạn hãy giúp nghệ nhân tính toán xem diện tích của bề mặt gỗ vừa xuất hiện sau nhát cưa đó là bao nhiêu cm$^2$ (làm tròn kết quả đến hàng đơn vị)?
	}{
	\begin{tikzpicture}[line cap=round,line join=round,font=\footnotesize,declare function={a=3.5;b=0.65*a;h=0.85*a;goc=-140;}]
		\path
		(0:0) coordinate (A)
		(0:a) coordinate (B)
		(goc:b) coordinate (D)
		($(B)+(D)-(A)$) coordinate (C)
		($(A)!0.5!(C)$)coordinate (O)++(90:h) coordinate (S)
		\foreach \x/\y/\z in {A/B/R,A/D/X,C/D/T,B/C/V,S/C/P,S/V/M,S/B/Q}{($(\x)!0.5!(\y)$)coordinate (\z)}
		;
		\fill[magenta!30](T)--(P)--(Q)--(R)--cycle;
		\draw[dashed]
		(D)--(A)--(B) (S)--(A) (T)--(R)--(Q);
		\draw
		(S)--(C)--(D)--cycle--(B)--(C)(T)--(P)--(Q);
		\foreach \x/\g in {A/135,B/0,C/-45,D/180,S/90}
		\fill (\x) circle (1pt)
		+(\g:2.5mm) node {$\x$};
	\end{tikzpicture}}
	\par\shortans[]{520}
\loigiai{
	\immini{Gọi $P$ là trung điểm của $SC$. Dựng mặt phẳng qua $P$ song song với mặt phẳng $(SAD)$.\\
	Từ $P$ kẻ song song với $SD$ cắt $CD$ tại $T$, kẻ song song với $BC$ cắt $SD$ tại $Q$.\\
	Từ $Q$ kẻ song song với $SA$ cắt $AB$ ở $R$.\\
	Khi đó thiết diện của khối gỗ bị cắt bởi cưa là tứ giác $PQRT$.\\
	Ta có $PQ\parallel RT\parallel BC$; $QR=PT=\dfrac{1}{2} SA=\dfrac{1}{2}SD$.\\
	Mà $QR$ không song song với $PT$ nên $PQRT$ là hình thang cân.
	}{
	\begin{tikzpicture}[line cap=round,line join=round,font=\footnotesize,declare function={a=4;b=0.65*a;h=0.85*a;goc=-140;}]
		\path
		(0:0) coordinate (A)
		(0:a) coordinate (B)
		(goc:b) coordinate (D)
		($(B)+(D)-(A)$) coordinate (C)
		($(A)!0.5!(C)$)coordinate (O)++(90:h) coordinate (S)
		\foreach \x/\y/\z in {A/B/R,A/D/X,C/D/T,B/C/V,S/C/P,S/V/M,S/B/Q}{($(\x)!0.5!(\y)$)coordinate (\z)};
		\fill[magenta!30](T)--(P)--(Q)--(R)--cycle;
		\draw[dashed]
		(D)--(A)--(B)--cycle (O)--(S)--(A)--(C) (T)--(R)--(Q) (S)--(X)--(V) (M)--(O);
		\draw
		(S)--(C)--(D)--cycle--(B)--(C) (T)--(P)--(Q) (S)--(V);
		\foreach \x/\g in {A/135,B/0,C/-45,D/180,S/90,O/-90,M/180,X/-90,T/-90,P/180,V/-30,R/-90,Q/0}
		\fill (\x) circle (1pt)
		+(\g:2.5mm) node {$\x$};
	\end{tikzpicture}}
	Áp dụng định lý đường trung bình ta có\\
	$PQ=\dfrac{1}{2}BC=20$\,cm, $RS=40$\,cm, $MO=\dfrac{1}{2} SX=\dfrac{1}{2}\cdot 20\sqrt{3}=10\sqrt{3}$.\\
	Vậy $S_{PQRS}=\dfrac{1}{2}\cdot (40+20)\cdot10\sqrt{3} \approx 520$\,(cm$^2$).
	}

%[1H4V4-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Kieu Hoa Luan]
	\immini[thm]{Cho hình lăng trụ tam giác $ABC.A'B'C'$. Gọi $M$, $M'$ lần lượt là trung điểm các đoạn thẳng $BC$, $B'C'$. Trên các đoạn thẳng $AM$, $A'M'$, $A'B$ lần lượt lấy các điểm $G$, $G'$, $K$ thỏa mãn $\dfrac{AG}{AM}=\dfrac{A'G'}{A'M'}=\dfrac{A'K}{A'B}=\dfrac{2}{3}$. Gọi $(\alpha)$ là mặt phẳng đi qua $K$ và song song với mặt phẳng $(ABC)$. Mặt phẳng $(\alpha)$ cắt cạnh $CC'$ tại điểm $I$. Tính $\dfrac{IC}{IC'}$.
	\par\shortans[]{0{,}5}
	}{
	\begin{tikzpicture}[scale=1.2, font=\footnotesize, line join=round, line cap=round, >=stealth]
		\path
		(0,0) coordinate (A)
		(0.9,-1) coordinate (B)
		(3.6,0) coordinate (C)
		($(A)+(0.5,3.5)$) coordinate (A')
		($(A')-(A)+(B)$) coordinate (B')
		($(A')-(A)+(C)$) coordinate (C')
		($(B)!0.5!(C)$) coordinate (M)
		($(B')!0.5!(C')$) coordinate (M')
		($(A)!{2/3}!(M)$) coordinate (G)
		($(A')!{2/3}!(M')$) coordinate (G')
		($(A')!{2/3}!(B)$) coordinate (K)
		;
		\draw (A)--(B)--(C) (A')--(B')--(C')--(A') (A')--(A) (B)--(B') (C)--(C') (C')--(M) (A')--(B)--(M')--(A');
		\draw[dashed] (A)--(C) (G')--(K) (G)--(G') (K)--(G) (A)--(M)--(M');
		\foreach \x/\g in {A/180,B/-90,C/0,A'/180,B'/70,C'/0,M/-90,M'/90,G/-90,G'/40,K/-180} \draw[fill=black] (\x) circle(1pt)++(\g:0.3) node{$\x$};
	\end{tikzpicture}}
\loigiai{
	\immini{Ta có $\heva{&(\alpha)\parallel (ABC)\\&AB\subset (ABC)}\Rightarrow AB\parallel (\alpha)$.\\
	Tương tự, $\heva{&(\alpha)\parallel (ABC)\\&AC\subset (ABC)}\Rightarrow AC\parallel (\alpha)$.\\
	Lại có $\heva{&K\in (\alpha)\cap (ABB'A')\\&AB\parallel (\alpha)\\&AB\subset (ABB'A')}$, suy ra giao tuyến của hai mặt phẳng $(\alpha)$ và $(ABB'A')$ là đường thẳng $d$ qua $K$ và song song $AB$. Đường thẳng này cắt $AA'$ tại $E$, cắt $BB'$ tại $F$.\\
	Khi đó $\dfrac{A'E}{A'A}=\dfrac{A'K}{A'B}=\dfrac{2}{3}\Rightarrow \dfrac{EA}{EA'}=\dfrac{1}{2}$.
	}{
	\begin{tikzpicture}[scale=1.4, font=\footnotesize, line join=round, line cap=round, >=stealth]
		\path
		(0,0) coordinate (A)
		(0.5,-1.1) coordinate (B)
		(3.6,0) coordinate (C)
		($(A)+(0.5,3.5)$) coordinate (A')
		($(A')-(A)+(B)$) coordinate (B')
		($(A')-(A)+(C)$) coordinate (C')
		($(B)!0.5!(C)$) coordinate (M)
		($(B')!0.5!(C')$) coordinate (M')
		($(A)!{2/3}!(M)$) coordinate (G)
		($(A')!{2/3}!(M')$) coordinate (G')
		($(A')!{2/3}!(B)$) coordinate (K)
		($(A')!{2/3}!(A)$) coordinate (E)
		($(B')!{2/3}!(B)$) coordinate (F)
		($(C')!{2/3}!(C)$) coordinate (I)	;
		\draw (A)--(B)--(C) (A')--(B')--(C')--(A') (A')--(A) (B)--(B') (C)--(C') (C')--(M) (A')--(B)--(M')--(A') (E)--(F)--(I);
		\draw[dashed] (A)--(C) (G')--(K) (G)--(G') (K)--(G) (A)--(M)--(M') (I)--(E);
		\foreach \x/\g in {A/180,B/-90,C/0,A'/180,B'/70,C'/0,M/-90,M'/90,G/-90,G'/40,K/-180,E/180,F/60,I/0} \draw[fill=black] (\x) circle(1pt)++(\g:0.3) node{$\x$};
	\end{tikzpicture}}
	\noindent
	Tương tự $\heva{&E\in (\alpha)\cap (ACC'A')\\&AC\parallel (\alpha)\\&AC\subset (ACC'A')}$, suy ra giao tuyến của hai mặt phẳng $(\alpha)$ và $(ACC'A')$ là đường thẳng đi qua $E$ và song song $AC$, đường này cắt $CC'$ tại $I$.\\
	Khi đó $\dfrac{IC}{IC'}=\dfrac{EA}{EA'}=\dfrac{1}{2}$.
	}

