%[1H4V4-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Kieu Hoa Luan]
	Bác Ba là một thợ mộc có tiếng trong vùng, nổi tiếng với những chiếc kệ gỗ vừa bền vừa tinh tế. Hôm nay, bác đang hoàn thiện một chiếc kệ gỗ trưng bày có thiết kế khá độc đáo:\immini{Tầng dưới cùng ($ABCD$) và tầng trên cùng ($EFGH$) là hai mặt phẳng song song tuyệt đối để đảm bảo đồ vật đặt lên không bị nghiêng. Bác đo được độ dài hai chân trụ phía trước và phía sau lần lượt là $AE = 80$\,cm và $CG = 90$\,cm. Để chiếc kệ thêm phần tiện dụng và chắc chắn, bác Ba quyết định lắp thêm một mâm tầng giữa ($IJKL$). Mâm này cũng phải nằm song song với hai tầng trên và dưới. Sau khi cân đối thẩm mỹ, bác thấy đặt mâm giữa sao cho khoảng cách từ tầng trên xuống (đoạn $EI$) bằng $36$\,cm là đẹp nhất. Bác Ba cần đo và đánh dấu điểm $K$ trên chân trụ $CG$ sao cho đoạn $GK$ dài bao nhiêu để mâm giữa nằm chuẩn xác, không bị vênh và song song với hai mâm còn lại?
	}{
	\begin{tikzpicture}[scale=.7, font=\footnotesize, line join=round, line cap=round, >=stealth][line join = round, line cap = round,>=stealth,font=\footnotesize,scale=0.6]
		\path
		(0,0) coordinate (A)
		(1.5,1) coordinate (B)
		(5,0) coordinate (D)
		(6.5,1) coordinate (C)
		(0,5) coordinate (E)
		(1.5,6) coordinate (F)
		(3.5,5) coordinate (H)
		(5,6) coordinate (G)
		($(E)!0.4!(A)$) coordinate (I)
		($(F)!0.4!(B)$) coordinate (J)
		($(H)!0.4!(D)$) coordinate (L)
		($(G)!0.4!(C)$) coordinate (K)
		;
		\draw (E)--(A)--(D)--(C)--(G)--(H)--(E)--(F)--(G) (D)--(H) (I)--(L)--(K);
		\draw[dashed] (A)--(B)--(C) (B)--(F) (I)--(J)--(K);
		\foreach \d/\g in {A/180, B/150, C/0, D/-50, I/190, J/150, K/30, L/-120, E/180,F/90,G/60,H/-120}
		\fill (\d) circle(1.5pt) node[shift={(\g:0.3)}]{$\d$};
		\node at (0,0){\href{4EA0NG}{\tiny \phantom{4EA0NG}}};
		\fill[blue!10] (E)--(F)--(G)--(H)--cycle;
	\end{tikzpicture}}
\loigiai{
	Áp dụng định lý Thalès trong không gian đối với $3$ mặt phẳng song song $(ABCD)$, $(IJKL)$, $(EFGH)$ và $2$ cát tuyến $EA$, $GC$ ta có \[\dfrac{EI}{AE}=\dfrac{GK}{CG}\Rightarrow \dfrac{GK}{90}=\dfrac{36}{80} \Rightarrow GK=40{,}5 \text{ (cm)}.\]
	}

