%[1H4V4-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Kieu Hoa Luan]
	Cho hình hộp $ABCD.A'B'C'D'$.
	\begin{enumerate}
		\item Chứng minh rằng $(BDA') \parallel(B'D'C')$.
		\item Chứng minh đường chéo $AC'$ đi qua trọng tâm $G_1$, $G_2$ của tam giác $BDA'$ và $B'D'C$.
		\item Chứng tỏ rằng $G_1$, $G_2$ chia đoạn $AC'$ thành ba phần bằng nhau.
		\item Mặt phẳng $(A'B'G_2)$ cắt hình hộp $ABCD.A'B'C'D'$ tạo thành một tứ giác là hình bình hành.
	\end{enumerate}
\loigiai{
	\begin{center}
		\begin{tikzpicture}[line join=round, line cap=round,>=stealth,thick, scale=1.2]
			\coordinate (A) at (-2,-2);
			\coordinate (B) at (-4,-4);
			\coordinate (C) at (2,-4);
			\coordinate (D) at (4,-2);
			\coordinate (A') at (-2,4);
			\coordinate (B') at (-4,2);
			\coordinate (C') at (2,2);
			\coordinate (D') at (4,4);
			\coordinate (O') at (intersection of A'--C' and B'--D');
			\coordinate (O) at (intersection of A--C and B--D);
			\coordinate (M) at ($(C')!0.5!(C)$);
			\coordinate (N) at ($(D')!0.5!(D)$);
			\coordinate (P) at ($(M)!0.5!(N)$);
			\coordinate (G_1) at (intersection of A'--O and A--C');
			\coordinate (G_2) at (intersection of C--O' and A--C');
			\draw(A')--(B') (B')--(C') (C')--(D') (D')--(A') (B')--(D') (A')--(C') (B')--(B) (C')--(C) (D')--(D) (B')--(M) (B')--(C) (M)--(N) (D')--(C) (B)--(C) (C)--(D);
			\draw[dashed](A')--(N) (A')--(D) (A)--(D) (A')--(A) (A')--(B) (A)--(D) (A)--(B) (A)--(C) (B)--(D) (A)--(C') (A')--(O) (A)--(B) (A')--(G_2) (C)--(O') (B')--(P);
			\foreach \i in {A',D',C',O',B'}{\draw(\i) node[scale=0.9,above]{$\i$};}
			\foreach \i in {G_1,G_2,N,D,C,P}{\draw(\i) node[scale=0.9, right]{$\i$};}
			\foreach \i in {A,B,M}{\draw(\i) node[scale=0.9, left]{$\i$};}
			\foreach \i in {O}{\draw(\i) node[scale=0.9,below]{$\i$};}
			\foreach \i in {O',G_1,G_2,O,O',A,B,C,D,A',B',C',D',M,N,P}{\draw[fill=](\i) circle (1.5pt);}
		\end{tikzpicture}
	\end{center}
	\begin{enumerate}
		\item
		Ta có $BA'D'C$ là hình bình hành nên $BA' \parallel D'C$.\\
		Ta có $BB'D'D$ là hình bình hành nên $B'D' \parallel BD$.\\
		Ta có $\heva{&BA'\parallel D'C \\&
		BD' \parallel B'D' \\
		&BA',\, BD \subset (BA'D),\, BA'\cap BD=B\\&
		B'D',\, D'C \subset (B'D'C),\, B'D'\cap D'C=D'}
		\Rightarrow (BDA') \parallel (B'D'C)$.
		\item Trong $(ABCD)$, gọi $O=AC \cap BD$.\\
		Ta có $\heva{& O\in AC,\,AC \subset (ACC'A')\\& O \in D,\, BD \subset (BDA')}$.\\
		$\Rightarrow O \in (ACC'A')\cap (BDA')$.\\
		Mà $A'\in (ACC'A') \cap (BDA')$ nên $A'O=(ACC'A')\cap (BDA')$.\\
		Trong $(ACC'A')$, gọi $E=A'O \cap AC'$.\\
		Ta có $\dfrac{{A'E}}{EO}=\dfrac{A'C'}{AO}=2$.\\
		Suy ra $E$ trùng với trọng tâm $G_1$ của tam giác $BDA'\quad(1)$.\\
		Trong $(A'B'C'D')$, gọi $O'=A'C'\cap B'D'$.\\
		Ta có $\heva{& O'\in A'C',\, A'C' \subset (ACC'A')\\ & O' \in B'D',\, B'D' \subset (B'D'C)}
		\Rightarrow O' \in (ACC'A') \cap (B'D'C)$.\\
		Mà $C \in (ACC'A') \cap (B'D'C)$ nên $CO=(ACC'A') \cap (B'D'C)$.\\
		Trong $(ACC'A')$, gọi $F=CO \cap AC'$.\\
		Ta có $\dfrac{CF}{FO'}=\dfrac{AC}{C'O'}=2$.\\
		Suy ra $F$ trùng với trọng tâm $G_2$ của tam giác $B'D'C.\quad(2)$. \\
		Từ $(1)$ và $(2)$ suy ra $AC'$ qua trọng tâm $G_1$, $G_2$ của tam giác $BDA'$ và $B'D'C$.
		\item Trong $(AA'C'C)$, gọi $I=A'C\cap AC'$.\\
		\begin{center}
			\begin{tikzpicture}[line join=round, line cap=round,>=stealth,thick, scale=1.2]
				\coordinate (A) at (-3,-2);
				\coordinate (A') at (-2,1);
				\coordinate (C') at (3,1);
				\coordinate (C) at (2,-2);
				\coordinate (O') at ($(A')!0.5!(C')$);
				\coordinate (O) at ($(A)!0.5!(C)$);
				\coordinate (G_1) at (intersection of A'--O and A--C');
				\coordinate (G_2) at (intersection of O'--C and A--C');
				\coordinate (I) at (intersection of A'--C and A--C');
				\draw(A')--(C') (C')--(C) (C)--(A) (A)--(A') (A')--(O) (C)--(O') (A')--(C) (A)--(C');
				\foreach \i in {A',O',C'}{\draw(\i) node[scale=0.9,above]{$\i$};}
				\foreach \i in {A,O,C,I}{\draw(\i) node[scale=0.9,below]{$\i$};}
				\foreach \i in {G_1,G_2}{\draw(\i) node[scale=0.9,below right]{$\i$};}
			\end{tikzpicture}
		\end{center}
		Vì $G_1$ là trọng tâm của tam giác $A'AC$ nên $AG_1=\dfrac{2}{3}AI=\dfrac{2}{3} \cdot \dfrac{1}{2} AC'=\dfrac{1}{3}AC'$.\\
		Vì $G_2$ là trọng tâm của tam giác $A'CC'$ nên $AG_2=\dfrac{2}{3}C' I=\dfrac{2}{3} \cdot \dfrac{1}{2}AC'=\dfrac{1}{3} AC'$.\\
		Ta có $G_1G_2=AC'-AG_1-C'G_2=A C'-\dfrac{1}{3}AC'-\dfrac{1}{3}AC'=\dfrac{1}{3} AC'$.\\
		Do đó $AG_1=G_1G_2=G_2C$.\\
		Vậy $G_1$, $G_2$ chia đoạn $AC'$ thành ba phần bằng nhau.
		\item  Xét tam giác $B'D'C$, gọi $P=B'G_2 \cap CD'$.\\
		Suy ra $P$ là trung điểm của $CD'$.\\
		Trong $(A'B'G_2)$, vẽ $Px \parallel AB'$.\\
		Trong $(CC'D'D)$, $Px$ cắt $CC'$, $DD'$ lần lượt tại $M$ và $N$.\\
		Suy ra $MN\parallel CD$ và $MN=CD$.\\
		Ta có $\heva{&(A'B'G_2)\cap (A'B'C' D')=A'B' \\
		&(A'B'G_2) \cap (B'C'CB)=B'M \\
		&(A'B'G_2)\cap (C'D'D)=MN \\
		&(A'B'G_2) \cap (AA'D'D)=NA'}.$\\
		Suy ra thiết diện của $(A'B'G_2)$ và hình hộp $ABCD.A'B'C'D'$ là tứ giác $A'B'MN$.\\
		Ta có $\heva{&MN \parallel A'B'\\ &MN=A'B'=CD.}$\\ Vậy thiết diện $A'B'MN$ là hình bình hành.
	\end{enumerate}
	}

