questions.solution:
Xét đáp án $C$, rút lũy thừa bậc cao nhất của $n$ ra làm nhân tử chung
	\begin{align*}
		\lim \dfrac{2n^2-3n^4}{n^2+2n^3} &= \lim \dfrac{n^4\left(\dfrac{2}{n^2} - 3\right)}{n^3\left(\dfrac{1}{n} + 2\right)} \\
		&= \lim \left[ n \cdot \dfrac{\dfrac{2}{n^2} - 3}{\dfrac{1}{n} + 2} \right].
	\end{align*}
	Vì $\lim n = +\infty$ và $\lim \dfrac{\dfrac{2}{n^2} - 3}{\dfrac{1}{n} + 2} = -\dfrac{3}{2} < 0$ nên giới hạn của dãy số là $-\infty$.

questions.rawBody:
%[1D3N1-4]
	Dãy số nào sau đây có giới hạn là $-\infty$?
	\choice
	{$\dfrac{1+2n}
	{5n+5n^2}$}
	{$u_n=\dfrac{n^3+2n-1}
	{-n+2n^3}$}
	{\True $u_n=\dfrac{2n^2-3n^4}{n^2+2n^3}$}
	{$u_n=\dfrac{n^2-2n}{5n+1}$}
\loigiai{
	Xét đáp án $C$, rút lũy thừa bậc cao nhất của $n$ ra làm nhân tử chung
	\begin{align*}
		\lim \dfrac{2n^2-3n^4}{n^2+2n^3} &= \lim \dfrac{n^4\left(\dfrac{2}{n^2} - 3\right)}{n^3\left(\dfrac{1}{n} + 2\right)} \\
		&= \lim \left[ n \cdot \dfrac{\dfrac{2}{n^2} - 3}{\dfrac{1}{n} + 2} \right].
	\end{align*}
	Vì $\lim n = +\infty$ và $\lim \dfrac{\dfrac{2}{n^2} - 3}{\dfrac{1}{n} + 2} = -\dfrac{3}{2} < 0$ nên giới hạn của dãy số là $-\infty$.
	}

%[1D3H1-5]
	Tổng của một cấp số nhân lùi vô hạn bằng $2$, tổng của ba số hạng đầu tiên của cấp số nhân bằng $2{,}25$. Số hạng đầu $u_1$ của cấp số nhân đó là
	\choice
	{\True $u_1=3$}
	{$u_1=4$}
	{$u_1=4{,}5$}
	{$u_1=5$}
\loigiai{
	Gọi $u_1$ là số hạng đầu và $q$ là công bội của cấp số nhân lùi vô hạn (với điều kiện $|q| < 1$).\\
	Theo công thức tính tổng của cấp số nhân lùi vô hạn $S = \dfrac{u_1}{1-q}$, ta có
	\begin{align}
		\dfrac{u_1}{1-q} = 2. \quad (1)
	\end{align}
	Theo công thức tính tổng của $n$ số hạng đầu tiên $S_n = u_1 \cdot \dfrac{1-q^n}{1-q}$, với $n=3$ ta có
	\begin{align}
		u_1 \cdot \dfrac{1-q^3}{1-q} = 2{,}25. \quad (2)
	\end{align}
	Từ $(1)$ và $(2)$, ta có hệ phương trình
	$$\heva{\dfrac{u_1}{1-q} = 2 \\
	\left(\dfrac{u_1}{1-q}\right) \cdot (1-q^3) = 2{,}25}$$
	Thế $(1)$ vào $(2)$, ta được
	\begin{align*}
		2 \cdot (1-q^3) &= 2{,}25 \\
		\Leftrightarrow 1-q^3 &= \dfrac{2{,}25}{2} \\
		\Leftrightarrow 1-q^3 &= 1{,}125 \\
		\Leftrightarrow q^3 &= 1 - 1{,}125 \\
		\Leftrightarrow q^3 &= -0{,}125 \\
		\Leftrightarrow q &= -0{,}5 \text{ (thỏa mãn điều kiện } |q| < 1).
	\end{align*}
	Thay $q = -0{,}5$ vào phương trình $(1)$ để tìm $u_1$, ta có
	\begin{align*}
		\dfrac{u_1}{1 - (-0{,}5)} &= 2 \\
		\Leftrightarrow \dfrac{u_1}{1{,}5} &= 2 \\
		\Leftrightarrow u_1 &= 2 \cdot 1{,}5 = 3.
	\end{align*}
	Vậy số hạng đầu của cấp số nhân lùi vô hạn đó là $u_1 = 3$.
	}

%[1D3H1-3]
	Giá trị của giới hạn $\lim \left(\sqrt{n+5}-\sqrt{n+1}\right)$ bằng
	\choice
	{\True $0$}
	{$1$}
	{$3$}
	{$5$}
\loigiai{
	Nhân và chia với biểu thức liên hợp, ta có
	\begin{align*}
		\lim \left(\sqrt{n+5}-\sqrt{n+1}\right) &= \lim \dfrac{(\sqrt{n+5}-\sqrt{n+1})\cdot(\sqrt{n+5}+\sqrt{n+1})}{\sqrt{n+5}+\sqrt{n+1}} \\
		&= \lim \dfrac{(n+5) - (n+1)}{\sqrt{n+5}+\sqrt{n+1}} \\
		&= \lim \dfrac{4}{\sqrt{n+5}+\sqrt{n+1}} \\
		&= \lim \dfrac{\dfrac{4}{\sqrt{n}}}{\sqrt{1+\dfrac{5}{n}}+\sqrt{1+\dfrac{1}{n}}} \\
		&= \dfrac{0}{1+1} = 0.
	\end{align*}
	}

%[1D3H1-5]
	Tính tổng $S=1+\dfrac{2}{3}+\dfrac{4}{9}+\dots+\dfrac{2^n}{3^n}+\dots$.
	\choice
	{\True $S=3$}
	{$S=4$}
	{$S=5$}
	{$S=6$}
\loigiai{
	Các số hạng của tổng lập thành một cấp số nhân lùi vô hạn với số hạng đầu $u_1=1$ và công bội $q=\dfrac{2}{3}$.\\
	Tổng của cấp số nhân lùi vô hạn này là
	\begin{align*}
		S &= \dfrac{u_1}{1-q} \\
		&= \dfrac{1}{1-\dfrac{2}{3}} \\
		&= 3.
	\end{align*}
	}

%[1D3H1-3]
	Giá trị của giới hạn $\lim \left(\sqrt{n^2-n+1}-n\right)$ là
	\choice
	{\True $-0{,}5$}
	{$0$}
	{$1$}
	{$-\infty$}
\loigiai{
	Nhân và chia với biểu thức liên hợp, ta có
	\begin{align*}
		\lim \left(\sqrt{n^2-n+1}-n\right) &= \lim \dfrac{(\sqrt{n^2-n+1}-n)\cdot(\sqrt{n^2-n+1}+n)}{\sqrt{n^2-n+1}+n} \\
		&= \lim \dfrac{n^2-n+1-n^2}{\sqrt{n^2-n+1}+n} \\
		&= \lim \dfrac{-n+1}{n\sqrt{1-\dfrac{1}{n}+\dfrac{1}{n^2}}+n} \\
		&= \lim \dfrac{n\cdot\left(-1+\dfrac{1}{n}\right)}{n\cdot\left(\sqrt{1-\dfrac{1}{n}+\dfrac{1}{n^2}}+1\right)} \\
		&= \lim \dfrac{-1+\dfrac{1}{n}}{\sqrt{1-\dfrac{1}{n}+\dfrac{1}{n^2}}+1} \\
		&= \dfrac{-1+0}{\sqrt{1-0+0}+1} = -\dfrac{1}{2} = -0{,}5.
	\end{align*}
	}

%[1D3H1-2]
	Cho hai dãy số $(u_n)$ và $(v_n)$ có $u_n=4n^2-n+3$; $v_n=3n^2+7$.
	\choiceTF
	{\True $\lim \dfrac{u_n}{v_n} \approx 1{,}33$}
	{$\lim \dfrac{u_n}{(v_n)^2} \approx 0{,}44$}
	{$\lim \dfrac{(u_n)^2}{v_n} \approx 5{,}33$}
	{\True $\lim \dfrac{u_n+an^2+2\,026}{v_n}=677$ khi đó $a=2\,027$}
\loigiai{
	\begin{itemchoice}
		\itemch Chia cả tử và mẫu cho $n^2$, ta có
		\begin{align*}
			\lim \dfrac{u_n}{v_n} &= \lim \dfrac{4n^2-n+3}{3n^2+7} \\
			&= \lim \dfrac{4 - \dfrac{1}{n} + \dfrac{3}{n^2}}{3 + \dfrac{7}{n^2}} = \dfrac{4}{3} \approx 1{,}33.
		\end{align*}
		\itemch Bậc của tử số là $2$, bậc của mẫu số là $4$. Chia cả tử và mẫu cho $n^4$
		\begin{align*}
			\lim \dfrac{u_n}{(v_n)^2} &= \lim \dfrac{4n^2-n+3}{(3n^2+7)^2} = \lim \dfrac{4n^2-n+3}{9n^4+42n^2+49} \\
			&= \lim \dfrac{\dfrac{4}{n^2} - \dfrac{1}{n^3} + \dfrac{3}{n^4}}{9 + \dfrac{42}{n^2} + \dfrac{49}{n^4}} = \dfrac{0}{9} = 0 \neq 0{,}44.
		\end{align*}
		\itemch Bậc của tử số là $4$, bậc của mẫu số là $2$.
		\begin{align*}
			\lim \dfrac{(u_n)^2}{v_n} &= \lim \dfrac{(4n^2-n+3)^2}{3n^2+7} = \lim \dfrac{n^4\cdot\left(4 - \dfrac{1}{n} + \dfrac{3}{n^2}\right)^2}{n^2\cdot\left(3 + \dfrac{7}{n^2}\right)} \\
			&= \lim \left[ n^2 \cdot \dfrac{\left(4 - \dfrac{1}{n} + \dfrac{3}{n^2}\right)^2}{3 + \dfrac{7}{n^2}} \right] = +\infty \neq 5{,}33.
		\end{align*}
		\itemch Ta thiết lập giới hạn với tham số $a$
		\begin{align*}
			\lim \dfrac{u_n+an^2+2\,026}{v_n} &= \lim \dfrac{(4n^2-n+3) + an^2 + 2\,026}{3n^2+7} \\
			&= \lim \dfrac{(4+a)\cdot n^2 - n + 2\,029}{3n^2+7} \\
			&= \lim \dfrac{(4+a) - \dfrac{1}{n} + \dfrac{2\,029}{n^2}}{3 + \dfrac{7}{n^2}} = \dfrac{4+a}{3}.
		\end{align*}
		Theo giả thiết, giới hạn này bằng $677$, ta có phương trình
		\[ \dfrac{4+a}{3} = 677 \Leftrightarrow 4+a = 2\,031 \Leftrightarrow a = 2\,027. \]
	\end{itemchoice}
	}

%[1D3H1-5]
	Cho dãy số $(u_n)$ có số hạng tổng quát $u_n=\dfrac{9^n+3^{n+2}}{6^n+9^{n+a}}$.
	\choiceTF
	{\True Khi $a=0$ thì $\lim u_n=1$}
	{Khi $a=1$ thì $\lim u_n=9$}
	{Khi $a=-1$ thì $\lim u_n \approx 0{,}11$}
	{\True Có $2\,026$ giá trị nguyên của tham số $a$ thuộc đoạn $[0;2\,027]$ để $\lim u_n \leq \dfrac{1}{81}$}
\loigiai{
	Ta biến đổi số hạng tổng quát và chia cả tử và mẫu cho $9^n$ (lũy thừa cơ số lớn nhất)
	\begin{align*}
		\lim u_n &= \lim \dfrac{9^n+9 \cdot 3^n}{6^n+9^a \cdot 9^n} \\
		&= \lim \dfrac{1 + 9 \cdot \left(\dfrac{3}{9}\right)^n}{\left(\dfrac{6}{9}\right)^n + 9^a} \\
		&= \lim \dfrac{1 + 9 \cdot \left(\dfrac{1}{3}\right)^n}{\left(\dfrac{2}{3}\right)^n + 9^a} = \dfrac{1 + 9 \cdot 0}{0 + 9^a} = \dfrac{1}{9^a} = 9^{-a} \quad(*).
	\end{align*}
	\begin{itemchoice}
		\itemch Thay $a=0$ vào $(*)$, ta được $\lim u_n = 9^0 = 1$.
		\itemch Thay $a=1 $ vào $(*)$, ta được $\lim u_n = 9^{-1} = \dfrac{1}{9} \neq 9$.
		\itemch Thay $a=-1$ vào $(*)$, ta được $\lim u_n = 9^{-(-1)} = 9 \neq 0{,}11$.
		\itemch Ta giải bất phương trình
		\begin{align*}
			\lim u_n \leq \dfrac{1}{81} &\Leftrightarrow 9^{-a} \leq 9^{-2} \\
			&\Leftrightarrow -a \leq -2 \\
			&\Leftrightarrow a \geq 2.
		\end{align*}
		Vì $a$ là số nguyên và $a \in [0; 2\,027]$ nên $a \in \{2; 3; 4; \dots; 2\,027\}$.\\
		Số lượng các giá trị của $a$ thỏa mãn là $2\,026$ giá trị.
	\end{itemchoice}
	}

%[1D3V1-6]
	Một loại vi khuẩn được nuôi cấy với số lượng ban đầu là $50$ con. Sau mỗi chu kì $4$ giờ, số lượng của chúng sẽ tăng gấp đôi. Gọi $u_n$ là số lượng vi khuẩn sau chu kì thứ $n$.
	\choiceTF
	{\True Công thức tổng quát của $u_n$ là $u_n = 50 \cdot 2^n$}
	{\True Dãy số $(u_n)$ có giới hạn là $+\infty$}
	{Số lượng vi khuẩn vượt con số $20\,260$ sau ít nhất $8$ chu kì}
	{Nếu tốc độ tăng trưởng chỉ là gấp $\dfrac{2\,027}{2\,026}$ lần thì giới hạn của dãy số $u_n$ là $0$}
\loigiai{
	\begin{itemchoice}
		\itemch Gọi $u_0 = 50$ là số lượng vi khuẩn ban đầu. \\
		Sau chu kì 1, số lượng là $u_1 = 50 \cdot 2$. \\
		Sau chu kì 2, số lượng là $u_2 = u_1 \cdot 2 = 50 \cdot 2^2$. \\
		Số lượng vi khuẩn sau chu kì thứ $n$ tạo thành một cấp số nhân có số hạng tổng quát là
		\begin{align*}
			u_n &= 50 \cdot 2^n.
		\end{align*}
		\itemch Ta xét giới hạn của dãy số $(u_n)$ khi $n \to +\infty$
		\begin{align*}
			\lim u_n &= \lim (50 \cdot 2^n) = 50 \cdot \lim 2^n.
		\end{align*}
		Vì công bội $q = 2 > 1$ nên $\lim 2^n = +\infty$. Suy ra $\lim u_n = +\infty$.
		\itemch Để số lượng vi khuẩn vượt con số $20\,260$, ta giải bất phương trình
		\begin{align*}
			u_n &> 20\,260 \\
			\Leftrightarrow 50 \cdot 2^n &> 20\,260 \\
			\Leftrightarrow 2^n &> 405{,}2.
		\end{align*}
		Vì $n$ là số nguyên dương và ta có $2^8 = 256 < 405{,}2$ và $2^9 = 512 > 405{,}2$, nên ta phải có $n \ge 9$. Nghĩa là cần ít nhất $9$ chu kì, không phải $8$ chu kì.
		\itemch Nếu tốc độ tăng trưởng là gấp $\dfrac{2\,027}{2\,026}$ lần (thay vì $2$ lần), ta có công thức $u_n = 50 \cdot \left(\dfrac{2\,027}{2\,026}\right)^n$. Giới hạn của dãy số lúc này là
		\begin{align*}
			\lim u_n &= \lim \left[ 50 \cdot \left(\dfrac{2\,027}{2\,026}\right)^n \right].
		\end{align*}
		Vì cơ số $q = \dfrac{2\,027}{2\,026} > 1$ nên $\lim \left(\dfrac{2\,027}{2\,026}\right)^n = +\infty$. Do đó $\lim u_n = +\infty$, không phải bằng $0$.
	\end{itemchoice}
	}

