%[1D3N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to 1}(2x^2-3x+1)$.
	\choice
	{\True $0$}
	{$1$}
	{$2$}
	{$3$}
\loigiai{
	Ta có $\lim_{x\to1}(2x^2-3x+1)=2-3+1=0$.
	}

%[1D3N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to -2}(x^3+1)$.
	\choice
	{\True $-7$}
	{$-9$}
	{$7$}
	{$9$}
\loigiai{
	Ta có $\displaystyle \lim_{x\to -2}(x^3+1)=(-2)^3+1=-8+1=-7$.
	}

%[1D3N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to 2}\frac{x^2+1}{x+3}$.
	\choice
	{\True $1$}
	{$2$}
	{$\frac{5}
	{2}$}
	{$\frac{3}{2}$}
\loigiai{
	Ta có $\displaystyle \lim_{x\to 2}\frac{x^2+1}{x+3}=\dfrac{2^2+1}{2+3}=1$.
	}

%[1D3N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to 0}(5x+3)$.
	\choice
	{$5$}
	{\True $3$}
	{$0$}
	{$-3$}
\loigiai{
	Ta có $\displaystyle \lim_{x\to 0}(5x+3)=5\cdot0+3=3$.
	}

