	\choice
	{$1$}
	{\True $2$}
	{$0$}
	{$3$}
\loigiai{
	$\displaystyle \lim_{x\to 1}\dfrac{x^2-1}{x-1}=\displaystyle \lim_{x\to 1}\dfrac{(x-1)(x+1)}{x-1}=\displaystyle \lim_{x\to 1}(x+1)=2$.
	}

questions.solution:
Ta có
	\begin{align*}
		\displaystyle \lim_{x\to 0}\dfrac{\sqrt{1+x}-1}{x}&=\lim_{x\to 0}\dfrac{\left(\sqrt{x+1}-1\right)\left(\sqrt{x+1}+1\right)}{x\left(\sqrt{x+1}+1\right)}
		\\
		&=\lim_{x\to 0}\dfrac{x}{x\left(\sqrt{x+1}+1\right)}
		\\
		&=\lim_{x\to 0}\dfrac{1}{\sqrt{x+1}+1}
		\\
		&=\dfrac{1}{2}.
	\end{align*}

