%[1D3N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Xét các mệnh đề sau đúng hay sai?
	\choiceTF
	{\True $\displaystyle \lim_{x\to 2}(3x-1)=5$}
	{$\displaystyle \lim_{x\to 0}(x^2+1)=0$}
	{$\displaystyle \lim_{x\to 1}\frac{x^2-1}{x-1}=1$}
	{$\displaystyle \lim_{x\to 3}\sqrt{x}=9$}
\loigiai{
	\begin{itemchoice}
		\itemch  Ta có $\lim_{x\to2}(3x-1)=3\cdot2-1=5$.
		\itemch Ta có $\lim_{x\to0}(x^2+1)=1\ne0$.
		\itemch Ta có $\displaystyle \lim_{x\to1}\frac{x^2-1}{x-1}
		=\lim_{x\to1}(x+1)=2\ne1$.
		\itemch Ta có $\lim_{x\to3}\sqrt{x}=\sqrt{3}\ne9$.
	\end{itemchoice}
	}

%[1D3H2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Xét các mệnh đề sau đúng hay sai?
	\choiceTF
	{\True $\displaystyle \lim_{x\to 1}\dfrac{x^2-1}{x-1}=2$}
	{$\displaystyle \lim_{x\to 0}\frac{\sqrt{1+x}-1}{x}=1$}
	{\True $\displaystyle \lim_{x\to +\infty}\frac{2x+1}{x+3}=2$}
	{$\displaystyle \lim_{x\to +\infty}\frac{5x+1}{x^2+2}=1$}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có $\displaystyle \lim_{x\to 1}\dfrac{x^2-1}{x-1}=\displaystyle \lim_{x\to 1}(x-1)=2$.
		\itemch Ta có $\displaystyle
		\lim_{x\to 0}\dfrac{\sqrt{1+x}-1}{x}
		=\displaystyle
		\lim_{x\to 0}\dfrac{1}{\sqrt{1+x}+1}=\dfrac{1}{2}\ne1$.
		\itemch Chia cả tử và mẫu cho $x$ ta có $\displaystyle \lim_{x\to +\infty}\frac{2x+1}{x+3}=\displaystyle \lim_{x\to +\infty}
		\dfrac{2+\frac{1}{x}}{1+\frac{3}{x}}=2$.
		\itemch Bậc tử nhỏ hơn bậc mẫu nên giới hạn bằng $0$, không phải $1$.
	\end{itemchoice}}

%[1D3V2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Chi phí trung bình để sản xuất mỗi sản phẩm được cho bởi công thức
	\[
	C(x)=\dfrac{5\,000x+2\,000}{x}\quad (\text{đồng}),
	\]
	trong đó $x$ là số sản phẩm sản xuất được.
	\choiceTF
	{\True Khi $x$ rất lớn thì $C(x)$ tiến dần tới $5\,000$}
	{$\displaystyle \lim_{x\to +\infty}C(x)=0$}
	{\True Với $x$ càng lớn thì chi phí trung bình càng ổn định}
	{$C(x)$ tăng vô hạn khi $x$ tăng vô hạn}
\loigiai{
	\begin{itemchoice}
		\itemch $\displaystyle \lim_{x\to+\infty}C(x)=\displaystyle \lim_{x\to+\infty}\dfrac{5\,000x+2\,000}{x}=5\,000$.
		\itemch Ta có $\displaystyle \lim_{x\to+\infty}C(x)=5\,000$.
		\itemch Ta có $\dfrac{C(x)}{x}=5\,000+\dfrac{2\,000}{x}$. \\
		Khi $x$ càng lớn thì $\dfrac{2\,000}{x}\to0$, chi phí trung bình ổn định gần $5\,000$
		\itemch $C(x)$ không tăng vô hạn mà tiến tới $5\,000$.
	\end{itemchoice}
	}

%[1D3V2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Một mô hình dân số được cho bởi
	\[
	P(t)=\dfrac{800t}{t+20},
	\]
	trong đó $t$ tính bằng năm, $P(t)$ tính bằng nghìn người.
	\choiceTF
	{\True $\displaystyle \lim_{t\to +\infty}P(t)=800$}
	{$\displaystyle \lim_{t\to +\infty}P(t)=20$}
	{\True Dân số có xu hướng ổn định ở mức $800$ nghìn người}
	{$P(t)$ tăng vô hạn khi $t$ tăng vô hạn}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có $\displaystyle \lim_{t\to +\infty}P(t)=\displaystyle \lim_{t\to +\infty}\dfrac{800t}{t+20}=800$.
		\itemch $\displaystyle \lim_{t\to +\infty}P(t)=800$.
		\itemch Điều này cho thấy dân số tiến dần tới mức ổn định $800$ nghìn người.
		\itemch Hàm số không tăng vô hạn mà bị chặn trên bởi $800$.
	\end{itemchoice}
	}

%[1D3H2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to 2}\frac{x^2-4x+4}{x-2}$.
	\par\shortans{0}
\loigiai{
	$\displaystyle \lim_{x\to 2}\frac{x^2-4x+4}{x-2}=\displaystyle \lim_{x\to 2}\dfrac{(x-2)^2}{x-2}=\displaystyle \lim_{x\to 2}(x-2)=0$.
	}

%[1D3H2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to 0}\frac{(1+x)^2-1}{x}$.
	\par\shortans{2}
\loigiai{
	$\displaystyle \lim_{x\to 0}\dfrac{(1+x)^2-1}{x}=\lim_{x\to 0}\dfrac{x^2+2x}{x}=\lim_{x\to 0}(x+2)=2.$.
	}

%[1D3H2-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Mui Doan]
	Tính $\displaystyle \lim_{x\to +\infty}\frac{4x^2+3x}{2x^2-5}$.
	\shortans[oly]{2}
\loigiai{
	Chia cả tử và mẫu cho $x^2$ ta có
	$\displaystyle \lim_{x\to +\infty}\frac{4x^2+3x}{2x^2-5}=\displaystyle \lim_{x\to +\infty}\dfrac{4+\frac{3}{x}}{2-\frac{5}{x^2}}=2$.
	}

