		\item  Tính $\displaystyle \lim_{t\to +\infty}P(t)$.
		\item  Giải thích ý nghĩa thực tế của kết quả.
		\item  Cho biết mô hình này cho thấy mức độ ô nhiễm có xu hướng như thế nào về lâu dài?
	\end{enumerate}
\loigiai{
	\begin{enumerate}
		\item Chia cả tử và mẫu cho $t^2$ ta có
		$\displaystyle \lim_{t\to +\infty}
		P(t)=\displaystyle \lim_{t\to +\infty}\dfrac{1\,200+\frac{500}{t}}{1+\frac{50}{t}+\frac{100}{t^2}}=1\,200$.
		\item Điều này cho thấy mức độ ô nhiễm không tăng vô hạn mà tiến dần tới mức ổn định là $1\,200$.
		\item Mô hình cho thấy các biện pháp bảo vệ môi trường giúp kiểm soát ô nhiễm, làm cho chỉ số ô nhiễm ổn định về lâu dài, không tiếp tục tăng không kiểm soát.
	\end{enumerate}
	}

