	{Hàm số liên tục tại mọi điểm trừ các điểm thuộc khoảng $( -3;3 )$}
	{\True Hàm số liên tục tại mọi điểm trừ điểm $x=-3$}
	{Hàm số liên tục tại mọi điểm trừ điểm $x=3$}
\loigiai{
	Ta có
	\begin{itemize}
		\item $\lim\limits_{x\to 3}f(x)=\lim\limits_{x\to 3}\dfrac{2x+6}{3x^2-27}$.\\
		Vì $\lim\limits_{x\to 3}( 2x+6 )=12\ne 0$ và $\lim\limits_{x\to 3}( 3x^2-27 )=0$ nên hàm số không có giới hạn tại $x=3$.
		\item $\lim\limits_{x\to -3}f(x)=\lim\limits_{x\to -3}\dfrac{2x+6}{3x^2-27}=\lim\limits_{x\to -3}\dfrac{2( x+3 )}{3( x-3 )( x+3 )}=\lim\limits_{x\to -3}\dfrac{2}{3( x-3 )}=\dfrac{-1}{9}$.
	\end{itemize}
	Vì $\lim\limits_{x\to -3}f(x)=f( -3 )=-\dfrac{1}{9}$ nên hàm số liên tục tại $x=-3$.}

%[1D3H3-3]
	Cho hàm số $f(x)=\heva{&\dfrac{x+\sqrt{x+2}}{x+1} & \text{khi} & x>-1 \\& 2x+3 &\text{khi} & x\le -1}$. Khẳng định nào sau đây đúng?
	\choice
	{$f(0)=3$}
	{Hàm số liên tục tại $x_0=-1$}
	{Hàm số liên tục tại mọi điểm}
	{\True Hàm số không liên tục tại tại $x_0=-1$}
\loigiai{Ta có
	\begin{itemize}
		\item $f(-1)=1$
		\item $\lim\limits_{x\to(-1)^-}f(x)=\lim\limits_{x\to(-1)^-}( 2x+3 )=1$.
		\item $\lim\limits_{x\to(-1)^+}f(x)=\lim\limits_{x\to(-1)^+}\dfrac{x+\sqrt{x+2}}{x+1}=\lim\limits_{x\to(-1)^+}\dfrac{x^2-x-2}{(x+1)\left( x-\sqrt{x+2}\right)}=\lim\limits_{x\to(-1)^+}\dfrac{x-2}{x-\sqrt{x+2}}=\dfrac{3}{2}$.
	\end{itemize}
	Suy ra $\lim\limits_{x\to(-1)^+}f(x)\ne \lim\limits_{x\to(-1)^-}f(x)$.\\
	Vậy hàm số không liên tục tại $x_0=-1$.}

%[1D3N3-4]
	Hàm số $f(x) = \sqrt{x-1}$ liên tục trên
	\choice
	{\True $(1;2)$}
	{$[0;2]$}
	{$\mathbb{R}$}
	{$(0;+\infty)$}
\loigiai{
	Hàm số $f(x) = \sqrt{x-1}$ là hàm sơ cấp nên liên tục trên tập xác định là $\mathscr{D} = [1;+\infty)$.\\
	Do $(1;2) \subset \mathscr{D}$ nên hàm số $f(x)$ liên tục trên khoảng $(1;2)$.
	}

%[1D3H3-4]
	Cho hàm số $f(x)=\heva{&3x^2+x-2&\text{ nếu } x<1\\&\sqrt{x^2+3x-1}&\text{ nếu } x\ge 1.}$ Khẳng định nào sau đây đúng?
	\choice
	{Hàm số không xác định tại  $x_0=-3$}
	{\True Hàm số liên tục tại  $x_0=-3$}
	{ Hàm số gián đoạn tại  $x_0=-3$}
	{Không có giới hạn $\lim\limits_{x \to -3}f(x)$}
\loigiai{
	Ta có
	\begin{itemize}
		\item $f(1)=\sqrt{3}$.
		\item $\lim\limits_{x\to 1^+}f(x)=\lim\limits_{x\to 1^+}\sqrt{x^2+3x-1}=\sqrt{3}$.
		\item $\lim\limits_{x\to 1^-}f(x)=\lim\limits_{x\to 1^-}(3x^2+x-2)=2$.
		\item Do $\lim\limits_{x\to 1^-}f(x)\ne \lim\limits_{x\to 1^+}f(x)=f(1)$ nên hàm số $f(x)$ không liên tục tại $x_0=1$.
	\end{itemize}
	}

