\loigiai{
	Ta thấy hàm số $y=f(x)$ gián đoạn tại các điểm $x=1$, $x=2$ và $x=3$ nên ta loại các đoạn chứa các điểm đó đi.\\
	Đoạn $[0{,}2;0{,}8]$ là tập con của nửa khoảng $[0;4)$ thoả mãn không chứa các điểm $x=1$, $x=2$, $x=3$.
	}

%[1D3H3-3]
	Cho hàm số $f(x) = \heva{&2x - 2 &\text{khi}\ x \neq 3 \\ &2m &\text{khi}\ x = 3}$ ($m$là tham số). Tìm giá trị thực của tham số $m$ để hàm số đã cho liên tục tại $x_0 = 3$.
	\choice
	{$m = 4$}
	{\True $m = 2$}
	{$m = 3$}
	{$m = 1$}
\loigiai{Tập xác định $\mathscr{D} = \mathbb{R}$. \\
	Ta có $\lim \limits_{x \to 3} f(x) = \lim \limits_{x \to 3}{(2x - 2)} = 4$, $f(3) = 2m$.\\
	Để hàm số liên tục tại $x_0 = 3$ thì $\lim \limits_{x \to 3}{f(x)} = f(3) \Leftrightarrow 4 = 2m \Leftrightarrow m = 2 $.
	}

%[1D3H3-4]
	Hàm số $f(x)=\heva{&ax+5&\text{ khi }x\geq 2\\&5&\text{ khi }x<2}$ liên tục trên $\mathbb{R}$ nếu $a$ bằng
	\choice
	{\True $0$}
	{$3$}
	{$-1$}
	{$7$}
\loigiai{Hàm số đã cho liên tục trên $(2;+\infty)$ và $(-\infty;2)$.\\
	Từ đó suy ra hàm số liên tục trên $\mathbb{R}$ nếu nó liên tục tại $x=2$.\\
	Ta có $\lim\limits_{x\to 2^+}f(x)=\lim\limits_{x\to 2^+}(ax+5)=2a+5$; $\lim\limits_{x\to 2^-}f(x)=\lim\limits_{x\to 2^+}(3x-1)=5$.\\
	Từ đó suy ra hàm số liên tục trên $\mathbb{R}$ nếu $2a+5=5 \Rightarrow a=0$.
	}

%[1D3N3-3]
	Biết rằng trong khoảng $(-4;0)$, phương trình $x^3-12x+1=0$ có đúng $1$ nghiệm. Nghiệm đó thuộc khoảng
	\choice
	{\True $(-4;-3)$}
	{$(-3;-2)$}
	{$(-2;-1)$}
	{$(-1;0)$}
\loigiai{
	Hàm số $f(x)=x^3-12x+1$ là hàm đa thức nên liên tục trên $\mathbb{R}$ và $f(-4)\cdot f(-3) < 0$ nên nghiệm của phương trình $f(x) = 0$ thuộc khoảng $(-4;-3)$.
	}

%[1D3H3-3]
	Phương trình nào dưới đây có nghiệm trong khoảng $\left(0;1\right)$?
	\choice
	{$2x^2-3x+4=0$}
	{$\left(x-1\right)^5-x^7-2=0$}
	{$3x^4-4x^2+5=0$}
	{\True $3x^{2025}-8x+4=0$}
\loigiai{
	Xét hàm số $f(x)=3x^{2025}-8x+4=0$ liên tục trên $\mathbb{R}$.\\
	Ta có $f(0)=4$; $f(1)=-1\Rightarrow f(0)\cdot f(1)=-4<0$.\\
	Vậy phương trình có ít nhất một nghiệm thuộc khoảng $\left(0;1\right)$.
	}

