%[1D3N3-6]
	\immini{
	Hình vẽ bên biểu diễn độ cao của một quả bóng nảy $h$(m) theo thời gian $t$(s). Ta có đồ thị của hàm số $h=-t^2+2t$ trên đoạn $[0;2]$. Nhìn vào hình vẽ, ta suy ra
	\choice
	{\True Hàm số liên tục trên đoạn $[0;2]$}
	{Hàm số gián đoạn tại $x=0$}
	{Hàm số gián đoạn tại $x=1$}
	{Hàm số gián đoạn tại $x=2$}
	}{
	\begin{tikzpicture}[scale=1.2, font=\footnotesize, line join=round, line cap=round, >=stealth]
		\draw[->] (-0.5,0) -- (3,0) node[below] {$t$};
		\draw[->] (0,-0.5) -- (0,2) node[left] {$h$};
		\draw (0,0)node[below left]{$O$} ;
		\clip (-0.5,-0.5)rectangle(3,2);
		\draw[smooth,samples=200,domain=0:2] plot (\x,{-(\x)^2+2*(\x)});
		\draw[fill] (0,0) circle(1pt);
		\draw[dashed] (1,0)node[below]{$1$}--(1,1)--(0,1)node[left]{$1$} (2,0)node[below]{$2$};
	\end{tikzpicture}
	}
\loigiai{
	Nhìn đồ thị, ta thấy $h=h(t)$ liên tục trên $[0;2]$.
	}

%[1D3H3-3]
	Cho hàm số $f(x)=\heva{&\dfrac{x^2-1}{x-1} & \text{ khi } x \neq 1 \\ &x+1 & \text{ khi } x=1}$ và $g(x)=4x^2-x+1$. Xét tính đúng sai của các mệnh đề sau
	\choiceTF[t]
	{\True $f(1)=2$}
	{\True Hàm số $f(x)$ liên tục tại điểm $x_0=1$}
	{\True Hàm số $g(x)$ liên tục tại điểm $x_0=1$}
	{Hàm số $y=f(x)-g(x)$ không liên tục tại điểm $x_0=1$}
\loigiai{
	Ta có $f\left(x_0\right)=f(1)=1+1=2 \Rightarrow \lim\limits_{x \to x_0} f(x) = \lim\limits_{x \to 1} \dfrac{x^2-1}{x-1} = \lim\limits_{x \to 1}(x+1)=2 = f\left(x_0\right)$.\\
	Vậy hàm số liên tục tại điểm $x_0=1$.\\
	Ta có $g\left(x_0\right)=g(1)=4$.\\
	$\lim\limits_{x \to x_0} g(x)=\lim\limits_{x \to 1}\left(4x^2-x+1\right)=4=g(1)$.\\
	Vậy hàm số liên tục tại điểm $x_0=1$.
	\begin{itemchoice}
		\itemch Mệnh đề \lq\lq $f(1)=2$\rq\rq\, đúng.
		\itemch Mệnh đề \lq\lq Hàm số $f(x)$ liên tục tại điểm $x_0=1$\rq\rq\, đúng.
		\itemch Mệnh đề \lq\lq Hàm số $g(x)$ liên tục tại điểm $x_0=1$\rq\rq\, đúng.
		\itemch Mệnh đề \lq\lq Hàm số $y=f(x)-g(x)$ không liên tục tại điểm $x_0=1$\rq\rq\, sai.
	\end{itemchoice}
	}

%[1D3H3-3]
	Cho hàm số $y=f(x)=x^3-x+3$. Xét tính đúng sai của các phát biểu sau
	\choiceTF[t]
	{\True Hàm số $y=f(x)$ liên tục trên $\mathbb{R}$}
	{$f(1)=-3$}
	{$f(0)\cdot f(-2)>0$}
	{\True Phương trình $f(x)=0$ có ít nhất một nghiệm âm}
\loigiai{
	Ta thấy $f(x)$ liên tục trên $\mathbb{R}$.\\
	Lại có $f(0)=3$ và $f(-2)=-3$, suy ra $f(0)\cdot f(-2)<0$.\\
	Vậy phương trình đã cho có ít nhất một nghiệm thuộc khoảng $(-2;0)$.
	\begin{itemchoice}
		\itemch Do hàm số $f(x)=x^3-x+3$ là hàm đa thức nên $f(x)$ liên tục trên $\mathbb{R}$.
		\itemch Ta có $f(1)=3$.
		\itemch Do $f(0)=3$ và $f(-2)=-3$ nên $f(0)\cdot f(-2)<0$.
		\itemch Do phương trình đã cho có ít nhất một nghiệm thuộc khoảng $(-2;0)$ nên có ít nhất một nghiệm âm.
	\end{itemchoice}
	}

%[1D3V3-4]
	Cho hàm số $y=\heva{&\dfrac{x^2-2}{x-\sqrt{2}}&\text{khi } x \neq \sqrt{2}\\
	&2\sqrt{2}&\text{khi } x = \sqrt{2}}$. Xét tính đúng sai của các khẳng định sau
	\choiceTF[t]
	{\True Hàm số liên tục trên khoảng $\left( -\infty;\sqrt{2}\right)$}
	{\True Hàm số liên tục trên khoảng $\left (\sqrt{2};+\infty\right) $}
	{Hàm số gián đoạn tại $x=\sqrt{2}$}
	{\True Hàm số liên tục trên $\mathbb{R}$}
\loigiai{
	Tập xác định $ \mathscr{D}=\mathbb{R} $.
	\begin{itemchoice}
		\itemch Trên khoảng $\left( -\infty;\sqrt{2}\right)$, $f(x)=\dfrac{x^2-2}{x-\sqrt{2}}$ nên hàm số đã cho liên tục trên khoảng $\left( -\infty;\sqrt{2}\right)$.
		\itemch Trên khoảng $\left (\sqrt{2};+\infty\right)$, $f(x)=\dfrac{x^2-2}{x-\sqrt{2}}$ nên hàm số đã cho liên tục trên khoảng $\left (\sqrt{2};+\infty\right)$.
		\itemch Ta có
		\begin{itemize}
			\item $ \lim\limits_{x\to\sqrt{2}}f(x)=\lim\limits_{x\to\sqrt{2}}\dfrac{x^2-2}{x-\sqrt{2}}=\lim\limits_{x\to\sqrt{2}}(x+\sqrt{2})=2\sqrt{2}$.
			\item $f(\sqrt{2}) = 2\sqrt{2}$.
		\end{itemize}
		Do đó $\lim\limits_{x\to\sqrt{2}}f(x)=f(\sqrt{2})$ nên $ f(x) $ liên tục tại $ x=\sqrt{2} $.
		\itemch Ta có
		\begin{itemize}
			\item Hàm số đã cho liên tục trên mỗi khoảng $\left( -\infty;\sqrt{2}\right)$ và $\left (\sqrt{2};+\infty\right) $.
			\item Hàm số đã cho liên tục tại $ x=\sqrt{2} $
		\end{itemize}
		Vậy $ f(x) $ liên tục trên $ \mathbb{R} $.
	\end{itemchoice}
	}

%[1D3V3-3]
	Cho phương trình $ax^2+bx+c=0$, $(a\neq 0)$ thỏa mãn $3a+4b+6c=0$. Đặt $f(x)=ax^2+bx+c$, xét tính đúng sai của các phát biểu sau
	\choiceTF[t]
	{$f(0)>0$}
	{\True Khi $c=0$ thì phương trình có một nghiệm dương}
	{\True Với $c\neq 0$ thì $f(0)\cdot f\left(\dfrac{3}{4}\right)<0$}
	{\True Phương trình đã cho luôn có nghiệm trong khoảng $\left(0;1\right)$}
\loigiai{
	Ta thấy hàm số $f(x)$ liên tục trên $\mathbb{R}$.\\
	Do đó $f(0)=c$ và $f\left(\dfrac{3}{4}\right)=\dfrac{9}{16}a+\dfrac{3}{4}b+c$.\\
	Suy ra $f(0)\cdot f\left(\dfrac{3}{4}\right)=\dfrac{9a+12b+16c}{16}\cdot c=\dfrac{3\cdot (3a+4b+6c)-2c}{16}\cdot c=-\dfrac{c^2}{8}$.
	\begin{itemize}
		\item Với $c=0$ thì $f\left(\dfrac{3}{4}\right)=0$.\\
		Suy ra $f(x)=0$ có nghiệm $x=\dfrac{3}{4}\in\left(0;1\right)$.
		\item Với $c\neq 0\Rightarrow f(0)\cdot f\left(\dfrac{3}{4}\right)<0$.\\
		Hàm số $y=f(x)$ liên tục trên $\left[0;\dfrac{3}{4}\right]\in\mathbb{R}$ nên có ít nhất một nghiệm trong $\left(0;\dfrac{3}{4}\right)$.
	\end{itemize}
	Vậy phương trình đã cho luôn có nghiệm trong khoảng $\left(0;1\right)$.
	\begin{itemchoice}
		\itemch Vì $f(0)=c$.\\
		Do chưa biết dấu của $c$ nên không thể kết luận $f(0)>0$.
		\itemch Với $c=0$ thì $f(x)=0$ có nghiệm $x=\dfrac{3}{4}>0$.
		\itemch Vì với $c\neq 0$ thì $f(0) \cdot f\left(\dfrac{3}{4}\right) =-\dfrac{c^2}{8}<0$.
		\itemch Vì với mọi $a\neq 0$ và $3a+4b+6c=0 \Rightarrow$ phương trình đã cho luôn có nghiệm trong $\left(0;1\right)$.
	\end{itemchoice}
	}

questions.solution:
Ta có
	\begin{align*}
		\lim\limits_{x\to -4}f(x)=\lim\limits_{x\to -4}\dfrac{x^2+x-12}{x+4}=\lim\limits_{x\to -4}\dfrac{(x-3)(x+4)}{x+4}=-7.
	\end{align*}
	Hàm số đã cho liên tục khi và chỉ khi
	\begin{align*}
		\lim\limits_{x\to -4} f(x)=f(-4) \Leftrightarrow -4m+1=-7 \Leftrightarrow m=2.
	\end{align*}
	Vậy $m=2$ là giá trị cần tìm.

questions.rawBody:
%[1D3H3-3]
	Cho hàm số $f(x)=\heva{&\dfrac{x^2+x-12}{x+4} &\text{khi}\ x\ne -4\\ &mx+1 &\text{khi}\ x=-4}$. Giá trị của tham số $m$ để hàm số liên tục tại $x=-4$ bằng
	\par\shortans{$2$}
\loigiai{
	Ta có
	\begin{align*}
		\lim\limits_{x\to -4}f(x)=\lim\limits_{x\to -4}\dfrac{x^2+x-12}{x+4}=\lim\limits_{x\to -4}\dfrac{(x-3)(x+4)}{x+4}=-7.
	\end{align*}
	Hàm số đã cho liên tục khi và chỉ khi
	\begin{align*}
		\lim\limits_{x\to -4} f(x)=f(-4) \Leftrightarrow -4m+1=-7 \Leftrightarrow m=2.
	\end{align*}
	Vậy $m=2$ là giá trị cần tìm.
	}

%[1D3H3-3]
	Tìm $m$ để hàm số $f(x)=\heva{&x^4+x^2-1 & \text { khi } x \leq-1 \\ &3 m+1 & \text { khi } x>-1}$ liên tục tại điểm $x_0=-1$.
	\par\shortans{$0$}
\loigiai{
	Ta có: $f(-1)=(-1)^4+(-1)^2-1=1$;\\
	$\lim\limits_{x\to -1^-}f(x)=\lim\limits_{x\to -1^-}(x^4+x^2-1)=1$;\\
	$\lim\limits_{x\to -1^+}f(x)=\lim\limits_{x\to -1^+}(3 m+1)=3m+1$.\\
	Hàm số liên tục tại $x_0=-1$ khi và chỉ khi $\lim\limits_{x\to -1}f(x)=f(-1) \Leftrightarrow 1=3m+1 \Leftrightarrow m=0$.
	}

%[1D3H3-4]
	Cho hàm số $f(x)=\heva{& \dfrac{x^2-16}{x-4} & \text{khi}\, x>4\\ & mx+1 & \text{khi}\, x\le 4}$. Giá trị của tham số $m$ để hàm số liên tục trên $\mathbb{R}$ bằng
	\par\shortans{$1{,}75$}
\loigiai{
	Hàm số đã cho liên tục trên các khoảng $\left(-\infty;4\right)$, $\left(4;+\infty\right)$.\\
	Vậy hàm số liên tục trên $\mathbb{R}$ khi và chỉ khi liên tục tại điểm $x=4$.\\
	Hàm số liên tục tại điểm $x=4$ khi $\displaystyle\lim_{x\rightarrow 4^+}f(x)=\displaystyle\lim_{x\rightarrow 4^-}f(x)=f(4)\Leftrightarrow 8=4m+1\Leftrightarrow m=\dfrac{7}{4}=1{,}75$.
	}

questions.prompt:
Cho hàm số $f(x)=\heva{
	&\dfrac{3-\sqrt{9-x}}{x} &&khi  0<x\leq 9\\
	&m &&khi  x\leq 0}$. Giá trị của tham số $m$ để hàm số liên tục trên $[0;9]$ bằng (làm tròn đến hàng phần trăm)

questions.rawBody:
%[1D3V3-4]
	Cho hàm số $f(x)=\heva{
	&\dfrac{3-\sqrt{9-x}}{x} &&\text{khi } 0<x\leq 9\\
	&m &&\text{khi } x\leq 0}$. Giá trị của tham số $m$ để hàm số liên tục trên $[0;9]$ bằng (làm tròn đến hàng phần trăm)
	\par\shortans{$0{,}17$}
\loigiai{
	\begin{itemize}
		\item Với $0<x<9$ thì $f(x)=\dfrac{3-\sqrt{9-x}}{x}$ hàm số xác định và liên tục.
		\item $\lim\limits_{x\to {9^-}}f(x)=\lim\limits_{x\to {9^-}}{\dfrac{3-\sqrt{9-x}}{x}}=\dfrac{1}{3}=f(9)$.
		\item Xét tại $x=0$ ta có $f(0)=m=\lim\limits_{x\to {0^-}}f(x)$.\\
		$\lim\limits_{x\to {0^+}}f(x)=\lim\limits_{x\to {0^+}}{\dfrac{3-\sqrt{9-x}}{x}}=\lim\limits_{x\to 0^+}{\dfrac{1}{3+\sqrt{9-x}}}=\dfrac{1}{6}$.
	\end{itemize}
	Để hàm số liên tục trên $[0;9]$ thì $f(0)=\dfrac{1}{6}$ hay $m=\dfrac{1}{6}\approx 0{,}17$.
	}

