	}$ liên tục tại $x=1$. Tính $a^2+b^2$.

questions.rawBody:
%[1D3V3-3]
	Cho $a$ và $b$ là các giá trị để hàm số $f(x)=\heva{
	ax^2+bx+3&\text{ khi }x<1\\
	5&\text{ khi }x=1\\
	2x-3b&\text{ khi }x>1
	}$ liên tục tại $x=1$. Tính $a^2+b^2$.
	\par\shortans{$10$}
\loigiai{
	Ta có
	\begin{itemize}
		\item $f(1)=5$.
		\item $\lim\limits_{x\to 1^{-}}f(x)=\lim\limits_{x\to 1^{-}}(ax^2+bx+3)=a+b+3$.
		\item $\lim\limits_{x\to 1^{+}}f(x)=\lim\limits_{x\to 1^{+}}(2x-3b)=2-3b$.
	\end{itemize}
	Hàm số $f(x)$ liên tục tại $x_0=1$ khi và chỉ khi
	$$\lim\limits_{x\to 1^-} f(x) = \lim\limits_{x\to 1^+}f(x) = f(1) \Leftrightarrow\heva{&a+b+3=5\\&2-3b=5} \Leftrightarrow
	\heva{&a=3\\&b=-1.}$$
	Vậy $a^2+b^2=10$.
	}

%[1D3V3-3]
	Tìm giá trị của tham số $a$ để hàm số $f(x)=\heva{&\dfrac{\sqrt{x}-1}{x-1} & \text { khi } x>1 \\& a x-\dfrac{1}{2} & \text { khi } x \leq 1}$ liên tục tại điểm $x=1$.
	\par\shortans{$1$}
\loigiai{
	Ta có: ${f(1)=a-\dfrac{1}{2}}$ và $\lim\limits_{x\to 1^-}f(x)=\lim\limits_{x\to 1^-}\left(a x-\dfrac{1}{2}\right)=a-\dfrac{1}{2}$;\\
	$\lim\limits_{x\to 1^+} f(x)=\lim\limits_{x\to 1^+} \dfrac{\sqrt{x}-1}{x-1}=\lim\limits_{x\to 1^+} \dfrac{\sqrt{x}-1}{(\sqrt{x}-1)(\sqrt{x}+1)}=\lim\limits_{x\to 1^+}\dfrac{1}{\sqrt{x}+1}=\dfrac{1}{2}$.\\
	Hàm số ${f(x)}$ liên tục tại $x=1$ khi và chỉ khi
	$f(1)=\lim\limits_{x\to 1}f(x) \Leftrightarrow a-\dfrac{1}{2}=\dfrac{1}{2} \Leftrightarrow a=1$.}

