%[1D3H3-3]
	Cho hàm số $f(x)=\heva{& \dfrac{x-1}{\sqrt{2-x}-1}\quad &\text{ nếu }x<1 \\ & -2x\quad &\text{ nếu }x\geq 1}$. Xét tính liên tục của hàm số tại các điểm $x_0=0$, $x_0=2$, $x_0=1$.
\loigiai{
	\begin{itemize}
		\item Ta có $\lim \limits_{x \to 0} f(x)=f(0)=\dfrac{0-1}{\sqrt{2-0}-1}=-\sqrt{2}-1$ nên hàm số liên tục tại $x_0=0$.
		\item Ta có $\lim \limits_{x \to 2} f(x)=f(2)=-2\cdot 2=-4$ nên hàm số liên tục tại $x_0=2$.
		\item Xét tại $x_0=1$, ta có $f(1)=-2$.\\
		$\lim \limits_{x \to 1^-} f(x)=\lim \limits_{x \to 1} \dfrac{x-1}{\sqrt{2-x}-1}=\lim \limits_{x \to 1} \dfrac{(x-1)\left(\sqrt{2-x}+1\right)}{1-x}=-\lim \limits_{x \to 1} \left(\sqrt{2-x}+1\right)=-2$;\\
		$\lim \limits_{x \to 1^+} f(x)=\lim \limits_{x \to 1} \left(-2x\right)=-2$.\\
		Ta thấy $\lim \limits_{x \to 1^+} f(x)=\lim \limits_{x \to 1^-} f(x)\Rightarrow \lim \limits_{x \to 1} f(x)=-2=f(1)$.\\
		Vậy hàm số đã cho liên tục tại $x=1$.
	\end{itemize}
	}

%[1D3V3-4]
	Xét tính liên tục của hàm số $ f(x)=\heva{&\dfrac{2x^3+x+3}{x^3+1} &\text{ khi } x\ne -1\\&\dfrac{7}{3} &\text{ khi } x=-1} $ trên $ \mathbb{R}$.
\loigiai{
	\begin{itemize}
		\item Tập xác định của hàm số $ f(x) $ là $ \mathscr{D}=\mathbb{R} $.
		\item Xét $ x\ne -1 $ thì $ f(x)=\dfrac{2x^3+x+3}{x^3+1} $ là hàm số hữu tỉ nên liên tục trên các khoảng $ (-\infty; -1) $ và $ (-1; +\infty) $ mà nó xác định.\hfill ($1$)
		\item Xét tính liên tục của hàm số $ f(x) $ tại $ x_0=-1 $, ta có
		\begin{itemize}
			\item $ f(-1)=\dfrac{7}{3} $.
			\item $ \lim\limits_{x\to-1}f(x)=\lim\limits_{x\to-1}\dfrac{2x^3+x+3}{x^3+1}=\lim\limits_{x\to-1}\dfrac{(x+1)\left(2x^2-2x+3\right)}{(x+1)\left( x^2-x+1 \right)}=\lim\limits_{x\to-1}\dfrac{2x^2-2x+3}{x^2-x+1}=\dfrac{7}{3} $.
		\end{itemize}
		Suy ra $\lim\limits_{x\to-1}f(x) = f(-1)$ nên hàm số $ f(x) $ liên tục tại $ x=-1 $.\hfill($2$)
	\end{itemize}
	Từ ($1$) và ($2$), suy ra hàm số $ f(x) $ đã cho liên tục trên $ \mathbb{R} $.
	}

%[1D3V3-3]
	Chứng minh rằng phương trình $x^3+mx^2-1=0$ luôn có nghiệm dương với mọi $m \in \mathbb{R}$.
\loigiai{
	\begin{itemize}
		\item Ta có $f(x)=x^3+mx^2-1$ là hàm đa thức và xác định trên $\mathbb{R}$ nên hàm số liên tục trên $\mathbb{R}$.
		\item $f(0)=-1<0$.
		\item $\lim\limits_{x\to +\infty}f(x)=\lim\limits_{x\to +\infty}x^3\left(1+\dfrac{m}{x}-\dfrac{1}{x^2}\right)=+\infty$.\\
		Suy ra tồn tại một số $b>0$ sao cho $f(b)>0$.
		\item Do đó $f(0)\cdot f(b)<0$ suy ra phương trình có ít nhất 1 nghiệm $x\in (0;b)$, hay phương trình luôn có nghiệm dương với mọi giá trị của $m$.
	\end{itemize}
	}

