		\draw (S)--(B)--(C)--(D)--(S)--(C);
		\draw[dashed] (B)--(A)--(D)
		(S)--(A)--(H);
		\tkzMarkRightAngles[size=0.4](A,H,D)
	\end{tikzpicture}
	}
	}

