	Cho hình hộp chữ nhật $ABCD.A'B'C'D'$ có $AA'=a$, $AB=b$, $BC=c$.
	\begin{enumerate}
		\item Tính khoảng cách giữa $CC'$ và $(BB'D'D)$.
		\item Xác định đường vuông góc chung và tính khoảng cách giữa $AC$ và $B'D'$
	\end{enumerate}
\loigiai{
	\begin{center}
