%[1H8H7-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Cường]
	\immini[thm]{Tính thể tích của khối chóp $S.ABCD$. Biết đáy $ABCD$ là hình vuông cạnh $a$, $SA \perp (ABCD)$, góc giữa đường thẳng $SB$ và mặt phẳng $(ABCD)$ bằng $45^\circ$.
	}{
	\begin{tikzpicture}[line join=round, line cap=round,scale=0.7]
		\coordinate (A) at (0,0);
		\coordinate (B) at (-2,-3);
		\coordinate (D) at (7,0);
		\coordinate (C) at ($(B)+(D)-(A)$);
		\coordinate (S) at ($(A)+(0,5)$);
		\draw(S)--(B) (S)--(C) (S)--(D) (B)--(C)--(D);
		\draw[dashed](S)--(A) (A)--(B) (A)--(D);
		\draw pic["$45^\circ$",draw,angle eccentricity=1.3,angle radius=1.4cm]{angle=A--B--S};
		\foreach \i/\g in {S/90,A/-90,B/-90,C/-90,D/0}{\draw[fill=black](\i) circle (1.0pt) ($(\i)+(\g:3mm)$) node[scale=1]{$\i$};}
	\end{tikzpicture}
	}
	\choice
	{$a^3$}
	{\True $\dfrac{a^3}
	{3}$}
	{$\dfrac{a^3\sqrt 2}{9}$}
	{$\dfrac{a^3\sqrt 2}{6}$}
\loigiai{
	Do $SA\perp (ABCD)$ và $BA$ chứa trong $(ABCD)$ nên $SA\perp AB$, suy ra $SA=AB\cdot \tan \widehat{SBA}$.\\
	Vì $SA\perp (ABCD)$ nên góc giữa đường thẳng $SB$ và mặt phẳng $(ABCD)$ bằng $\widehat{SBA}$. Suy ra $\widehat{SBA}=45^\circ$.\\
	Từ đó, ta có $SA=a\cdot \tan 45^\circ=a$.\\
	Mặt khác, do diện tích hình vuông $ABCD$ là $S_{ABCD}=a^2$ nên thể tích khối chóp là
	\[V_{S.ABCD}=\dfrac{1}{3}S_{ABCD}\cdot SA=\dfrac{1}{3}a^2\cdot a=\dfrac{a^3}{3}.\]
	}

