%[1H8H7-4]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Cường]
	\immini[thm]{
	Cho hình lăng trụ đứng $ABC.A'B'C'$ có đáy là tam giác đều cạnh $3a$, đường thẳng $A'B$ tạo với mặt phẳng $(ABC)$ một góc $30^\circ$.
	\choiceTF
	{\True $AA' \perp BC$}
	{\True Diện tích đáy $ABC$ bằng $\dfrac{9a^2\sqrt{3}}{4}$}
	{Chiều cao của hình lăng trụ bằng $\sqrt{3}$}
	{\True Thể tích của khối lăng trụ $ABC.A'B'C'$ bằng $\dfrac{27a^3}{4}$}
	}
	{
	\begin{tikzpicture}[scale=0.8, font=\footnotesize, line join=round, line cap=round, >=stealth]
		\def\a{4}
		\def\h{4}
		\path 	(0:0) coordinate (A)
		++(0:\a) coordinate (C)
		++(-150:3*\a/4) coordinate (B)
		($(A)+(90:\h)$) coordinate (A')
		($(B)+(90:\h)$) coordinate (B')
		($(C)+(90:\h)$) coordinate (C');
		\draw[dashed] 	(A)--(C);
		\draw(C)--(C') 	(B)--(B')	(A)--(A') (A)--(B)--(C)
		(A')--(B')--(C')--cycle (A')--(B);
		\foreach \x/\g in {A/180,B/-45,C/0,A'/90,B'/70,C'/90}
		\fill(\x) circle (1pt)	($(\g:3mm)+(\x)$) node {$\x$};
	\end{tikzpicture}
	}
\loigiai{
	\begin{itemchoice}
		\itemch Cạnh bên lăng trụ đứng thì vuông góc với đáy nên $AA' \perp BC$.
		\itemch $\triangle ABC$ là tam giác đều cạnh $3a$ nên diện tích đáy $ABC$ là $$S_{\triangle ABC}=\dfrac{(3a)^2\sqrt{3}}{4}=\dfrac{9a^2\sqrt{3}}{4}.$$
		\itemch Chiều cao lăng trụ là $AA'$.\\
		Hình chiếu của $A'B$ lên mặt phẳng $(ABC)$ là $AB$, suy ra góc giữa $A'B$ và mặt phẳng $(ABC)$ là $\left(A'B,AB\right)=\widehat{ABA'}=30^\circ$.\\
		Xét $\triangle A'AB$ vuông tại $A$.\\
		Ta có $\tan \widehat{A'BA}=\dfrac{AA'}{AB}\Rightarrow AA'=AB\cdot \tan \widehat{A'BA}=3a\cdot \tan 30^\circ =a\sqrt{3}$.
		\itemch Thể tích khối lăng trụ $ABC.A'B'C'$ là $V=AA'\cdot S_{\triangle ABC}= \dfrac{9a^2\sqrt{3}}{4} \cdot a\sqrt{3} =\dfrac{27a^3}{4}$.
	\end{itemchoice}
	}

