%[1H8H7-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Cường]
	\immini[thm]{
	Cho hình chóp đều $S.ABCD$ có cạnh đáy bằng $a$, gọi $O$ là giao điểm của $AC$ và $BD$, $SO=3a$.
	\choiceTF
	{\True $SO\perp (ABCD)$}
	{\True Góc giữa $SA$ và mặt phẳng $(ABCD)$ bằng $\widehat{SAO}$}
	{Thể tích của khối chóp $S.ABCD$ bằng $3a^3$}
	{\True Hai mặt phẳng $(SAC)$ và $(SBD)$ vuông góc}
	}
	{
	\begin{tikzpicture} [font=\footnotesize, line join=round, line cap=round, >=stealth, scale=1]
		\def\a{4}
		\path (0:0) coordinate (A)
		++(0:\a) coordinate (D)
		++(-135:\a/2) coordinate (C)
		($(A)+(C)-(D)$) coordinate (B)
		(intersection of A--C and B--D) coordinate (O)
		($(O)+(90:\a)$) coordinate (S);
		\draw[dashed] 	(B)--(A)--(D)	(A)--(S)
		(A)--(C)	(B)--(D)	(S)--(O)	;
		\draw	(B)--(C)--(D)	(B)--(S)	(C)--(S)	(D)--(S);
		\foreach \x/\g in {A/180,B/-135,C/-45,D/0,S/90,O/-90}
		\fill (\x) circle (1pt)	($(\g:3mm)+(\x)$) node {$\x$};
		\pic[draw,angle radius=2mm]{right angle=D--O--S};
	\end{tikzpicture}
	}
\loigiai{
	\begin{itemchoice}
		\itemch Vì $S.ABCD$ là hình chóp đều nên $\heva{&OA=OB=OC=OD \\&SA=SB=SC=SD}\Rightarrow SO\perp (ABCD)$.
		\itemch Ta có $SO\perp (ABCD)$ suy ra $OA$ là hình chiếu của $SA$ lên mặt phẳng $(ABCD)$.\\
		Do đó $\widehat{SAO}$ chính là góc giữa $SA$ và mặt phẳng $(ABCD)$.
		\itemch Thể tích khối chóp $S.ABCD$ là $V=\dfrac{1}{3}S_{ABCD}\cdot SO=\dfrac{1}{3}\cdot a^2\cdot 3a=a^3$.
		\itemch Ta có $\heva{&AC\perp BD \text{ \big(vì }ABCD\text{ là hình vuông\big)}\\&SO\perp BD \text{ \big(vì }SO\perp (ABCD)\big)}
		\Rightarrow BD\perp (SAC)$.\\
		Mà $BD\subset (SBD)$ nên $(SBD)\perp (SAC)$.
	\end{itemchoice}
	}

