%[1H8V7-6]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Cường]
	\immini[thm]{Một chụp đèn hình chóp cụt đều (tham khảo hình vẽ) có chiều cao bằng $42$\,cm, đáy là lục giác đều, độ dài cạnh đáy lớn bằng $17$\,cm và độ dài cạnh đáy nhỏ bằng $10$\,cm.
	\choiceTF
	{Khoảng cách giữa hai đáy là $27$\,cm}
	{\True Diện tích đáy bé là $S'=150 \sqrt{3}$ cm$^2$}
	{\True Diện tích đáy lớn là $S=\dfrac{867 \sqrt{3}}{2}$ cm$^2$}
	{Thể tích phần không gian bên trong của chụp đèn bé hơn $20\,000$ cm$^3$}
	}{
	\begin{tikzpicture}[scale=1, font=\footnotesize, line join=round,
		line cap=round, >=stealth]
		\clip (-3.5,0) rectangle (1,3.8);
		\path (0:0) coordinate (F)--++(180:2.5) coordinate (A)--++(150:1) coordinate (B)--++(40:1.2) coordinate (C)--++(0:2.5) coordinate (D)--++(-30:1) coordinate (E)
		($(A)!.5!(D)$) coordinate --++(90:6)coordinate (S)
		\foreach \x in {A,B,C,D,E,F}{($(\x)!.4!(S)$) coordinate (\x')};
		\fill[green!40!gray] (A)--(B)--(B')--(A') (E)--(F)--(F')--(E');
		\fill[green!50!gray] (A')--(A)--(F)--(F');
		\fill[green!10!gray] (A')--(B')--(C')--(D')--(E')--(F');
		\draw[dashed] (B)--(C)--(D)--(E)	(C)--(C') (D)--(D');
		\draw (A')--(B')--(C')--(D')--(E')--(F')--cycle (B)--(A)--(F)--(E)--(E') (A)--(A') (F)--(F') (B)--(B');
	\end{tikzpicture}
	}
\loigiai{
	\begin{itemchoice}
		\itemch Khoảng cách giữa hai đáy là $42$\,cm.
		\itemch Đáy nhỏ là lục giác đều được ghép bởi $6$ tam giác đều có cạnh đều bằng $10$\,cm.
		\begin{center}
			\begin{tikzpicture}[scale=0.7, font=\footnotesize, line join=round,
				line cap=round, >=stealth]
				\path (0:0) coordinate (A)--++(120:2) coordinate (B)--++(60:2) coordinate (C)--++(0:2) coordinate (D)--++(-60:2) coordinate (E)--++(-120:2) coordinate (F);
				\draw (1,-.3) node{$10$\,cm};
				\draw (A)--(B)--(C)--(D)--(E)--(F)--cycle(A)--(D) (B)--(E) (C)--(F);
				\foreach \x/\g in {A/180,B/150,C/0,D/-30,E/180,F/150}
				\fill (\x) circle (1pt);
			\end{tikzpicture}
		\end{center}
		Diện tích đáy nhỏ là $S'=6\cdot \dfrac{\sqrt{3}}{4}\cdot 10^2=150\sqrt{3}$ cm$^2$.
		\itemch Đáy lớn là lục giác đều được ghép bởi $6$ tam giác đều có cạnh đều bằng $17$\,cm.
		\begin{center}
			\begin{tikzpicture}[scale=0.7, font=\footnotesize, line join=round,
				line cap=round, >=stealth]
				\path (0:0) coordinate (A)--++(120:2) coordinate (B)--++(60:2) coordinate (C)--++(0:2) coordinate (D)--++(-60:2) coordinate (E)--++(-120:2) coordinate (F);
				\draw (1,-.3) node{$17$\,cm};
				\draw (A)--(B)--(C)--(D)--(E)--(F)--cycle(A)--(D) (B)--(E) (C)--(F);
				\foreach \x/\g in {A/180,B/150,C/0,D/-30,E/180,F/150}
				\fill (\x) circle (1pt);
			\end{tikzpicture}
		\end{center}
		Diện tích đáy lớn là $S=6\cdot \dfrac{\sqrt{3}}{4}\cdot 17^2=\dfrac{867\sqrt{3}}{2}$ cm$^2$.
		\itemch Thể tích phần không gian bên trong của chụp đèn là
		\begin{align*}
			V&=\dfrac{1}{3}\cdot h\cdot \left( S+S'+\sqrt{S\cdot S'}\right)\\
			&=\dfrac{1}{3}\cdot 42 \cdot \left( \dfrac{867\sqrt{3}}{2}+150\sqrt{3}+\sqrt{\dfrac{867\sqrt{3}}{2}\cdot 150\sqrt{3}}\right)\\
			&=11\,739\sqrt{3}\approx 20\,333\mathrm{\,cm^3}.
		\end{align*}
		Vậy $V>20\,000 \mathrm{\,cm^3}$.
	\end{itemchoice}
	}

%[1H8V7-3]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Cường]
	Cho hình chóp $S.ABC$ có đáy $ABC$ là tam giác đều cạnh $2a$ và cạnh bên $SA$ vuông góc với đáy, với $SA=\dfrac{a}{2}$.
	\choiceTF
	{\True Diện tích đáy $ABC$ của hình chớp $S.ABC$ là $a^2\sqrt{3}$}
	{Thể tích của khối chóp $S.ABC$ bằng $\dfrac{a^3\sqrt{3}}{8}$}
	{Góc tạo bởi mặt phẳng $(SBC)$ và mặt phẳng $(ABC)$ bằng $45^{\circ}$}
	{Gọi $P$, $Q$ lần lượt là trung điểm $SB$, $SC$. Thể tích khối chóp $A.BCQP$ bằng $\dfrac{a^3\sqrt{3}}{12}$}
\loigiai{\begin{center}
	\begin{tikzpicture}[>=stealth,line join=round,line cap=round,font=\footnotesize,scale=0.75]
		\path (0,0) coordinate (A)
		(2,-1.4) coordinate (B)
		(6,0) coordinate (C)
		($(B)!0.5!(C)$) coordinate (H)
		($(A)+(0,5)$)coordinate (S)
		($(S)!0.5!(B)$) coordinate (P)
		($(S)!0.5!(C)$) coordinate (Q)
		($(S)!0.65!(H)$) coordinate (K)
		;
		\draw (H)--(S)--(A)--(B)--(C)--(S)--(B) (A)--(P)--(Q);
		\draw[dashed] (H)--(A)--(C) (K)--(A)--(Q);
		\foreach \p / \r in {A/135,B/-90,C/45,S/90,H/-45,P/45,Q/45,K/45}
		\fill (\p) circle (1pt) node[shift={(\r:2.5mm)}]{$\p$};
		\foreach \p / \r / \t in {A/H/B,S/H/C,H/K/A}
		\pic[draw,angle radius=2mm,angle eccentricity=1.5] {right angle = \p--\r--\t};
	\end{tikzpicture}
	\end{center}
	\begin{itemchoice}
		\itemch Diện tích tam giác $ABC$ là $S_{ABC}=\dfrac{AB^2\sqrt{3}}{4}=\dfrac{4a^2\sqrt{3}}{4}=a^2\sqrt{3}$.
		\itemch Thể tích của khối chóp $S.ABC$ là \[V_{S.ABC}=\dfrac{1}{3}\cdot SA\cdot S_{ABC}=\dfrac{1}{3}\cdot\dfrac{a}{2}\cdot a^2\sqrt{3}=\dfrac{a^3\sqrt{3}}{6}.\]
		\itemch Gọi $H$ là trung điểm của $BC$.\\
		Tam giác $ABC$ đều nên $AH\perp BC$ tại $H$.\\
		Ta có $SA\perp(ABC)$ nên $SA\perp BC$.\\
		Suy ra $BC\perp(SAH)$, do $SH\subset(SAH)$ nên $SH\perp BC$ tại $H$.\\
		Suy ra góc tạo bởi mặt phẳng $(SBC)$ và mặt phẳng $(ABC)$ là $\widehat{SHA}$.\\
		Tam giác $ABC$ có $AH=\dfrac{AB\sqrt{3}}{2}=a\sqrt{3}$.\\
		Tam giác $SAH$ có $\tan\widehat{SHA}=\dfrac{SA}{AH}=\dfrac{\dfrac{a}{2}}{a\sqrt{3}}=\dfrac{\sqrt{3}}{6}$.\\
		Suy ra góc tạo bởi mặt phẳng $(SBC)$ và mặt phẳng $(ABC)$ là $\widehat{SHA}\approx16{,}1^\circ$.
		\itemch Ta có $BC\perp(SAH)$ nên $(SAH)\perp(SBC)$ theo giao tuyến $SH$.\\
		Kẻ $AK\perp SH$ tại $K$ trong mặt phẳng $(SAH)$, suy ra $AK\perp(SBC)$.\\
		Tam giác $SAH$ có $\heva{&SH=\sqrt{SA^2+AH^2}=\sqrt{\left(\dfrac{a}{2}\right)+\left(a\sqrt{3}\right)^2}=\dfrac{a\sqrt{13}}{2};\\&AK=\dfrac{SA\cdot AH}{SH}=\dfrac{\dfrac{a}{2}\cdot a\sqrt{3}}{\dfrac{a\sqrt{13}}{2}}=\dfrac{a\sqrt{39}}{13}.}$\\
		Tam giác $SBC$ có
		\[S_{BCQP}=S_{SBC}-S_{SPQ}=\dfrac{3}{4}S_{SBC}=\dfrac{3}{4}\cdot\dfrac{1}{2}\cdot SH\cdot BC=\dfrac{3}{8}\cdot\dfrac{a\sqrt{13}}{2}\cdot2a=\dfrac{3a^2\sqrt{13}}{8}.\]
		Thể tích của khối chóp $A.BCQP$ là
		\[V_{A.BCQP}=\dfrac{1}{3}\cdot AK\cdot S_{BCQP}=\dfrac{1}{3}\cdot\dfrac{a\sqrt{39}}{13}\cdot\dfrac{3a^2\sqrt{13}}{8}=\dfrac{a^3\sqrt{3}}{8}.\]
	\end{itemchoice}}

