%[1H8V7-9]
	\immini{Một chiếc lồng đèn kéo quân có hình lăng trụ lục giác đều với cạnh đáy $8$ cm. Biết tổng diện tích các mặt bên của chiếc lồng đèn này bằng $1\,536$ cm$^2$. Tính thể tích của chiếc lồng đèn đó, kết quả làm tròn đến hàng đơn vị.}
	{\begin{tikzpicture}[scale=0.7, font=\footnotesize, line join=round, line cap=round, >=stealth]
	\path (0,0)coordinate (O)
	($(O)+(10:2cm and 1cm)$)coordinate (A)
	($(O)+(70:2cm and 1cm)$)coordinate (B)
	($(O)+(130:2cm and 1cm)$)coordinate (C)
	($(O)+(190:2cm and 1cm)$)coordinate (D)
	($(O)+(-50:2cm and 1cm)$)coordinate (F)
	($(O)+(-110:2cm and 1cm)$)coordinate (E)
	($(A)+(0,4)$)coordinate (A')
	($(B)+(0,4)$)coordinate (B')
	($(C)+(0,4)$)coordinate (C')
	($(D)+(0,4)$)coordinate (D')
	($(E)+(0,4)$)coordinate (E')
	($(F)+(0,4)$)coordinate (F')
	;
	\fill[color=blue!20](A)--(F)--(E)--(D)--(D')--(E')--(F')--(A')--(A);
	\draw (A)--(A')(D)--(D')(E)--(E')(F)--(F');
	\draw (D)--(E)--(F)--(A) (A')--(B')--(C')--(D')--(E')--(F')--(A');
	\draw[dashed] (A)--(B)--(C)--(D)(B)--(B')(C)--(C');
	\end{tikzpicture}}
	\shortans{$5321 $}
\loigiai{
	Gọi $h$ là chiều cao của chiếc lồng đèn. \\
	Theo đề $6\cdot 8\cdot h=1\,536\Rightarrow h=32$ cm.\\
	Diện tích mặt đáy của chiếc lồng đèn là $S=6\cdot \dfrac{8^2\sqrt{3}}{4}=96\sqrt{3}$ cm$^2$.\\
	Thể tích của chiếc lồng đèn đó là $V=96\sqrt{3}\cdot 32\approx 5\,321$ cm$^3$.
	}

