questions.rawBody:
%[1H8V7-5]
	Hình bên là hình biểu diễn của khối vật thể có bốn mặt tam giác cân bằng nhau, bốn mặt hình chữ nhật và đáy là hình vuông. Thể tích của khối vật thể đó là bao nhiêu cm$^3$ (\textit{làm tròn kết quả đến hàng đơn vị})?
	\begin{center}
		\begin{tikzpicture}
			\coordinate (S) at (0.6,3,1);
			\coordinate (A) at (0,0,0);
			\coordinate (B) at (0,2,0);
			\coordinate (C) at (3,2,0);
			\coordinate (D) at (3,0,0);
			\coordinate (A1) at (0,0,4);
			\coordinate (B1) at (0,2,4);
			\coordinate (C1) at (3,2,4);
			\coordinate (D1) at (3,0,4);
			\draw[dashed] (D)--(A)--(A1);
			\draw[dashed] (C)--(B)--(B1);
			\draw [dashed] (S)--(B)--(A);
			\draw (A1)--(B1)--(C1)--(D1)--cycle;
			\draw (C1)--(C)--(D)--(D1);
			\draw (B1)--(S)--(C1);
			\draw (S)--(C);
			\node[above right] at ($(S)!0.5!(C)$) {$18$ cm};
			\node[below right] at ($(C)!0.5!(D)$) {$6$ cm};
			\node[below right] at ($(D)!0.5!(D1)$) {$8$ cm};
			\node[below right] at ($(A1)!0.5!(D1)$) {$8$ cm};
		\end{tikzpicture}
	\end{center}
	\shortans{$749$}
\loigiai{
	Khối đã cho được tạo thành từ khối chóp tứ giác đều và khối hộp chữ nhật. \\
	Thể tích khối chóp tứ giác đều là $\dfrac{1}{3}\cdot 8\cdot 8\cdot \sqrt{18^2-{\left(\dfrac{8\sqrt{2}}{2}\right)}^2}=\dfrac{128\sqrt{73}}{3}$ (cm$^3)$ \\
	Thể tích khối hộp chữ nhật là $8\cdot 8\cdot 6=384$ (cm$^3)$. \\
	Thể tích khối đã cho là $\dfrac{128\left(9+\sqrt{73}\right)}{3}\approx 749$ (cm$^3)$
	}

