questions.rawBody:
%[1H8V7-9]
	\immini{Một cái ly nước hình trụ có chiều cao $9~\mathrm{cm}$. Lượng nước trong ly chiếm $\tfrac{2}{3}$ thể tích ly nước. Hoa đặt một viên kim cương hình lập phương vào miệng ly nước thì thấy một đỉnh của viên kim cương chạm vào mặt nước, đồng thời mô hình ly nước và kim cương cùng lấy trục ly nước làm trục đối xứng. Nếu ban đầu Hoa đổ nước đầy ly thì sau khi đặt khối lập phương như trên, lượng nước tràn ra là bao nhiêu $\mathrm{cm}$ khối (làm tròn đến hàng phần chục và bỏ qua độ dày của ly)?
	}{\resizebox{!}{4cm}{\begin{tikzpicture}[line cap=round,line join=round]
	\path
	(0,4.15) coordinate (A) --
	(-1.2,3.4) coordinate (B) --
	(0,2.6) coordinate (C) --
	(1.1,3.5) coordinate (D)
	(-1.2,2.4) coordinate (E) --
	(0,1.5) coordinate (F) --
	(1.1,2.5) coordinate (G)
	($(B)!0.65!(E)$) coordinate (H)
	($(C)!0.7!(F)$) coordinate (I)
	($(D)!0.65!(G)$) coordinate (J)
	($(0,2.1)+(0:0.94 and 0.22)$) coordinate (Rt)
	($(0,2.1)+(180:0.94 and 0.22)$) coordinate (Lt)
	(0:0.85 and 0.3) coordinate (Rd)
	(180:0.85 and 0.3) coordinate (Ld);
	\draw (0,2.1) ellipse (0.94 and 0.22);
	\path[inner color=black!65,outer color=cyan!15,fill opacity=0.85] (0,1.5) ellipse (0.94 and 0.2);
	\path[top color=gray,bottom color=black!80]  (B)--(E)--(F)--(G)--(D);
	\path[left color=cyan!10,right color=gray,fill opacity=0.65]
	(B)--(H)--(I)--(C)--cycle;
	\path[right color=cyan!10,left color=gray,fill opacity=0.65]
	(C)--(I)--(J)--(D)--cycle;
	\path[top color=cyan!15!gray,bottom color=black] (A)--(B)--(C)--(D)--cycle;
	\def\than{(Rt)--(Rd) arc (360:180:0.85 and 0.3)--(Ld)--(Lt)}
	\begin{scope}
		\clip \than;
