%[1D7V1-1]%[KNTT-CS]%[Trần Xuân Hòa]
	Cho $f(x)=\heva{&\dfrac{\sqrt{x^2+1}-1}{x}&\text{khi }x\neq0\\ &0&\text{khi }x=0}$. Tính $f'(0)$.
	\par\shortans[oly]{$0{,}5$}
\loigiai{
	Ta có $\lim\limits_{x\to 0}f(x)=\lim\limits_{x\to 0}\dfrac{\sqrt{x^2+1}-1}{x}=\lim\limits_{x\to 0}\dfrac{x^2}{x\left(\sqrt{x^2+1}+1\right)}=\lim\limits_{x\to 0}\dfrac{x}{\sqrt{x^2+1}+1}=0$ và $f(0)=0$.\\
	Vì $\lim\limits_{x\to 0}f(x)=f(0)=0$ nên hàm số liên tục tại $x=0$.\\
	Ta có
	\begin{eqnarray*}
		f'(0)&=&\lim\limits_{x\to 0}\dfrac{\dfrac{\sqrt{x^2+1}-1}{x}-0}{x-0}\\
		&=&\lim\limits_{x\to 0}\dfrac{\sqrt{x^2+1}-1}{x^2}\\
		&=&\lim\limits_{x\to 0}\dfrac{x^2}{x^2\left(\sqrt{x^2+1}+1\right)}\\
		&=&\lim\limits_{x\to 0}\dfrac{1}{\sqrt{x^2+1}+1}=0{,}5.
	\end{eqnarray*}
	}

%[1D7H1-4]%[KNTT-CS]%[Trần Xuân Hòa]
	Cho biết điện lượng truyền trong dây dẫn theo thời gian biểu thị bởi hàm số $Q(t)=2t^2+t$, trong đó $t$ được tính bằng giây và $Q$ được tính theo Cu-lông. Tính cường độ dòng điện tại thời điểm $t=4$ (s).
	\par\shortans{$17$}
\loigiai{Tại thời điểm $t_0$ ta có \begin{align*}
	\lim\limits_{t\to t_0}\dfrac{Q(t)-Q(t_0)}{t-t_0}&=\lim\limits_{t\to t_0}\dfrac{2t^2+t-\left(2t_0^2+t_0\right)}{t-t_0}\\
	&=\lim\limits_{t-t_0}\dfrac{(t-t_0)\left[2(t+t_0)+1\right]}{t-t_0}\\
	&=\lim\limits_{t\to t_0}2(t+t_0)+1=4t_0+1.
	\end{align*}
	Do đó, $Q'(t_0)=4t_0+1$.\\
	Vậy
	cường độ dòng điện tại thời điểm $t=4$ (s) là $Q'(4)=4\cdot 4+1=17$ (C/s).
	}

%[1D7V1-4]%[KNTT-CS]%[Trần Xuân Hòa]
	Một chất điểm chuyển động theo phương trình $s(t)=\dfrac{1}{3}t^3+t^2-18t+4$, trong đó $t>0$ tính bằng giây, $s(t)$ tính bằng mét. Tính vận tốc (đơn vị m/s) của chất điểm tại thời điểm vật đi được quãng đường $4$ mét.
	\par\shortans[oly]{$30$}
\loigiai{
	\begin{itemize}
		\item Thời điểm chất điểm đi được quãng đường $4$ mét là
		\begin{eqnarray*}
			\dfrac{1}{3}t^3+t^2-18t+4=4&\Leftrightarrow&
			\dfrac{1}{3}t^3+t^2-18t=0\\
			&\Leftrightarrow&\hoac{&t=6&& \text{(nhận)}\\&t=-9&& \text{(loại)}\\&t=0&& \text{(loại).}}
		\end{eqnarray*}
		\item Ta có $s(6)=\dfrac{1}{3}6^3+6^2-18\cdot 6+4=4$.\\
		Vận tốc của chất điểm tại thời điểm vật đi được quãng đường $4$ mét là
		\[v(6)=s'(6)=\lim\limits_{t\to 6}\dfrac{\dfrac{1}{3}t^3+t^2-18t+4-4}{t-6}=\lim\limits_{t\to 6}\dfrac{1}{3}t(t+9)=30\text{ (m/s)}. \]
	\end{itemize}
	}

%[1D7V1-4]%[KNTT-CS]%[Trần Xuân Hòa]
	Một vật được phóng theo phương thẳng đứng lên trên từ mặt đất, biết độ cao $h$ của nó (tính bằng mét) sau $t$ giây được cho bởi phương trình $h(t)=24{,}5t-4{,}9t^2$. Tìm vận tốc của vật khi nó chạm đất.
	\par\shortans{$24{,}5$}
\loigiai{Ta có \begin{align*}
	\lim\limits_{t\to t_0}\dfrac{h(t)-h(t_0)}{t-t_0}&=\lim\limits_{t\to t_0}\dfrac{24{,5}t-4{,}9t^2-\left(24{,}5t_0-4{,}9t_0^2\right)}{t-t_0}\\
	&=\lim\limits_{t\to t_0}\dfrac{(t-t_0)\left[24{,}5-4{,}9(t+t_0)\right]}{t-t_0}\\
	&=\lim\limits_{t\to t_0}\left[24{,}5-4{,}9(t+t_0)\right]\\
	&=24{,}5-9{,}8t_0.
	\end{align*}
	Do đó vận tốc của vật tại thời điểm $t_0$ là $v(t_0)=h'(t_0)=24{,}5-9{,}8t_0$.\\
	Khi vật chạm đất thì $h=0 \Leftrightarrow 24{,}5t-4{,}9t^2=0 \Rightarrow t=5$.\\
	Vậy tốc độ của vật tại thời điểm nó chạm đất $t=5$ là $$\left|v(5)\right|=\left|h'(5)\right|=|24{,}5-9{,}8\cdot 5|=24{,}5\  (\mathrm{m}/\mathrm{s}).$$
	}

questions.solution:
Ta có
	\begin{eqnarray*}
		&f'(1)=\lim\limits_{x\to 1}\dfrac{f(x)-f(1)}{x-1}&=\lim\limits_{x\to 1}\dfrac{\sqrt{x+1}-\sqrt{2}}{x-1}\\
		&&=\lim\limits_{x\to 1}\dfrac{x-1}{x-1\left(\sqrt{x+1}+\sqrt{2}\right)}\\
		&&=\lim\limits_{x\to 1}\dfrac{1}{\sqrt{x+1}+\sqrt{2}}=\dfrac{1}{2\sqrt{2}}.
	\end{eqnarray*}

questions.rawBody:
%[1D7H1-1]%[KNTT-CS]%[Trần Xuân Hòa]
	Tính đạo hàm của hàm số $f(x)=\sqrt{x+1}$ tại $x=1$.
\loigiai{
	Ta có
	\begin{eqnarray*}
		&f'(1)=\lim\limits_{x\to 1}\dfrac{f(x)-f(1)}{x-1}&=\lim\limits_{x\to 1}\dfrac{\sqrt{x+1}-\sqrt{2}}{x-1}\\
		&&=\lim\limits_{x\to 1}\dfrac{x-1}{x-1\left(\sqrt{x+1}+\sqrt{2}\right)}\\
		&&=\lim\limits_{x\to 1}\dfrac{1}{\sqrt{x+1}+\sqrt{2}}=\dfrac{1}{2\sqrt{2}}.
	\end{eqnarray*}
	}

%[1D7H1-1]%[KNTT-CS]%[Trần Xuân Hòa]
	Tính đạo hàm của hàm số $f(x)=\heva{&x^2-3x&\text{khi }x\neq 1\\&-2&\text{khi }x=1}$ tại $x=1$.
\loigiai{
	Ta có $\heva{&\lim\limits_{x\to 1}f(x)=\lim\limits_{x\to 1}\left(x^2-3x\right)=-2\\&f(1)=-2}\Rightarrow$ Hàm số liên tục tại $x=1$.\\
	Khi đó $f'(1)=\lim\limits_{x\to 1}\dfrac{f(x)-f(1)}{x-1}=\lim\limits_{x\to 1}\dfrac{x^2-3x+2}{x-1}=\lim\limits_{x\to 1}\dfrac{(x-1)(x-2)}{x-1}=\lim\limits_{x\to 1}(x-2)=-1$.
	}

%[1D7V1-4]%[KNTT-CS]%[Trần Xuân Hòa]
	Một chất điểm chuyển động theo phương trình $s(t)=-5t^2+20t+4$, trong đó $t>0$, $t$ được tính bằng giây (s) và $s(t)$ được tính bằng mét (m). Tính vận tốc (đơn vị m/s) của chất điểm tại thời điểm $t=1$ giây.
\loigiai{
	Ta có $s(1)=-5\cdot 1^2+20\cdot 1+4=19$ (m).\\
	Vận tốc của vật tại thời điểm $t=1$ giây là
	\begin{eqnarray*}
		&v(1)=s'(1)&=\lim\limits_{t\to 1}\dfrac{s(t)-s(1)}{t-1}\\
		&&=\lim\limits_{t\to 1}\dfrac{-5t^2+20t+4-19}{t-1}\\
		&&=\lim\limits_{t\to 1}\dfrac{-5(t-1)(t-3)}{t-1}\\
		&&=\lim\limits_{t\to 1}-5(t-3)=10\text{ (m/s)}.
	\end{eqnarray*}
	}

%[1D7V1-5]%[KNTT-CS]%[Trần Xuân Hòa]
	Giả sử chi phí $C$ (USD) để sản xuất $Q$ máy vô tuyến là $C(Q)=Q^2+80Q+3\,500$.
	\begin{enumerate}
		\item Ta gọi chi phí biên là chi phí gia tăng để sản xuất thêm $1$ sản phẩm từ $Q$ sản phẩm lên $Q+1$ sản phẩm. Giả sử chi phí biên được xác định bởi hàm số $C'(Q)$. Tìm hàm chi phí biên.
		\item Tìm $C'(90)$ và giải thích ý nghĩa kết quả tìm được.
		\item Hãy tính chi phí sản xuất máy vô tuyến thứ $100$.
	\end{enumerate}
\loigiai{
	\begin{enumerate}
		\item Hàm chi phí biên để sản xuất thêm $1$ sản phẩm từ $Q_0$ sản phẩm là
		\begin{eqnarray*}
			C'(Q_0)&=&\lim\limits_{Q\to Q_0}\dfrac{C(Q)-C(Q_0)}{Q-Q_0}\\
			&=&\lim\limits_{Q\to Q_0}\dfrac{Q^2+80Q+3\,500-{Q_0}^2-80Q_0-3\,500}{Q-Q_0}\\
			&=&\lim\limits_{Q\to Q_0}\dfrac{(Q-Q_0)(Q+Q_0+80)}{Q-Q_0}\\
			&=&\lim\limits_{Q\to Q_0}(Q+Q_0+80)\\
			&=&2Q_0+80.
		\end{eqnarray*}
		\item Ta có $C'(90)=2\cdot 90+80=260$.\\
		Dựa vào kết quả trên, ta thấy chi phí gia tăng để sản xuất thêm $1$ sản phẩm từ $90$ lên $91$ sản phẩm là $260$ (USD).
		\item Chi phí sản xuất máy vô tuyến thứ $100$ là
		\begin{eqnarray*}
			C(100)-C(99)&=&100^2+80\cdot 100+3\,500-\left(99^2+80\cdot 99+3\,500\right)\\
			&=&279 \text{ (USD)}.
		\end{eqnarray*}
	\end{enumerate}
	}

%[1D7C1-4]%[KNTT-CS]%[Trần Xuân Hòa]
	Một chất điểm chuyển động theo phương trình $s=s(t)=-\dfrac{1}{2}t^3+9t^2$, trong đó $t$ được tính bằng giây và $s$ được tính bằng mét. Tìm thời điểm để vận tốc của chất điểm đạt giá trị lớn nhất.
\loigiai{
	Vận tốc tại thời điểm $t_0$ là
	\begin{eqnarray*}
		v(t_0)=s'(t_0)=\lim\limits_{t\to t_0}\dfrac{s(t)-s(t_0)}{t-t_0}&=&\lim\limits_{t\to t_0}\dfrac{-\dfrac{1}{2}t^3+9t^2+\dfrac{1}{2}{t_0}^3-9{t_0}^2}{t-t_0}\\
		&=&\lim\limits_{t\to t_0}\dfrac{(t-t_0)\left[9(t+t_0)-\dfrac{1}{2}\left(t^2+tt_0+{t_0}^2\right)\right]}{t-t_0}\\
		&=&\lim\limits_{t\to t_0}\left[9(t+t_0)-\dfrac{1}{2}\left(t^2+tt_0+{t_0}^2\right)\right]\\
		&=&18t_0-\dfrac{3}{2}{t_0}^2\text{ (m/s)}.
	\end{eqnarray*}
	Ta có $18t_0-\dfrac{3}{2}{t_0}^2=-\dfrac{3}{2}(t-6)^2+54\leq 54$.\\
	Vậy vận tốc đạt giá trị lớn nhất bằng $54$ khi $t-6=0\Leftrightarrow t=6$.
	}

%[2D1N1-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Cho hàm số $y=f(x)$ có đạo hàm trên $\mathbb{R}$ thoả mãn $f'(x)<0$, $\forall x \in(1;2)$ và $f'(x)>0$, $\forall x \in(2; 3)$. Phát biểu nào sau đây là đúng?
	\choice
	{Hàm số $f(x)$ đồng biến trên cả hai khoảng $(1;2)$ và $(2;3)$}
	{Hàm số $f(x)$ nghịch biến trên cả hai khoảng $(1;2)$ và $(2;3)$}
	{Hàm số $f(x)$ đồng biến trên khoảng $(1;2)$ và nghịch biến trên khoảng $(2;3)$}
	{\True Hàm số $f(x)$ nghịch biến trên khoảng $(1;2)$ và đồng biến trên khoảng $(2; 3)$}
\loigiai{Vì $f'(x)<0$, $\forall x \in(1;2)$ nên hàm số $f(x)$ nghịch biến trên khoảng $(1;2)$.\\
	Vì $f'(x)>0$, $\forall x \in(2; 3)$ nên hàm số $f(x)$ đồng biến trên khoảng $(2;3)$.
	}

%[2D1N1-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Hàm số nào dưới đây đồng biến trên $\mathbb{R}$?
	\choice
	{$y=x^2+2x+3$}
	{\True $y=x^3+x+1$}
	{$y=-x^3-3x$}
	{$y=\dfrac{x+1}{x+3}$}
\loigiai{
	Xét hàm số $y=x^3+x+1$ có $y'=3x^2+1 \ge 0,\forall x \in \mathbb{R}$.\\
	Do đó hàm số đã cho đồng biến trên $\mathbb{R}$.}

%[2D1N1-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Hàm số $y=\dfrac{x-7}{x+4}$ đồng biến trên khoảng
	\choice
	{$(-\infty;+\infty)$}
	{$(-6;0)$}
	{\True $(1;4)$}
	{$(-5;1)$}
\loigiai{Tập xác định $\mathscr{D}=\mathbb{R} \setminus \left\{-4\right\}$.\\
	Ta có $y'=\dfrac{11}{(x+4)^2} > 0$, $\forall x\in \mathscr{D}$.\\
	Vậy hàm số đồng biến trên các khoảng $(-\infty;-4)$ và $(-4;+\infty)$ và đồng biến trên $(1;4)$.}

%[2D1N1-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Hàm số $y = \dfrac{2x+3}{x+1}$ có bao nhiêu điểm cực trị?
	\choice
	{$3$}
	{$2$}
	{\True $0$}
	{$1$}
\loigiai{
	Tập xác định $\mathscr{D} = \mathbb{R} \setminus \{-1\}$. Đạo hàm $y'=\dfrac{-1}{(x+1)^2} <0$, $\forall x \neq -1$.\\
	Khi đó hàm số luôn nghịch biến trên từng khoảng xác định.\\
	Vậy hàm số đã cho không có cực trị.
	}

