%[2D1N2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Cho hàm số $y=f(x)$ có bảng biến thiên như hình dưới đây.
	\begin{center}
		\begin{tikzpicture}
			\tkzTabInit[lgt=1.2,espcl=3,deltacl=.5]
			{$x$/0.7, $f'(x)$/0.7, $f(x)$/2}
			{$-\infty$,$-\tfrac{1}{2}$,$3$,$+\infty$}
			\tkzTabLine{,+,d,+,$0$,-,}
			\tkzTabVar{-/$-\infty$ ,+D-/$+\infty$/$-\infty$ ,+/$4$,-/$-\infty$}
		\end{tikzpicture}
	\end{center}
	\choiceTF
	{Hàm số đã cho có $2$ điểm cực đại là $x=3$ và $x=-\dfrac{1}{2}$}
	{Hàm số đã cho đồng biến trên khoảng $(-\infty;3)$}
	{\True Hàm số đã cho nghịch biến trên khoảng $(3;+\infty)$}
	{\True Hàm số đã cho có giá trị cực đại $y=4$}
\loigiai{
	\begin{itemchoice}
		\itemch Từ bảng biến thiên, suy ra hàm số có một điểm cực đại là $x=3$.
		\itemch Từ bảng biến thiên, suy ra hàm số đồng biến trên các khoảng $\left(-\infty;-\dfrac{1}{2}\right)$ và $\left(-\dfrac{1}{2};3\right)$.
		\itemch Từ bảng biến thiên, suy ra hàm số nghịch biến trên khoảng $(3;+\infty)$.
		\itemch Từ bảng biến thiên, suy ra hàm số có giá trị cực đại $y=4$.
	\end{itemchoice}
	}

%[2D1H2-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Cho hàm số $y=\dfrac{x^2-2x+2}{x-1}$.
	\choiceTF
	{Đạo hàm của hàm số đã cho là $y'=\dfrac{x^2-2x}{x+1}$}
	{\True Giá trị cực đại của hàm số bằng $-2$}
	{Điểm cực tiểu của hàm số bằng $0$}
	{\True Đường thẳng đi qua hai điểm cực trị của đồ thị hàm số đã cho có phương trình là $y=2x-2$}
\loigiai{
	\begin{itemchoice}
		\itemch
		Ta có
		$$ y'=\dfrac{(2x-2)(x-1)-\left(x^2-2x+2\right)}{(x-1)^2}=\dfrac{2x^2-4x+2-x^2+2 x-2}{(x-1)^2}=\dfrac{x^2-2 x}{(x-1)^2}.$$
		\itemch
		Tập xác định $\mathscr{D}=\mathbb{R} \setminus \{1\}$.\\
		Ta có $y'=\dfrac{x^2-2x}{(x-1)^2}$, cho $y'=0 \Leftrightarrow x^2-2x=0 \Leftrightarrow\hoac{&x=0 \\& x=2.}$\\
		Bảng biến thiên
		\begin{center}
			\begin{tikzpicture}
				\tkzTabInit[lgt=1.2,espcl=3]
				{$x$/0.75,$y'$/0.75,$y$/2}
				{$-\infty$,$0$,$1$,$2$,$+\infty$}
				\tkzTabLine{ ,+,0,-,d,-,0,+, }
				\tkzTabVar{-/$-\infty$,+/$-2$,-D+/$-\infty$/$+\infty$,-/$2$,+/$+\infty$}
			\end{tikzpicture}
		\end{center}
		Từ bảng biến thiên ta thấy giá trị cực đại của hàm số bằng $-2$.
		\itemch
		Từ bảng biến thiên ta thấy điểm cực tiểu của hàm số bằng $2$.
		\itemch
		Đồ thị hàm số $y=\dfrac{x^2-2x+2}{x-1}$ có hai điểm cực trị lần lượt là $A(0 ;-2)$, $B(2;2)$.\\
		Phương trình đường thẳng đi qua hai điểm $A$, $B$ là $\dfrac{x-0}{2-0}=\dfrac{y+2}{2+2} \Leftrightarrow y=2x-2$.
	\end{itemchoice}
	}

%[2D1V1-5]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Xét một chất điểm chuyển động dọc theo trục $Ox$. Toạ độ của chất điểm tại thời điểm $t$ được xác định bởi hàm số $x(t)=t^3-6t^2+9t$ với $t \leq 0$. Khi đó $x'(t)$ là vận tốc của chất điểm tại thời điểm $t$, kí hiệu $v(t)$; $v'(t)$ là gia tốc chuyển động của chất điểm tại thời điểm $t$, kí hiệu $a(t)$.
	\choiceTF
	{Phương trình hàm vận tốc là $v(t) = 3t^2-6t+9$}
	{\True Phương trình hàm gia tốc là $a(t)=6t-12$}
	{\True Vận tốc của chất điểm tăng khi $t \in (0;1)\cup (3;+\infty)$}
	{\True Vận tốc của chất điểm giảm khi $t \in (1;3)$}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có $v(t) = x'(t) = 3t^2-12t+9$.
		\itemch Ta có $a(t) = v'(t) = 6t-12$.
		\itemch Xét $v(t)=0 \Leftrightarrow \hoac{&t=1\\&t=3.}$\\
		Bảng xét dấu
		\begin{center}
			\begin{tikzpicture}[>=stealth, scale=1]
				\tkzTabInit[lgt=2,espcl=2.7]
				{$t$/0.8,$v(t)$/0.8}
				{$0$,$1$,$3$,$+\infty$}
				\tkzTabLine{,+,0,-,0,+,}
			\end{tikzpicture}
		\end{center}
		Suy ra vận tốc của chất điểm tăng khi $t \in (0;1) \cup (3;+\infty)$.
		\itemch Vận tốc của chất điểm giảm khi $t \in (1;3)$.
	\end{itemchoice}
	}

%[2D1V1-5]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Trong $25$ phút theo dõi, lưu lượng nước của một con sông được tính theo công thức
	$$
	Q(t)=-\dfrac{t^3}{10}+5 t^2+50.
	$$
	Trong đó $Q$ tính theo $\mathrm{m}^3/$ phút, $t$ tính theo phút, $0 \leq t \leq 25$. Khi lưu lượng nước của con sông lên đến $500$ m$^3$/phút thì cảnh báo lũ được đưa ra.
	\choiceTF
	{\True Lưu lượng nước sông lúc bắt đầu theo dõi là $50 \mathrm{~m}^3 /$ phút}
	{Cảnh báo lũ được đưa ra trước thời điểm $t=10$ phút}
	{Trong khoảng thời gian $10$ phút đầu tiên, không có thời điểm nào mà tốc độ tăng của lưu lượng nước sông bằng $40 \mathrm{~m}^3/(\text{phút})^2$}
	{\True Trong khoảng thời gian từ phút thứ $10$ đến phút thứ $15$, lưu lượng nước sông trung bình mỗi phút tăng $77{,}5 \mathrm{~m}^3/$ phút}
\loigiai{
	\begin{itemchoice}
		\itemch
		Khi $t = 0$, ta có
		$$
		Q(0) = -\dfrac{0^3}{10} + 5 \cdot 0^2 + 50 = 50 \mathrm{~m}^3/\text{phút}.
		$$
		\itemch
		Xét hàm số $Q(t)=-\dfrac{t^3}{10}+5 t^2+50$, có $Q'(t)=-\dfrac{3t^2}{10}+10t$.\\
		Cho $Q'(t)=0\Leftrightarrow \hoac{&t=0 & (\text{nhận vì } t\in \left[0;25\right])\\&t=\dfrac{100}{3}&(\text{loại vì } t\in \left[0;25\right]).}$\\
		Bảng biến thiên
		\begin{center}
			\begin{tikzpicture}[scale=1, font=\footnotesize, line join=round, line cap=round, >=stealth]
				\tkzTabInit[nocadre=false,lgt=1.25,espcl=2,deltacl=0.75]
				{$t$/.7 ,$Q'(t)$/.7,$Q(t)$/2}
				{$0$,$ $ , $25$}
				\draw[dashed,->](3,-.57)node[above] {$10$}--(3,-2.75)node[below] {$450$};
				\tkzTabLine{ ,  , + , , }
				\draw[->] (2,-3.13)node[left] {$50$} -- (5.5,-1.75)node[right] {$1612{,}5$};
			\end{tikzpicture}
		\end{center}
		Dựa vào bảng biến thiên, $10$ phút đầu tiên lưu lượng nước chưa đạt mức cảnh báo là $500$ m$^3$/phút.
		\itemch
		\begin{itemize}
			\item Hàm tốc độ thay đổi của lưu lượng nước là đạo hàm của $Q(t)$, ta có
			$$
			Q'(t) = -\dfrac{3t^2}{10} + 10t, \mathrm{~m}^3/(\text{phút})^2.
			$$
			\item Giải phương trình $Q'(t) = 40$ ta có
			$$
			-\dfrac{3t^2}{10} + 10t = 40 \Leftrightarrow
			-3t^2 + 100t - 400 = 0 \Leftrightarrow \hoac{&t \approx 28{,}68 &(\text{loại vì } t \leq 25)\\&t\approx 4{,}65 &(\text{nhận vì } 0\leq t \leq 25).}
			$$
			\item Nhận thấy $t \approx 4{,}65$ thuộc khoảng $10$ phút đầu, nên tồn tại thời điểm trong $10$ phút đầu mà $Q'(t) = 40$  m$^3$/phút.
		\end{itemize}
		\itemch
		\begin{itemize}
			\item Tính lưu lượng tại $t = 10$ và $t = 15$, ta có\\
			$
			Q(10) = -\dfrac{1000}{10} + 5 \cdot 100 + 50 = -100 + 500 + 50 = 450 \mathrm{~m}^3/\text{phút}.
			$\\
			$
			Q(15) = -\dfrac{3375}{10} + 5 \cdot225 + 50 = -337{,}5 + 1125 + 50 = 837{,}5$ m$^3$/phút.
			\item Lưu lượng trung bình $Q_{\text{trung bình}}$ trong khoảng $t$ từ $10$ đến $15$:
			$$
			Q_{\text{trung bình}} = \dfrac{Q(15) - Q(10)}{15 - 10} = \dfrac{837{,}5 - 450}{5} = \dfrac{387{,}5}{5} = 77{,}5 \mathrm{~m}^3/\text{phút}.
			$$
		\end{itemize}
	\end{itemchoice}
	}

