	Cho hàm số $y=f(x)$ có đạo hàm trên $\mathbb{R}$ thỏa mãn $f'(x)=x^2-5x-6, \forall x\in \mathbb{R}$. Biết rằng hàm số đã cho nghịch biến trên khoảng $(a;b)$, với $a$, $b\in \mathbb{Z}$. Tính $a+b$.
	\par
	\shortans{$5$}
\loigiai{
	Ta có $f'(x)=0\Leftrightarrow x^2-5x-6=0\Leftrightarrow \hoac{&x=-1\\&x=6.}$\\
	Bảng xét dấu $f'(x)$
	\begin{center}
		\begin{tikzpicture}
			\tkzTabInit[lgt=1.2, espcl=3, deltacl=0.5]
