%[2D1V2-7]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	\immini[thm]{
	Khi chất thải hữu cơ được đổ vào một cái ao, quá trình ôxy hóa xảy ra sẽ làm giảm hàm lượng ôxy trong nước. Tuy nhiên, theo thời gian, tự nhiên sẽ phục hồi lại mức ôxy về giá trị bình thường. Trong đồ thị kèm theo, $P(t)$ cho biết phần trăm hàm lượng ôxy (so với mức bình thường) sau $t$ ngày kể từ khi chất thải được đổ vào ao.
	Giả sử hàm số cho hàm lượng ôxy là $$P(t)=100\cdot\dfrac{t^2+10t+100}{t^2+20t+100}, \,\forall t \geq 0.$$}{
	\begin{tikzpicture}[line join = round, line cap = round,>=stealth,font=\footnotesize,yscale=1/35,xscale=1/25]
		\def\xmin{-10} \def\xmax{100}
		\def\ymin{-10} \def\ymax{130}
		\def\f(#1){100*(((#1)^2+10*(#1)+100)/((#1)^2+20*(#1)+100))}
		\def\xp{10}
		\pgfmathsetmacro{\yp}{\f(\xp)}
		\foreach \x in {} \draw (\x,2pt)--(\x,-2pt) node [below] {$\x$};
		\draw[-stealth] (\xmin,0)--(\xmax,0)node[below]{$t\,\left(\text{ngày}\right)$};
		\foreach \y in {75,100} \draw (2,\y)--(-2,\y) node [left] {$\y$};
		\draw[-stealth] (0,\ymin)--(0,\ymax)node[left]{$y\,\left(\%\right)$};
		\filldraw (0,0)node[below left]{$O$} circle (1.5pt);
		\clip (\xmin,\ymin) rectangle (\xmax,\ymax);
		\draw[samples=100,domain=0:100,smooth,thick] plot (\x,{\f(\x)});
		\draw[samples=100,domain=0:100,smooth,dashed] plot (\x,{100});
		\fill (\xp,\yp)node[below]{$P$} circle (1.5);
	\end{tikzpicture}
	}
	Khi đó tọa độ của điểm $P(a;b)$ trên đồ thị là điểm cực trị của đồ thị hàm số $P(t)$. Tính $a+b$.
\loigiai{
	Ta có $P'(t)=\dfrac{(2t+10)\left(t^2+20t+100\right)-(2t+20)\left(t^2+10t+100\right)}{\left(t^2+20t+100\right)^2}$.\\
	Khi đó \allowdisplaybreaks
	\begin{eqnarray*}
		&&P'(t)=0\\
		&\Leftrightarrow&(2t+10)\left(t^2+20t+100\right)-(2t+20)\left(t^2+10t+100\right)=0\\
		&\Rightarrow& 10t^2-1000=0\\
		&\Rightarrow& t^2=100\\
		&\Rightarrow& t=10 \quad (t \geqslant 0).
	\end{eqnarray*}
	Lập bảng biến thiên
	\begin{center}
		\begin{tikzpicture}
			\tkzTabInit[lgt=1.5,espcl=3,deltacl=1] {$x$ /1.2, $P’(x)$ /1.2,$P(x)$/2.5} {$0$,$10$,$+\infty$}
			\tkzTabLine{ ,-,0,+, }
			\tkzTabVar{+/$100$,-/$75$,+/$100$}
		\end{tikzpicture}
	\end{center}
	Ta có $t=10$ là điểm cực tiểu của hàm số.\\
	Khi đó, $P(10)=100\dfrac{10^2+10\cdot 10+100}{10^2+20\cdot 10+100}=75$.\\
	Vậy điểm $P$ có tọa độ $(10; 75)$.
	}

questions.solution:
Ta có $h(t)=2\cos \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)+5 \Rightarrow h'(t) = -\dfrac{\pi}{6} \sin \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)$.\\
	Xét $h'(t)=0 \Leftrightarrow \sin \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)=0 \Leftrightarrow \dfrac{\pi t}{12}+\dfrac{\pi}{3}=k\pi \Leftrightarrow t=-4+12k$ ($k \in \mathbb{Z}$).\\
	Mà $0 \leq t \leq 24$ nên $0 \leq -4 + 12k \leq 24 \Leftrightarrow \dfrac{1}{3} \leq k \leq \dfrac{7}{3}$.\\
	Vì $k\in \mathbb{Z}$ nên $\hoac{&k=1 \Rightarrow t=8\\&k=2 \Rightarrow t=20.}$\\
	Do đó $h'(t)=0 \Rightarrow \hoac{&t=8 \\ &t=20.}$
	\begin{tikzpicture}
			\tkzTabInit[nocadre=true ,lgt=1.2,espcl=2.5]
			{$t$/0.7, $h'(t)$/0.7, $h(t)$/2}
			{$0$, $8$, $20$, $24$}
			\tkzTabLine{,-,z,+,z,-,}
			\tkzTabVar{+/$6$, -/$3$, +/$7$, -/$6$}
		\end{tikzpicture}
	Từ bảng biến thiên, ta thấy hàm số đồng biến trên khoảng $(8;20)$.\\
	Vậy độ sâu của mực nước trong kênh tăng dần trong khoảng từ $8$ giờ đến $20$ giờ.

