%[2D1C1-5]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[GV Nguyễn Đức Tuấn Anh]
	Hằng ngày mực nước của một con kênh lên xuống theo thuỷ triều. Độ sâu $h$ (m) của mực nước trong kênh tại thời điểm $t$ (giờ) $(0 \leq t \leq 24)$ trong ngày được xác định bởi công thức $h=2\cos\left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)+5$. Tìm khoảng thời gian trong ngày mà độ sâu của mực nước trong kênh tăng dần.
\loigiai{
	Ta có $h(t)=2\cos \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)+5 \Rightarrow h'(t) = -\dfrac{\pi}{6} \sin \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)$.\\
	Xét $h'(t)=0 \Leftrightarrow \sin \left(\dfrac{\pi t}{12}+\dfrac{\pi}{3}\right)=0 \Leftrightarrow \dfrac{\pi t}{12}+\dfrac{\pi}{3}=k\pi \Leftrightarrow t=-4+12k$ ($k \in \mathbb{Z}$).\\
	Mà $0 \leq t \leq 24$ nên $0 \leq -4 + 12k \leq 24 \Leftrightarrow \dfrac{1}{3} \leq k \leq \dfrac{7}{3}$.\\
	Vì $k\in \mathbb{Z}$ nên $\hoac{&k=1 \Rightarrow t=8\\&k=2 \Rightarrow t=20.}$\\
	Do đó $h'(t)=0 \Rightarrow \hoac{&t=8 \\ &t=20.}$
	\begin{center}
		\begin{tikzpicture}
			\tkzTabInit[nocadre=true ,lgt=1.2,espcl=2.5]
			{$t$/0.7, $h'(t)$/0.7, $h(t)$/2}
			{$0$, $8$, $20$, $24$}
			\tkzTabLine{,-,z,+,z,-,}
			\tkzTabVar{+/$6$, -/$3$, +/$7$, -/$6$}
		\end{tikzpicture}
	\end{center}
	Từ bảng biến thiên, ta thấy hàm số đồng biến trên khoảng $(8;20)$.\\
	Vậy độ sâu của mực nước trong kênh tăng dần trong khoảng từ $8$ giờ đến $20$ giờ.
	}

 %[2D3N2-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Cho mẫu số liệu ghép nhóm gồm $k$ nhóm, trong đó giá trị đại diện của nhóm thứ $i$ là $x_i$ và tần số tương ứng là $n_i$ ($i = 1, \ldots, k$). Gọi $n = n_1 + n_2 + \ldots + n_k$ là tổng số số liệu. Công thức tính số trung bình $\overline{x}$ của mẫu số liệu ghép nhóm là
	\choice
	{\True $\overline{x} = \dfrac{n_1 x_1 + n_2 x_2 + \ldots + n_k x_k}
	{n}$}
	{$\overline{x} = \dfrac{x_1 + x_2 + \ldots + x_k}
	{k}$}
	{$\overline{x} = \dfrac{n_1 x_1 + n_2 x_2 + \ldots + n_k x_k}{k}$}
	{$\overline{x} = \dfrac{x_1 + x_2 + \ldots + x_k}{n}$}
\loigiai{
	Số trung bình của mẫu số liệu ghép nhóm được tính bằng tổng tích của giá trị đại diện và tần số tương ứng, sau đó chia cho tổng số số liệu.
	}

 %[2D3N2-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Trong thống kê, phương sai của mẫu số liệu được dùng để đo
	\choice
	{Giá trị lớn nhất của mẫu số liệu}
	{Giá trị trung tâm của mẫu số liệu}
	{\True Mức độ phân tán của mẫu số liệu xung quanh số trung bình}
	{Tổng giá trị của mẫu số liệu}
\loigiai{
	Phương sai và độ lệch chuẩn là các số đặc trưng đo mức độ phân tán của mẫu số liệu.
	}

 %[2D3N2-2]
	Một mẫu số liệu có phương sai $s^2 = 25$. Độ lệch chuẩn $s$ của mẫu số liệu đó bằng
	\choice
	{$s = 625$}
	{$s = 12{,}5$}
	{\True $s = 5$}
	{$s = 50$}
\loigiai{
	Ta có $s = \sqrt{s^2} = \sqrt{25} = 5$.
	}

 %[2D3N2-1]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Khi so sánh hai mẫu số liệu về cùng một tiêu chí, mẫu số liệu nào có phương sai nhỏ hơn thì
	\choice
	{Mẫu số liệu đó có mức độ phân tán lớn hơn}
	{\True Mẫu số liệu đó có độ ổn định cao hơn (ít phân tán hơn)}
	{Mẫu số liệu đó có giá trị trung bình lớn hơn}
	{Mẫu số liệu đó có giá trị trung bình nhỏ hơn}
\loigiai{
	Phương sai càng nhỏ thì các giá trị trong mẫu số liệu càng tập trung gần số trung bình, biểu thị độ ổn định cao.
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Người ta ghi lại tiền lãi (đơn vị: triệu đồng) của $25$ nhà đầu tư vào lĩnh vực $A$ thu được mẫu số liệu ghép nhóm sau
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|c|}
			\hline
			Tiền lãi & $[5; 10)$ & $[10; 15)$ & $[15; 20)$ & $[20; 25)$ & $[25; 30)$ \\
			\hline
			Số nhà đầu tư & $2$ & $5$ & $8$ & $6$ & $4$ \\
			\hline
		\end{tabular}
	\end{center}
	Số trung bình $\overline{x}$ của mẫu số liệu trên là
	\choice
	{$17{,}5$}
	{\True $18{,}5$}
	{$16{,}9$}
	{$20{,}0$}
\loigiai{
	Các giá trị đại diện lần lượt là: $7{,}5$; $12{,}5$; $17{,}5$; $22{,}5$; $27{,}5$.\\
	Số trung bình là $\overline{x} = \dfrac{2 \cdot 7{,}5 + 5 \cdot 12{,}5 + 8 \cdot 17{,}5 + 6 \cdot 22{,}5 + 4 \cdot 27{,}5}{25} = \dfrac{462{,}5}{25} = 18{,}5$.
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Thành tích môn nhảy cao của $20$ vận động viên được ghi lại như sau
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|}
			\hline
			Mức xà (cm) & $[170; 172)$ & $[172; 174)$ & $[174; 176)$ & $[176; 180)$ \\
			\hline
			Số vận động viên & $3$ & $10$ & $6$ & $1$ \\
			\hline
		\end{tabular}
	\end{center}
	Phương sai $s^2$ của mẫu số liệu ghép nhóm này là
	\choice
	{$s^2 = 1{,}66$}
	{\True $s^2 = 2{,}7475$}
	{$s^2 = 3{,}1525$}
	{$s^2 = 2{,}1025$}
\loigiai{
	Bảng giá trị đại diện của các nhóm:
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|}
			\hline
			Mức xà (cm) & $[170; 172)$ & $[172; 174)$ & $[174; 176)$ & $[176; 180)$ \\
			\hline
			Giá trị đại diện $x_i$ & $171$ & $173$ & $175$ & $178$ \\
			\hline
			Số vận động viên $n_i$ & $3$ & $10$ & $6$ & $1$ \\
			\hline
		\end{tabular}
	\end{center}
	Số trung bình của mẫu số liệu là
	$$\overline{x} = \dfrac{3 \cdot 171 + 10 \cdot 173 + 6 \cdot 175 + 1 \cdot 178}{20} = 173{,}55.$$
	Phương sai của mẫu số liệu là
	$$s^2 = \dfrac{3 \cdot (171 - 173{,}55)^2 + 10 \cdot (173 - 173{,}55)^2 + 6 \cdot (175 - 173{,}55)^2 + 1 \cdot (178 - 173{,}55)^2}{20} = 2{,}7475.$$
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Ghi lại tiền lãi của một số nhà đầu tư khi đầu tư vào hai lĩnh vực $A$ và $B$, ta thu được kết quả lĩnh vực $A$ có số trung bình $\overline{x}_A = 18{,}5$ và độ lệch chuẩn $s_A \approx 5{,}83$; lĩnh vực $B$ có số trung bình $\overline{x}_B = 16{,}9$ và độ lệch chuẩn $s_B \approx 8{,}04$. Phát biểu nào sau đây là đúng về mức độ rủi ro?
	\choice
	{Đầu tư vào lĩnh vực $B$ ít rủi ro hơn vì có độ lệch chuẩn lớn hơn}
	{\True Đầu tư vào lĩnh vực $A$ ít rủi ro hơn vì có độ lệch chuẩn nhỏ hơn}
	{Hai lĩnh vực có mức độ rủi ro như nhau vì cùng số nhà đầu tư}
	{Đầu tư vào lĩnh vực $B$ đem lại lợi nhuận cao và ổn định hơn}
\loigiai{
	Lĩnh vực $A$ có số trung bình cao hơn và độ lệch chuẩn nhỏ hơn lĩnh vực $B$.\\ Do $s_A < s_B$, mức độ phân tán của tiền lãi lĩnh vực $A$ thấp hơn, do đó đầu tư vào lĩnh vực $A$ ít rủi ro và ổn định hơn.
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Để khảo sát doanh thu của $40$ chi nhánh của một hệ thống cửa hàng tiện lợi trong một tháng, người ta thu được bảng số liệu ghép nhóm sau (đơn vị: triệu đồng)
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|}
			\hline
			Doanh thu & $[100; 200)$ & $[200; 300)$ & $[300; 400)$ & $[400; 500)$ \\
			\hline
			Số chi nhánh & $5$ & $12$ & $15$ & $8$ \\
			\hline
		\end{tabular}
	\end{center}
	Số doanh thu trung bình của mỗi chi nhánh trong tháng đó là
	\choice
	{$325$ triệu đồng}
	{\True $315$ triệu đồng}
	{$310$ triệu đồng}
	{$320$ triệu đồng}
\loigiai{
	Xác định giá trị đại diện $x_i$ của các nhóm là
	$x_1 = 150$; $x_2 = 250$; $x_3 = 350$; $x_4 = 450$.\\
	Tổng số chi nhánh $n = 5 + 12 + 15 + 8 = 40$.\\
	Số doanh thu trung bình là
	$$\overline{x} = \dfrac{5 \cdot 150 + 12 \cdot 250 + 15 \cdot 350 + 8 \cdot 450}{40} = 315 \text{ (triệu đồng)}.$$
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Kết quả kiểm tra môn Toán của $50$ học sinh lớp 12A được trình bày ở bảng sau
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|}
			\hline
			Điểm số & $[5; 6)$ & $[6; 7)$ & $[7; 8)$ & $[8; 9)$ \\
			\hline
			Số học sinh & $5$ & $15$ & $20$ & $10$ \\
			\hline
		\end{tabular}
	\end{center}
	Biết số điểm trung bình của cả lớp là $\overline{x} = 7{,}2$. Phương sai $s^2$ của mẫu số liệu ghép nhóm trên là
	\choice
	{\True $0{,}81$}
	{$0{,}90$}
	{$0{,}75$}
	{$0{,}64$}
\loigiai{
	Giá trị đại diện các nhóm lần lượt là $x_1 = 5{,}5$; $x_2 = 6{,}5$; $x_3 = 7{,}5$; $x_4 = 8{,}5$.\\
	Phương sai của mẫu số liệu là
	$$s^2 = \dfrac{1}{50} \left[ 5 \cdot (5{,}5 - 7{,}2)^2 + 15 \cdot (6{,}5 - 7{,}2)^2 + 20 \cdot (7{,}5 - 7{,}2)^2 + 10 \cdot (8{,}5 - 7{,}2)^2 \right]$$
	$$s^2 = \dfrac{5 \cdot (-1{,}7)^2 + 15 \cdot (-0{,}7)^2 + 20 \cdot 0{,}3^2 + 10 \cdot 1{,}3^2}{50}$$
	$$s^2 = \dfrac{14{,}45 + 7{,}35 + 1{,}8 + 16{,}9}{50} = \dfrac{40{,}5}{50} = 0{,}81.$$
	}

 %[2D3H2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Cân nặng của $30$ trẻ sơ sinh tại một bệnh viện phụ sản được ghi lại theo bảng sau (đơn vị: kg)
	\begin{center}
		\begin{tabular}{|c|c|c|c|c|}
			\hline
			Cân nặng & $[2{,}5; 3{,}0)$ & $[3{,}0; 3{,}5)$ & $[3{,}5; 4{,}0)$ & $[4{,}0; 4{,}5)$ \\
			\hline
			Số trẻ & $6$ & $14$ & $8$ & $2$ \\
			\hline
		\end{tabular}
	\end{center}
