			\hline Sồ lần chạy của $B$ & $3$ & $7$ & $9$ & $6$ \\
			\hline
		\end{tabular}
	\end{center}
	\begin{itemize}
		\item Thời gian chạy trung bình củ vận động viên $A$ là $$\overline{x}_A=\dfrac{1}{20}(2\cdot10{,}15+10\cdot10,45+5\cdot10{,}75+3\cdot11{,}05)=10{,}585$$
		\item Độ lệch chuẩn của vận động viên $A$. $$s_A=\sqrt{\dfrac{1}{20}\left(2\cdot10{,}15^2+10\cdot10{,}45^2+5\cdot10{,}75^2+3\cdot11{,}05^2\right)-10{,}585^2}=0{,}25937.$$
		\item Thời gian chạy trung bình của vận động viên $B$ là $$\overline{x}_A=\dfrac{1}{25}\cdot(3\cdot10{,}15+7\cdot10{,}45+9\cdot10{,}75+6\cdot11{,}05)=10{,}666.$$
		\item Độ lệch chuẩn của vận động viên $B$. $$s_A=\sqrt{\dfrac{1}{25}\cdot\left(3\cdot10{,}15^2+7\cdot10{,}45^2+9\cdot10{,}75^2+6\cdot11{,}05^2\right)-10{,}666^2}=0{,}288.$$
	\end{itemize}
	Vậy độ viên $B$ có thành tích ổn định hơn.
	}

%[2D3V2-2]%[Biên soạn tài liệu dạy học bộ KNTT-CS]%[Nguyễn Hữu Cường]
	Hàm lượng protein (trong 100 g) của một số loại thực phẩm được cho trong bảng sau
	\begin{center}
		\begin{tabular}{|l|c|c|c|c|c|c|}
			\hline \hline
			\textbf{Hàm lượng protein (gam)} & $[8; 10)$ & $ [10; 12)$ & $ [12; 14)$ & $ [14; 16)$ & $ [16; 18]$ & $[18;20]$   \\
			\hline
			\textbf{Tần số }&$4$ & $12$ & $16$ & $14$ & $2$ & $2$ \\
			\hline \hline
		\end{tabular}
	\end{center}
	\begin{enumEX}{1}
		\item Tìm khoảng biến thiên, khoảng tứ phân vị và độ lệch chuẩn của mẫu số liệu (\textit{làm tròn kết quả đến hàng phần trăm}).
		\item Nêu ý nghĩa của các kết quả tìm được.
	\end{enumEX}
\loigiai{
	Cỡ mẫu $N= 4+ 12+ 16+ 14+ 2 + 2= 50$.
	\begin{center}
		\begin{tabular}{|l|c|c|c|c|c|c|}
			\hline \hline
			\textbf{Hàm lượng protein (gam)} & $[8; 10)$ & $ [10; 12)$ & $ [12; 14)$ & $ [14; 16)$ & $ [16; 18]$ & $[18;20]$   \\
			\hline
			\textbf{Tần số }&$4$ & $12$ & $16$ & $14$ & $2$ & $2$ \\ \hline
			\textbf{Tần số tích lũy}&$4$ & $16$ & $32$ & $46$ & $48$ & $50$ \\
			\hline \hline
		\end{tabular}
	\end{center}
	\begin{enumEX}{1}
		\item Khoảng biến thiên là $20-8=12$.\\
		Do $\dfrac{N}{4}= 12{,}5$, nên nhóm chứa $Q_1$ là nhóm $[10; 12)$.\\
		Suy ra $Q_1= 10 + \dfrac{12{,}5- 4}{12} \cdot 2\approx 11{,} 42$.\\
		Do $\dfrac{3N}{4}= 37{,}5$, nên nhóm chứa $Q_3$ là nhóm $[14; 16)$.\\
		Khi đó $Q_3 =14 +\dfrac{37{,}5- 32 }{14} \cdot 2 \approx 14{,} 79$.\\
		Suy ra khoảng tứ phân vị $\Delta_Q = Q_3 - Q_1\approx  3{,} 37$.
		\begin{center}
			\begin{tabular}{|l|c|c|c|c|c|c|}
				\hline \hline
				\textbf{Hàm lượng protein (gam)} & $[8; 10)$ & $ [10; 12)$ & $ [12; 14)$ & $ [14; 16)$ & $ [16; 18]$ & $[18;20]$   \\
				\hline
				\textbf{Giá trị đại diện}&$9$ & $11$ & $13$ & $15$ & $17$ & $19$ \\ \hline
				\textbf{Tần số }&$4$ & $12$ & $16$ & $14$ & $2$ & $2$ \\
				\hline \hline
			\end{tabular}
		\end{center}
		Hàm lượng protein trung bình là $$\overline{x}=\dfrac{9 \cdot 4 + 11 \cdot 12 + 13 \cdot 16 + 15 \cdot 14 + 17 \cdot 12 + 19 \cdot 2 }{50}= 13{,} 16 \text{ gam}.$$
		Phương sai $$s=\sqrt{\dfrac{9^2 \cdot 4 + 11^2 \cdot 12 + 13^2 \cdot 16 + 15^2 \cdot 14 + 17^2 \cdot 12 + 19^2 \cdot 2 }{50} - 13{,} 16^2}\approx 2{,} 33 \text{ gam}. $$
		\item Nêu ý nghĩa của các kết quả tìm được.	\\
		Ta có $25\%$ loại thực phẩm (khoảng $12$ loại) có hàm lượng protein không vượt quá $11{,} 42$ gam và $25\%$ loại thực phẩm có hàm lượng protein đạt ít nhất $14{,} 79$ gam. Đồng thời có $50\%$ loại thực phẩm còn lại có hàm lượng protein từ $11{,} 42$ gam đến $14{,} 79$ gam và hàm lượng protein của các loại thực phẩm này chênh lệch nhau khoảng $3{,} 37$ gam.\\
		Hàm lượng protein trung bình của $50$ loại thực phẩm là $13{,} 16$ gam và do $s \approx 2{,} 33$ gam nên so với số này thì hàm lượng protein của mỗi loại thực phẩm chênh lệch khoảng $2{,} 33$ gam.
	\end{enumEX}}

