			\begin{tabular}{|c|c|}
				\hline
				Điểm & Số học viên (tần số) \\
				\hline
				$[50;60)$ & $8$ \\
				\hline
				$[60;70)$ & $20$ \\
				\hline
				$[70;80)$ & $50$ \\
				\hline
				$[80;90)$ & $17$ \\
				\hline
				$[90;100)$ & $5$ \\
				\hline
			\end{tabular}
		\end{center}
		\begin{center}
			Bảng B. Điểm của lớp B
			\begin{tabular}{|c|c|}
				\hline
				Điểm & Số học viên (tần số) \\
				\hline
				$[50;60)$ & $15$ \\
				\hline
				$[60;70)$ & $20$ \\
				\hline
				$[70;80)$ & $30$ \\
				\hline
				$[80;90)$ & $20$ \\
				\hline
				$[90;100)$ & $15$ \\
				\hline
			\end{tabular}
		\end{center}
	\end{multicols}
	\begin{enumerate}
		\item Tìm khoảng biến thiên của mỗi mẫu số liệu. Có thể dùng khoảng biến thiên để biết điểm của lớp nào đồng đều hơn không?
		\item Tìm các tứ phân vị và khoảng tứ phân vị của mỗi mẫu số liệu.
		\item Mẫu số liệu nào có độ phân tán lớn hơn? Minh hoạ câu trả lời bằng cách biểu diễn các tứ phân vị và khoảng tứ phân vị của mỗi mẫu số liệu trên trục số.
	\end{enumerate}
\loigiai{
	\begin{enumerate}
		\item Hai mẫu số liệu đều có khoảng biến thiên là $R=100-50=50$ nên không thể căn cứ vào đó để nói điểm của lớp nào đồng đều hơn.
		\item Kích thước của hai mẫu số liệu đều là $n=100$.\\ Ta có $\dfrac{n}{4}=25$; $\dfrac{n}{2}=50$; $\dfrac{3n}{4}=75$.\\
		Đối với mẫu số liệu về điểm của lớp $A$, ta tìm các tứ phân vị $Q_{1}^{A}$, $Q_{2}^{A}$, $Q_{3}^{A}$ và khoảng tứ phân vị $\Delta_{Q}^{A}$ qua bảng tần số tích luỹ dưới đây:
		\immini{Nhóm chứa $Q_{1}^{A}$ là $[60;70)$.\\ $Q_{1}^{A}=60+\dfrac{25-8}{20}\cdot10=68{,}5$.\\
		Nhóm chứa $Q_{2}^{A}$ là $[70;80)$.\\ $Q_{2}^{A}=70+\dfrac{50-28}{50}\cdot10=74{,}4$.\\
		Nhóm chứa $Q_{3}^{A}$ là $[70;80)$.\\ $Q_{3}^{A}=70+\dfrac{75-28}{50}\cdot10=79{,}4$.\\
		Vậy $\Delta_{Q}^{A}=Q_{3}^{A}-Q_{1}^{A}=79{,}4-68{,}5=10{,}9$.}{
		\begin{tabular}{|c|c|c|}
			\hline
			Điểm & Tần số & Tần số tích luỹ \\
			\hline
			$[50;60)$ & $8$ & $8$ \\
			\hline
			$[60;70)$ & $20$ & $28$ \\
			\hline
			$[70;80)$ & $50$ & $78$ \\
			\hline
			$[80;90)$ & $17$ & $95$ \\
			\hline
			$[90;100)$ & $5$ & $100$ \\
			\hline
		\end{tabular}
		}
		Gọi $Q_{1}^{B}$, $Q_{2}^{B}$, $Q_{3}^{B}$ là các tứ phân vị và $\Delta_{Q}^{B}$ là khoảng tứ phân vị của mẫu số liệu về điểm của lớp $B$. Ta lập bảng tần số tích luỹ và tính được:
		\immini{Nhóm chứa $Q_{1}^{B}$ là $[60;70)$.\\ $Q_{1}^{B}=60+\dfrac{25-15}{20}\cdot10=65$.\\
		Nhóm chứa $Q_{2}^{B}$ là $[70;80)$.\\ $Q_{2}^{B}=70+\dfrac{50-35}{30}\cdot10=75$.\\
		Nhóm chứa $Q_{3}^{B}$ là $[80;90)$.\\ $Q_{3}^{B}=80+\dfrac{75-65}{20}\cdot10=85$.}{
		\begin{tabular}{|c|c|c|}
			\hline
			Điểm & Tần số & Tần số tích luỹ \\
			\hline
			$[50;60)$ & $15$ & $15$ \\
			\hline
			$[60;70)$ & $20$ & $35$ \\
			\hline
			$[70;80)$ & $30$ & $65$ \\
			\hline
			$[80;90)$ & $20$ & $85$ \\
			\hline
			$[90;100)$ & $15$ & $100$ \\
			\hline
		\end{tabular}}
		Vậy $\Delta_{Q}^{B}=Q_{3}^{B}-Q_{1}^{B}=85-65=20$.
		\item $\Delta_{Q}^{B}> \Delta_{Q}^{A}$ nên điểm của lớp $B$ phân tán hơn điểm của lớp $A$. Minh hoạ trên trục số: Mỗi mẫu đều có $100$ số liệu thuộc khoảng $[50;100)$. Có $50\%$ số liệu ở giữa của bảng điểm lớp $B$ thuộc khoảng $\left(Q_{1}^{B},Q_{3}^{B}\right)$. Bảng điểm lớp $A$ cũng có $50\%$ số liệu ở giữa thuộc khoảng $\left(Q_{1}^{A},Q_{3}^{A}\right)$. Vì $\left(Q_{1}^{A},Q_{3}^{A}\right)\subset\left(Q_{1}^{B},Q_{3}^{B}\right)$ nên ta có thể nói là điểm của lớp $B$ phân tán hơn so với điểm lớp $A$.
		\begin{center}
			\begin{tikzpicture}[
				xscale=0.2, % Điều chỉnh tỉ lệ trục x để hình rộng hơn
				dot/.style={circle, fill, inner sep=1.3pt}, % Định nghĩa style cho các điểm dữ liệu
				font=\small % Sử dụng font chữ nhỏ hơn một chút
				]
				% --- Dữ liệu lớp A (phía trên) ---
				\def\yA{2} % Tọa độ y cho đường của lớp A
				% Vẽ trục số
				\draw (50, \yA) -- (100, \yA);
				% Vẽ các điểm và nhãn trên trục
				\foreach \x/\label in {50/50, 60/60, 65/65, 85/85, 90/90, 100/100} {
				\node[dot, label=above:{\label}] at (\x, \yA) {};
				}
				% Các điểm đặc biệt cho lớp A
				\node[dot, label=above:{$68{,}5$}] at (68.5, \yA) {};
