%[2H5H3-2]
	Trong không gian $Oxyz$, cho mặt cầu $(S)\colon \left(x-2\right)^2+y^2+\left(z+1\right)^2=1$ và mặt phẳng $(P)\colon  x+2y-z+1=0$. Các mệnh đề sau đúng hay sai?
	\choiceTF
	{Khoảng cách từ tâm $I$ đến mặt phẳng $(P)$ bằng $\dfrac{\sqrt{6}}{3}$}
	{\True Mặt cầu $(S)$ có tâm $I\left(2;0;-1\right)$ và bán kính $R=1$}
	{Mặt phẳng $(P)$ tiếp xúc mặt cầu $(S)$}
	{\True Phương trình mặt cầu tâm $I\left(2;0;-1\right)$ và tiếp xúc mặt phẳng $(P)$ là $\left(S'\right)\colon x^2+y^2+z^2-4x+2z+\dfrac{7}{3}=0$}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có
		$\mathrm{d}\left(I,(P)\right)=\dfrac{\left|2+1+1\right|}{\sqrt{1+4+1}}=\dfrac{2\sqrt{6}}{3}$.
		\itemch Mặt cầu $(S)\colon \left(x-2\right)^2+y^2+\left(z+1\right)^2=1$ có tâm $I\left(2;0;-1\right)$ và bán kính $R=1$.
		\itemch Vì $\mathrm{d}\left(I,(P)\right)=\dfrac{2\sqrt{6}}{3} > R$ nên $(P)$ không cắt mặt cầu $(S)$.
		\itemch Phương trình mặt cầu cần tìm có bán kính $R=\mathrm{d}\left(I,(P)\right)=\dfrac{2\sqrt{6}}{3}$, tâm $I\left(2;0;-1\right)$ nên có phương trình
		\[\left(x-2\right)^2+y^2+\left(z+1\right)^2=\left(\dfrac{2\sqrt{6}}{3} \right)^2 \Leftrightarrow x^2+y^2+z^2-4x+2z+\dfrac{7}{3}=0.\]
	\end{itemchoice}
	}

%[2H5H3-2]
	Trong hệ trục $Oxyz$, cho mặt cầu $(S)$ có phương trình $x^2+y^2+z^2-6x+6y+4z-67=0$. Xét tính đúng-sai của các khẳng định sau:
	\choiceTF
	{\True  Tâm của mặt cầu ${(S)}$ là điểm $I(3;-3;-2)$}
	{Bán kính của mặt cầu ${(S)}$ là $R=89$}
	{\True  Điểm $M(-6;-5;-2)$ nằm trong mặt cầu $(S)$}
	{\True  Mặt phẳng $(P)\colon 3x - 2y + 3z + 5=0$ cắt mặt cầu $(S)$ theo một đường tròn có bán kính bằng $\dfrac{\sqrt{9691}}{11}$}
\loigiai{
	\begin{itemchoice}
		\itemch Tâm của mặt cầu ${(S)}$ là điểm $I(3;-3;-2)$.
		\itemch Bán kính của mặt cầu ${(S)}$ là $R=\sqrt{89}$.
		\itemch Ta có $IM=\sqrt{81+4+0}= \sqrt{85}<\sqrt{89}$.
		Suy ra điểm $M(-6;-5;-2)$ nằm trong mặt cầu ${(S)}$.
		\itemch ${(S)}$ có tâm $I(3;-3;-2)$ và bán kính $R = \sqrt{89}$.
		Khoảng cách từ tâm ${I}$ đến mặt phẳng $(P)$:
		$d(I,(P))=\dfrac{|3 \cdot 3 + (-2)\cdot(-3) + 3\cdot(-2) + 5|}{\sqrt{9+4+9}} = \dfrac{7 \sqrt{22}}{11}<\sqrt{89}$
		Mặt phẳng $(P)\colon 3x - 2y + 3z + 5 = 0$ cắt mặt cầu ${(S)}$ theo một đường tròn có bán kính bằng $r=\sqrt{R^2-d^2} = \sqrt{89-\dfrac{98}{11}} = \dfrac{\sqrt{9691}}{11}$.
	\end{itemchoice}
	}

