questions.rawBody:
%[2H5V3-4]
	\immini{Ngọn hải đăng Kê Gà (Bình Thuận) cao $65$ (m) (tính từ mực nước biển) có thể được nhìn thấy từ khoảng cách $26$ km. Chọn hệ trục tọa độ $Oxyz$ trong không gian có tâm $O$ là đỉnh của ngọn hai đăng và đơn vị trên mỗi trục là $1$ km. Một chiếc khinh khí cầu bay trên một đường thẳng đi qua hai điểm  $M(7;38;12)$ đến $N(-13;-242;-68)$.
	}{\begin{tikzpicture}[scale=1,font=\footnotesize, line join=round, line cap=round, >=stealth,scale=.85]
	\path(5.05,1.5) coordinate (O)
	(2,4)coordinate (M)
	--	(8,2)coordinate (N)
	;
	\draw[name path= mn] (M)--(N);
	\path[name path= c](O)circle (2);
	\path[name intersections={of=mn and c}] (intersection-1) coordinate (D)(intersection-2) coordinate (E)
	;
	\draw
	(2,0)--(4,0)--(4.5,0.5)--(5.5,0.5)--(6,0)
	(4.7,0.5) --(4.7,1.2)
	(5.4,0.5) --(5.4,1.2)
	(4.7,1.2)--(4.8,1.2)--(4.8,1.5)
	(5.4,1.2)--(5.3,1.2)--(5.3,1.5)--(4.8,1.5)
	(E)--(O)--(D)
	;
	%\draw (0,-0.5) node[]{$\backsim$};
	\path ($(O)+(0,-1.5)$) coordinate (A);
	\foreach \p/\r in {		O/-90,M/180,N/0,D/90,E/90		}
	\fill (\p) circle (1.2pt) node[shift={(\r:3mm)}]{$\p$};
	\clip
	(3,2)rectangle+(4.5,3)
	;
	\draw[dashed] (O)circle (2)	;
	\end{tikzpicture}	}
	\choiceTF
	{Khinh khí cầu chuyển động trên đường thẳng  có phương trình là $\heva{&x=7+t\\&y=38+14t\\&z=4+4t}$ }
	{Tọa độ điểm cuối cùng  mà người trên khinh khí cầu còn có thể nhìn thấy ngọn hải đăng là $D(6;24;8)$ }
	{\True Khoảng cách từ điểm đầu tiên đến điểm cuối cùng nhìn thấy khinh khí cầu là $51$ km (làm tròn đến hàng đơn vị theo đơn vị km)}
	{Nếu thời  gian di chuyển  của khinh khí cầu từ $M$ đến $N$ là $12$ giờ thì thời gian từ lúc người trên khinh khí cầu nhìn thấy ngọn hải đăng đến lúc không nhìn thấy là $3$  (làm tròn đến hàng đơn vị theo đơn vị giờ)}
\loigiai{
	\begin{itemchoice}
		\itemch Sai. Ta có $\overrightarrow{MN}=(-20;-280;-80)$ nên đường thẳng $MN$ có một véc-tơ chỉ phương là $\overrightarrow{u}=-\dfrac{1}{20}\overrightarrow{MN}=(1;14;4)$.\\
		Vậy khinh khí cầu chuyển động trên đường thẳng  có phương trình là
		$$\heva{&x=7+t\\&y=38+14t\\&z=12+4t.}$$
		\itemch Sai. Gọi  $D$, $E$  là giao điểm của mặt cầu $(C)\colon x^2+y^2+z^2=26^2$ và đường thẳng $MN$.\\ Ta có $E$ là điểm đầu tiên mà người trên khinh khí cầu nhìn thấy ngọn hải đăng, $D$ là điểm cuối cùng mà người trên khinh khí cầu còn có thể nhìn thấy ngọn hải đăng.\\
		Thay  $x=7+t$, $y=38+14t$, $z=12+4t$ vào $(C)$ ta được
		\begin{eqnarray*}
			&&(7+t)^2+(38+14t)^2+(12+4t)^2=26^2\\
			&\Leftrightarrow& 213t^2 +1174t+961=0\\
			&\Leftrightarrow& \hoac{&t=-1\\&t=-\dfrac{961}{213}.}
		\end{eqnarray*}
		Do $E$ nằm giữa $M$ và $D$ nên $\overrightarrow{EM}$ và $\overrightarrow{ED}$ ngược chiều nhau, hay $(x_M-x_E)(x_D-x_E)<0$, suy ra $x_D=\dfrac{530}{213}, x_E=6$.\\ Vậy điểm  cuối cùng mà người trên khinh khí cầu có thể nhìn thấy ngọn hải đăng là $D\left(\dfrac{530}{213};-\dfrac{5360}{213};-\dfrac{1288}{213}\right)$.
		\itemch Đúng. Khoảng cách từ điểm đầu tiên nhìn thấy ngọn hải đăng và điểm cuối cùng nhìn thấy ngọn hải đăng là
		$$d=ED=\sqrt{\left(\dfrac{530}{213}-6\right) ^2+\left(-\dfrac{5360}{213}-24 \right)^2  +\left(-\dfrac{1288}{213}-8\right)^2 }\approx 51 \ (\text{km}).$$
		\itemch Sai. Ta có $MN=\sqrt{(-20)^2+(-280^2)+(-80)^2}=20\sqrt{213}$ (km), ta có $\dfrac{MN}{ED}=\dfrac{1065}{187}$ nên thời gian khinh khí cầu bay từ $E$ đến $D$ là
		$$12:\dfrac{1065}{187}\approx 2 \ (\text{giờ}).$$
	\end{itemchoice}
	}

