questions.rawBody:
%[2H5C3-4]
	\immini[thm]{Các thiên thạch có đường kính lớn hơn 140 m và có thể lại gần Trái Đất ở khoảng cách nhỏ hơn $7\,500\,000$ km được coi là những vật thể có khả năng va chạm gây nguy hiểm cho Trái Đất. Để theo dõi những thiên thạch này, người ta đã thiết lập các trạm quan sát các vật thể bay gần Trái Đất. Giả sử có một hệ thống quan sát có khả năng theo dõi các vật thể ở độ cao không vượt quá $6\,600$ km so với mực nước biển. Coi Trái Đất là khối cầu có bán kính $6\,400$ km.
	}{
	\begin{tikzpicture}[scale=.4]
		\draw(130:5.5)coordinate(A) (45:5.5)coordinate(B)--(barycentric cs:A=1,B=-5)coordinate(N)--(barycentric cs:B=1,A=-5)coordinate(M);
		\draw(0,0)coordinate(O)circle(3.2)circle(5.5) ;
		\draw[<->](O)--(3.2,0)node[pos=.5,above,scale=.6]{$6400$km};
		\draw[<->](3.2,0)--(5.5,0)node[pos=.5,above,scale=.6]{$6600$km};
		\foreach \p/\g in {O/-90,A/120,B/60,N/90,M/90}\draw[fill=white](\p)circle(.03)node[shift={(\g:.2)},scale=.8]{$\p$};
	\end{tikzpicture}
	}\noindent
	Chọn hệ trục tọa độ $Oxyz$  trong không gian có gốc $O$  tại tâm Trái Đất và đơn vị độ dài trên mỗi trục tọa độ là $1\,000$km. Một thiên thạch (coi như một hạt) chuyển động với tốc độ không đổi theo một đường thẳng từ điểm $M(6;20;0)$  đến điểm $N(-6;-12;16)$.
	\choiceTF
	{\True Đường thẳng $MN$  có phương trình tham số là $\left \{\begin{array}{l} x=6+3t \\ y=20+8t,~(t\in \mathbb{R}) \\ z=-4t\end{array}\right.$}
	{Vị trí đầu tiên thiên thạch di chuyển vào phạm vi theo dõi của hệ thống quan sát là điểm  $A(-3;-4;12)$}
	{\True Khoảng cách giữa vị trí đầu tiên và vị trí cuối cùng mà thiên thạch di chuyển trong phạm vi theo dõi của hệ thống quan sát là $18900$km (kết quả làm tròn đến hàng trăm theo đơn vị ki-lô-mét)}
	{\True Nếu thời gian di chuyển của thiên thạch trong phạm vi theo dõi của hệ thống quan sát là $3$ phút thì thời gian nó di chuyển từ  $M$ đến $N$  là $6$ phút}
\loigiai{
	\begin{itemchoice}
		\itemch Ta có $\overline{M N}=(-12 ;-32 ; 16)=-4(3 ; 8 ;-4)$.\\
		Vectơ chỉ phương của đường thẳng $M N$ là $\vec{u}=(3 ; 8 ;-4)$.\\
		Phương trình tham số của đường thẳng $M N$ là: $\left\{\begin{array}{l}x=6+3 t \\ y=20+8t \\ z=-4 t\end{array}, t \in \mathbb{R}\right.$.
		\itemch Để tìm vị trí đầu tiên thiên thạch di chuyển vào phạm vi theo dõi, ta cần tìm điểm giao của đường thẳng $M N$ với mặt cầu có tâm $O(0 ; 0 ; 0)$ và bán kính $R=6,4+6,6=13$.\\
		Phương trình mặt cầu là: $x^2+y^2+z^2=13^2$.
		Thay $x=6+3 t, y=20+8 t$ và $z=-4 t$ vào phương trình mặt cầu, ta được:
		$$(6+3 t)^2+(20+8 t)^2+(-4 t)^2=13^2 \Leftrightarrow 89 t^2+356 t+267=0.$$
		Giải phương trình, ta tìm được $t=-3$ hoặc $t=-1$.\\
		Thay $t=-3$ và $t=-1$ vào phương trình tham số của đường thẳng $M N$, ta được hai giao điểm của $M N$ và mặt cầu là $(-3 ;-4 ; 12)$ và $(3 ; 12 ; 4)$. Nhận thấy từ $M$ đến $N$, hoành độ có xu hướng giảm dần, nên điểm $A(3 ; 12 ; 4)$.
		\itemch Ta có $B(-3 ;-4 ; 12)$.\\
		Khoảng cách giữa vị trí đầu tiên và vị trí cuối cùng mà thiên thạch di chuyển trong phạm vi theo dỗi của hệ thống quan sát là $A B$.\\
		$A B=\sqrt{(-3-3)^2+(-4-12)^2+(12-4)^2}=2 \sqrt{89} \approx 18,9$ tương đương với 18900 km .
		\itemch Ta có $MN=\sqrt{(6+6)^2+(-12-20)^2+(16-0)^2}=4 \sqrt{89}=2 A B$.\\
		Thời gian thiên thạch di chuyển từ $M$ đến $N$ là: $t=\frac{M N}{A B} \cdot 3=6$ (phút).
	\end{itemchoice}
	}

